export function getHoldingAssetClass(ticker) {
    if (typeof ticker !== 'string') {
        return 'stock';
    }
    const normalized = ticker.trim().toUpperCase();
    if (!normalized) {
        return 'stock';
    }
    const override = ASSET_CLASS_OVERRIDES[normalized];
    if (override) {
        return override;
    }
    if (isLikelyFundTicker(normalized)) {
        return 'etf';
    }
    return 'stock';
}

