// Liquid-glass donut: an annular lens positioned under the pie canvas refracts
// the page background along the ring's rims (bezel distortion + caustics).
// The slices are translucent, so the optics read through them. The overlay
// tracks the chart's arc geometry and follows canvas resizes.
function initDonutRefraction() {
    const container = document.querySelector('#fundPieChartContainer');
    const canvas = document.getElementById('fundPieChart');
    if (!container || !canvas) {
        return;
    }

    const overlay = document.createElement('div');
    overlay.setAttribute('aria-hidden', 'true');
    overlay.style.position = 'absolute';
    overlay.style.pointerEvents = 'none';
    overlay.style.borderRadius = '50%';
    container.insertBefore(overlay, canvas);

    const lens = new LiquidGlassRefraction(overlay, DONUT_REFRACTION);
    if (!lens.enabled) {
        overlay.remove();
        return;
    }

    // The canvas must paint above the positioned overlay.
    canvas.style.position = 'relative';
    canvas.style.zIndex = '1';

    const sync = () => {
        if (typeof Chart === 'undefined' || typeof Chart.getChart !== 'function') {
            return;
        }
        const chart = Chart.getChart(canvas);
        const arc = chart?.getDatasetMeta?.(0)?.data?.[0];
        if (!arc || !(arc.outerRadius > 0)) {
            return;
        }
        const size = Math.ceil(arc.outerRadius * 2);
        overlay.style.left = `${Math.round(canvas.offsetLeft + arc.x - arc.outerRadius)}px`;
        overlay.style.top = `${Math.round(canvas.offsetTop + arc.y - arc.outerRadius)}px`;
        overlay.style.width = `${size}px`;
        overlay.style.height = `${size}px`;
        lens.options.innerRadiusRatio = arc.innerRadius / arc.outerRadius;
        lens.update();
    };

    sync();
    // eslint-disable-next-line no-undef
    const geometryObserver = new ResizeObserver(() => {
        requestAnimationFrame(sync);
        window.setTimeout(sync, 400); // again after the chart's resize animation settles
    });
    geometryObserver.observe(canvas);
}

// Initialize application with visibility checks
async function startApp() {
    try {
        const fxResponse = await fetch('../data/fx_data.json?t=' + new Date().getTime());
        if (!fxResponse.ok) {
            throw new Error('Failed to load FX data');
        }
        const fxData = await fxResponse.json();
        exchangeRates = fxData.rates || { USD: 1.0 };
    } catch (error) {
        logger.error('Error loading exchange rates:', error);
        // Keep default exchangeRates if loading fails
    }

    if (typeof Chart !== 'undefined') {
        if (typeof ChartDataLabels !== 'undefined') {
            Chart.register(ChartDataLabels);
        } else {
            logger.warn('ChartDataLabels plugin NOT found. Ensure it is loaded before main.js.');
        }
        Chart.register(customArcBordersPlugin);
        Chart.register(waveAnimationPlugin);

        initCurrencyToggle();
        const storedCurrency = getStoredCurrency();
        if (storedCurrency) {
            currentSelectedCurrency = storedCurrency;
        }
        applyCurrencySelection(currentSelectedCurrency, { emitEvent: false });
        initFooterToggle();

        // Initialize perlin background
        if (PERLIN_BACKGROUND_SETTINGS?.enabled) {
            perlinBackgroundHandle = mountPerlinPlaneBackground(PERLIN_BACKGROUND_SETTINGS);
        }

        // Initialize table glass effect
        try {
            new TableGlassEffect('.table-responsive-container', {
                ...TABLE_GLASS_EFFECT,
                // The visible glass pane here is the .content-block wrapper, which
                // already owns the backdrop frost. Mount the lens there: nesting a
                // second backdrop-filter inside it would darken the pane.
                refraction: {
                    ...TABLE_GLASS_EFFECT.refraction,
                    target: '.content-block',
                },
                onHoverRow: (ticker) => hoverSliceByTicker(ticker),
            });
        } catch (e) {
            logger.error('Failed to initialize table glass effect:', e);
        }

        // Wait for multiple animation frames to ensure proper layout in real browsers.
        // In test environments, skip this to avoid flakiness from timer/raf scheduling.
        const isTestEnv =
            typeof process !== 'undefined' && process.env && process.env.NODE_ENV === 'test';
        if (!isTestEnv) {
            await new Promise((resolve) =>
                requestAnimationFrame(() => requestAnimationFrame(resolve))
            );
        }

        try {
            // Load data, render chart (which also calls checkAndToggleVerticalScroll)
            await loadAndDisplayPortfolioData(
                currentSelectedCurrency,
                exchangeRates,
                CURRENCY_SYMBOLS
            );
            // Now that chart is rendered and initial scroll check is done:
            alignToggleWithChartMobile(); // Align toggle based on the rendered chart

            try {
                initDonutRefraction();
            } catch (error) {
                logger.error('Failed to initialize donut refraction:', error);
            }

            // Trigger toggle animation after chart loads (mobile only)
            if (window.innerWidth <= 768) {
                setTimeout(() => {
                    const toggleContainer = document.querySelector('#currencyToggleContainer');
                    if (toggleContainer) {
                        toggleContainer.classList.add('chart-loaded');
                    }
                }, 200); // Small delay to ensure chart is fully rendered
            }
            // Keep initial UI minimal on first load (no footer/table)
        } catch (error) {
            logger.error('Error during initial portfolio data load and display:', error);
        }
    } else {
        logger.error(
            'Chart.js core NOT found. Ensure it is loaded before main.js. App initialization skipped.'
        );
    }
}

