export async function drawBetaChart(ctx, chartManager, timestamp) {
    const performanceSeries =
        transactionState.performanceSeries && typeof transactionState.performanceSeries === 'object'
            ? transactionState.performanceSeries
            : {};
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const { chartVisibility } = transactionState;
    stopContributionAnimation();
    stopFxAnimation();

    if (Object.keys(performanceSeries).length === 0) {
        stopPerformanceAnimation();
        chartLayouts.beta = null;
        updateCrosshairUI(null, null);
        return;
    }

    const MARKET_REF = '^GSPC';
    if (!performanceSeries[MARKET_REF]) {
        stopPerformanceAnimation();
        chartLayouts.beta = null;
        return;
    }

    // Limit to DJI, GSPC, IXIC + Portfolio
    const allowedBenchmarks = ['^GSPC', '^IXIC', '^DJI'];
    const orderedKeys = Object.keys(performanceSeries)
        .filter((k) => k === '^LZ' || allowedBenchmarks.includes(k))
        .sort((a, b) => {
            if (a === '^LZ') {
                return -1;
            }
            if (b === '^LZ') {
                return 1;
            }
            return a.localeCompare(b);
        });

    for (let i = 0; i < orderedKeys.length; i++) {
        const key = orderedKeys[i];
        if (transactionState.chartVisibility[key] === undefined) {
            transactionState.chartVisibility[key] = key === '^LZ' || key === '^GSPC';
        }
    }

    // Enforce "one benchmark" rule
    const visibleBenchmarks = allowedBenchmarks.filter(
        (b) => transactionState.chartVisibility[b] === true
    );
    if (visibleBenchmarks.length > 1) {
        const toHide = visibleBenchmarks.slice(1);
        for (let i = 0; i < toHide.length; i++) {
            transactionState.chartVisibility[toHide[i]] = false;
        }
    }

    // 1. Calculate daily returns
    const returnsMap = {};
    for (let i = 0; i < orderedKeys.length; i++) {
        const key = orderedKeys[i];
        const points = performanceSeries[key] || [];
        const sourceCurrency = PERFORMANCE_SERIES_CURRENCY[key] || 'USD';
        const returns = [];
        for (let j = 1; j < points.length; j++) {
            const startVal = convertBetweenCurrencies(
                Number(points[j - 1].value),
                sourceCurrency,
                points[j - 1].date,
                selectedCurrency
            );
            const endVal = convertBetweenCurrencies(
                Number(points[j].value),
                sourceCurrency,
                points[j].date,
                selectedCurrency
            );
            if (startVal !== 0) {
                returns.push({
                    date: points[j].date,
                    time: parseLocalDate(points[j].date).getTime(),
                    val: endVal / startVal - 1,
                });
            }
        }
        returnsMap[key] = returns;
    }

    const marketReturns = returnsMap[MARKET_REF];
    if (!marketReturns || marketReturns.length < 20) {
        chartLayouts.beta = null;
        return;
    }

    // 2. Calculate rolling 6-month Beta (126 trading days)
    const windowSize = 126;
    const allPossibleSeries = [];
    for (let k = 0; k < orderedKeys.length; k++) {
        const key = orderedKeys[k];
        const assetReturns = returnsMap[key];
        if (!assetReturns) {
            continue;
        }

        const assetReturnMap = new Map();
        for (let i = 0; i < assetReturns.length; i++) {
            const r = assetReturns[i];
            assetReturnMap.set(r.date, r.val);
        }

        const betaData = [];

        // Master timeline from market returns
        for (let i = windowSize - 1; i < marketReturns.length; i++) {
            if (key === MARKET_REF) {
                betaData.push({ date: marketReturns[i].date, value: 1.0 });
                continue;
            }

            // Bolt: Optimize O(N * W) slice/array allocations by iterating indices directly over marketReturns array
            const startIdx = i - windowSize + 1;
            let n = 0;
            let mSum = 0;
            let aSum = 0;

            // First pass to compute sum and valid counts directly
            for (let j = startIdx; j <= i; j++) {
                const mR = marketReturns[j];
                const aVal = assetReturnMap.get(mR.date);
                if (aVal !== undefined) {
                    n++;
                    mSum += mR.val;
                    aSum += aVal;
                }
            }

            if (n < windowSize * 0.8) {
                continue;
            }

            const mMean = mSum / n;
            const aMean = aSum / n;

            let cov = 0;
            let mVar = 0;

            // Second pass to compute variance and covariance
            for (let j = startIdx; j <= i; j++) {
                const mR = marketReturns[j];
                const aVal = assetReturnMap.get(mR.date);
                if (aVal !== undefined) {
                    const mDiff = mR.val - mMean;
                    cov += (aVal - aMean) * mDiff;
                    mVar += mDiff * mDiff;
                }
            }

            const beta = mVar < 1e-12 ? 0 : cov / mVar;
            betaData.push({
                date: marketReturns[i].date,
                value: beta,
            });
        }

        if (betaData.length > 0) {
            allPossibleSeries.push({
                key,
                name: key,
                data: betaData,
            });
        }
    }

    const visibility = chartVisibility || {};
    const seriesToDraw = allPossibleSeries.filter((s) => visibility[s.key] !== false);

    if (seriesToDraw.length === 0) {
        stopPerformanceAnimation();
        chartLayouts.beta = null;
        updateCrosshairUI(null, null);
        return;
    }

    const canvas = ctx.canvas;
    const isMobile = typeof window !== 'undefined' ? window.innerWidth <= 768 : false;
    const padding = isMobile
        ? { top: 15, right: 20, bottom: 35, left: 50 }
        : { top: 20, right: 30, bottom: 48, left: 70 };
    const plotWidth = canvas.offsetWidth - padding.left - padding.right;
    const plotHeight = canvas.offsetHeight - padding.top - padding.bottom;

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    const filteredSeries = [];
    const allPoints = [];
    for (let i = 0; i < seriesToDraw.length; i++) {
        const s = seriesToDraw[i];
        const validData = [];
        for (let j = 0; j < s.data.length; j++) {
            const d = s.data[j];
            const dt = parseLocalDate(d.date);
            if ((!filterFrom || dt >= filterFrom) && (!filterTo || dt <= filterTo)) {
                validData.push(d);
                allPoints.push(d);
            }
        }
        filteredSeries.push({ ...s, data: validData });
    }
    if (allPoints.length === 0) {
        stopPerformanceAnimation();
        return;
    }

    // Bolt: Use explicit O(N) loop instead of chained .map() and Math.max(...spread) to eliminate GC overhead and avoid call stack limits
    let minTime = Infinity;
    let maxTime = -Infinity;
    let dataMin = Infinity;
    let dataMax = -Infinity;

    for (let i = 0; i < allPoints.length; i++) {
        const time = parseLocalDate(allPoints[i].date).getTime();
        const value = allPoints[i].value;
        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
        if (value < dataMin) {
            dataMin = value;
        }
        if (value > dataMax) {
            dataMax = value;
        }
    }

    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }
    const valueRange = dataMax - dataMin;
    const yPadding = Math.max(valueRange * 0.1, 0.2);
    const yMin = Math.max(0, dataMin - yPadding);
    const yMax = dataMax + yPadding;

    const xScale = (t) =>
        padding.left +
        (maxTime === minTime ? plotWidth / 2 : ((t - minTime) / (maxTime - minTime)) * plotWidth);
    const yScale = (v) =>
        padding.top +
        plotHeight -
        (yMax === yMin ? plotHeight / 2 : ((v - yMin) / (yMax - yMin)) * plotHeight);

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        (v) => v.toFixed(1),
        true
    );

    // Draw reference line at Beta = 1.0
    const y1 = yScale(1.0);
    if (y1 >= padding.top && y1 <= padding.top + plotHeight) {
        ctx.save();
        ctx.setLineDash([5, 5]);
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.15)';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(padding.left, y1);
        ctx.lineTo(padding.left + plotWidth, y1);
        ctx.stroke();
        ctx.restore();
    }

    const animationPhase = advancePerformanceAnimation(timestamp);
    const rootStyles =
        typeof window !== 'undefined' ? window.getComputedStyle(document.documentElement) : null;
    const colors = getChartColors(rootStyles);
    const colorMap = {
        '^LZ': BENCHMARK_GRADIENTS['^LZ'][1],
        '^GSPC': BENCHMARK_GRADIENTS['^GSPC'][1],
        '^IXIC': BENCHMARK_GRADIENTS['^IXIC'][1],
        '^DJI': BENCHMARK_GRADIENTS['^DJI'][1],
        '^SSEC': BENCHMARK_GRADIENTS['^SSEC'][1],
        '^HSI': BENCHMARK_GRADIENTS['^HSI'][1],
        '^N225': BENCHMARK_GRADIENTS['^N225'][1],
    };

    const lineThickness = CHART_LINE_WIDTHS.performance ?? 2;
    const renderedSeries = [];
    let glowIndex = 0;

    const chartBounds = {
        top: padding.top,
        bottom: padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    const seriesForDrawing = filteredSeries.slice().sort((a, b) => {
        if (a.key === '^LZ') {
            return 1;
        }
        if (b.key === '^LZ') {
            return -1;
        }
        return 0;
    });

    for (let i = 0; i < seriesForDrawing.length; i++) {
        const series = seriesForDrawing[i];
        if (series.data.length === 0) {
            continue;
        }

        // Use raw points for Beta to ensure statistical accuracy (no smoothing)
        const points = series.data.map((p) => ({ date: parseLocalDate(p.date), value: p.value }));

        const gradientStops = BENCHMARK_GRADIENTS[series.key];
        const resolvedColor = gradientStops
            ? gradientStops[1]
            : colorMap[series.key] || colors.contribution;

        const coords = points.map((p) => ({
            x: xScale(p.date.getTime()),
            y: yScale(p.value),
            time: p.date.getTime(),
            value: p.value,
        }));

        if (mountainFill.enabled) {
            drawMountainFill(ctx, coords, yScale(yMin), {
                color: resolvedColor,
                colorStops: gradientStops || [resolvedColor, resolvedColor],
                opacityTop: 0.2,
                opacityBottom: 0,
                bounds: chartBounds,
            });
        }

        ctx.beginPath();
        for (let idx = 0; idx < coords.length; idx++) {
            const c = coords[idx];
            if (idx === 0) {
                ctx.moveTo(c.x, c.y);
            } else {
                ctx.lineTo(c.x, c.y);
            }
        }
        ctx.strokeStyle = resolvedColor;
        if (gradientStops) {
            const grad = ctx.createLinearGradient(padding.left, 0, padding.left + plotWidth, 0);
            grad.addColorStop(0, gradientStops[0]);
            grad.addColorStop(1, gradientStops[1]);
            ctx.strokeStyle = grad;
        }
        ctx.lineWidth = lineThickness;
        ctx.stroke();

        renderedSeries.push({
            key: series.key,
            name: series.name,
            color: resolvedColor,
            x: coords[coords.length - 1].x,
            y: coords[coords.length - 1].y,
            value: points[points.length - 1].value,
            coords,
            points: coords.map((c) => ({ time: c.time, value: c.value })),
        });

        if (isAnimationEnabled('performance')) {
            drawSeriesGlow(
                ctx,
                { coords, color: resolvedColor, lineWidth: lineThickness },
                {
                    basePhase: animationPhase,
                    seriesIndex: glowIndex,
                    isMobile,
                    chartKey: 'performance',
                }
            );
            glowIndex += 1;
        }
    }

    if (isAnimationEnabled('performance') && glowIndex > 0) {
        schedulePerformanceAnimation(chartManager);
    } else {
        stopPerformanceAnimation();
    }

    if (getShowChartLabels()) {
        for (let i = 0; i < renderedSeries.length; i++) {
            const s = renderedSeries[i];
            drawEndValue(
                ctx,
                s.x,
                s.y,
                s.value,
                s.color,
                isMobile,
                padding,
                plotWidth,
                plotHeight,
                (v) => v.toFixed(2),
                true,
                []
            );
        }
    }

    chartLayouts.beta = {
        key: 'beta',
        minTime,
        maxTime,
        valueType: 'number',
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: renderedSeries.map((s) => ({
            key: s.key,
            label: `${s.name}`,
            color: s.color,
            getValueAtTime: createTimeInterpolator(s.points),
            formatValue: (v) => v.toFixed(3),
        })),
    };

    drawCrosshairOverlay(ctx, chartLayouts.beta);

    if (legendState.performanceDirty) {
        const legendSeries = allPossibleSeries.map((s) => ({
            key: s.key,
            name: s.name,
            color: colorMap[s.key] || colors.contribution,
        }));
        updateLegend(legendSeries, chartManager);
        legendState.performanceDirty = false;
    }
}

import { logger } from '../../../utils/logger.js';
import {
    transactionState,
    getCompositionFilterTickers,
    getCompositionAssetClassFilter,
} from '../../state.js';
import { chartLayouts } from '../state.js';
import { loadCompositionSnapshotData } from '../../dataLoader.js';
import {
    stopPerformanceAnimation,
    stopContributionAnimation,
    stopFxAnimation,
} from '../animation.js';
import { updateCrosshairUI, updateLegend, drawCrosshairOverlay } from '../interaction.js';
import { drawAxes } from '../core.js';
import {
    createTimeInterpolator,
    clampTime,
    formatPercentInline,
    parseLocalDate,
} from '../helpers.js';
import {
    formatCurrencyInlineValue,
    formatCurrencyCompact,
    convertValueToCurrency,
} from '../../utils.js';
import { COLOR_PALETTES, getHoldingAssetClass } from '../../../config.js';

let compositionDataCache = null;
let compositionDataLoading = false;

function aggregateCompositionSeries(tickers, chartData, seriesLength) {
    if (!Array.isArray(tickers) || tickers.length === 0 || !Number.isFinite(seriesLength)) {
        return null;
    }
    // Bolt: Use new Array(length).fill(0) instead of Array.from to reduce GC overhead
    const aggregated = new Array(seriesLength).fill(0);
    for (let tIdx = 0; tIdx < tickers.length; tIdx += 1) {
        const ticker = tickers[tIdx];
        const values = chartData[ticker] || [];
        for (let i = 0; i < seriesLength; i += 1) {
            const value = Number(values[i] ?? 0);
            if (Number.isFinite(value)) {
                aggregated[i] += value;
            }
        }
    }
    return aggregated;
}

function buildCompositionDisplayOrder(
    baseOrder,
    chartData,
    filterTickers,
    seriesLength,
    referenceData = null
) {
    if (!Array.isArray(baseOrder) || baseOrder.length === 0) {
        return { order: [], filteredOthers: null };
    }
    const filterSet = new Set();
    if (Array.isArray(filterTickers)) {
        for (let i = 0; i < filterTickers.length; i += 1) {
            const ticker = filterTickers[i];
            if (ticker) {
                filterSet.add(ticker.toUpperCase());
            }
        }
    }
    if (filterSet.size === 0) {
        return { order: [...baseOrder], filteredOthers: null };
    }
    const selectedOrder = baseOrder.filter((ticker) => filterSet.has(ticker.toUpperCase()));
    if (selectedOrder.length === 0) {
        return { order: [...baseOrder], filteredOthers: null };
    }

    const remainder = baseOrder.filter((ticker) => !filterSet.has(ticker.toUpperCase()));
    const includeFilteredOthers = remainder.length > 0 && !filterSet.has('OTHERS');
    const filteredOthers = includeFilteredOthers
        ? aggregateCompositionSeries(remainder, chartData, seriesLength)
        : null;
    const filteredReference =
        includeFilteredOthers && referenceData
            ? aggregateCompositionSeries(remainder, referenceData, seriesLength)
            : null;
    const order = filteredOthers ? [...selectedOrder, 'Others'] : selectedOrder;
    return { order, filteredOthers, filteredReference };
}

function renderCompositionChartWithMode(ctx, chartManager, data, options = {}) {
    // 1. Validate Data
    const valueMode = options.valueMode === 'absolute' ? 'absolute' : 'percent';

    if (
        !data ||
        typeof data !== 'object' ||
        !Array.isArray(data.dates) ||
        data.dates.length === 0
    ) {
        chartLayouts.composition = null;
        chartLayouts.compositionAbs = null;
        updateCrosshairUI(null, null);
        const emptyState = document.getElementById('runningAmountEmpty');
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    const emptyState = document.getElementById('runningAmountEmpty');
    if (emptyState) {
        emptyState.style.display = 'none';
    }

    // 2. Prepare Basic Data (Indices, Dates)
    const rawDates = data.dates.slice();
    const rawSeries = data.composition || data.series || {};
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    // Bolt: Replaced O(N) Array .map().filter().map() with a single inline loop
    const filteredIndices = [];
    for (let i = 0; i < rawDates.length; i += 1) {
        const date = parseLocalDate(rawDates[i]);
        if (!date || Number.isNaN(date.getTime())) {
            continue;
        }
        if (filterFrom && date < filterFrom) {
            continue;
        }
        if (filterTo && date > filterTo) {
            continue;
        }
        filteredIndices.push(i);
    }

    const dates =
        filterFrom || filterTo ? filteredIndices.map((i) => rawDates[i]) : rawDates.slice();

    if (dates.length === 0) {
        if (valueMode === 'absolute') {
            chartLayouts.compositionAbs = null;
        } else {
            chartLayouts.composition = null;
        }
        updateCrosshairUI(null, null);
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    // 3. Prepare Values (Total Values, Conversion, Percent Mapping)
    const rawTotalValues = Array.isArray(data.total_values) ? data.total_values : [];
    const mappedTotalValues =
        filteredIndices.length > 0
            ? filteredIndices.map((index) => Number(rawTotalValues[index] ?? 0))
            : rawTotalValues.map((value) => Number(value ?? 0));
    const totalValuesUsd =
        mappedTotalValues.length === dates.length
            ? mappedTotalValues
            : dates.map((_, idx) => Number(mappedTotalValues[idx] ?? 0));
    const totalValuesConverted = totalValuesUsd.map((value, idx) => {
        const converted = convertValueToCurrency(value, dates[idx], selectedCurrency);
        return Number.isFinite(converted) ? converted : 0;
    });

    const percentSeriesMap = {};
    const chartData = {};
    Object.entries(rawSeries).forEach(([ticker, values]) => {
        const mappedValues =
            filterFrom || filterTo
                ? filteredIndices.map((index) => values[index] ?? 0)
                : values.map((value) => value ?? 0);
        const percentValues =
            mappedValues.length === dates.length
                ? mappedValues
                : dates.map((_, idx) => Number(mappedValues[idx] ?? 0));
        percentSeriesMap[ticker] = percentValues;
        if (valueMode === 'absolute') {
            // Bolt: Optimize absolute value mapping by pre-allocating an array and using a for loop
            const absoluteValues = new Array(percentValues.length);
            for (let i = 0; i < percentValues.length; i += 1) {
                absoluteValues[i] = ((totalValuesConverted[i] ?? 0) * percentValues[i]) / 100;
            }
            chartData[ticker] = absoluteValues;
        } else {
            chartData[ticker] = percentValues;
        }
    });

    // 4. Determine Active Tickers and Sort Order
    const baseTickerOrder = Object.keys(chartData).sort((a, b) => {
        const arrA = chartData[a] || [];
        const arrB = chartData[b] || [];
        const lastA = arrA[arrA.length - 1] ?? 0;
        const lastB = arrB[arrB.length - 1] ?? 0;
        return lastB - lastA;
    });

    const explicitTickerFilters = getCompositionFilterTickers();
    const assetClassFilter = getCompositionAssetClassFilter();
    let derivedTickerFilters = explicitTickerFilters;
    if (assetClassFilter === 'etf' || assetClassFilter === 'stock') {
        const shouldMatchEtf = assetClassFilter === 'etf';
        const classMatchedTickers = baseTickerOrder.filter((ticker) => {
            if (typeof ticker === 'string' && ticker.toUpperCase() === 'OTHERS') {
                return false;
            }
            const ac = getHoldingAssetClass(ticker);
            return shouldMatchEtf ? ac === 'etf' : ac !== 'etf';
        });
        if (explicitTickerFilters.length) {
            // OR: explicit tickers + asset-class-matched tickers
            const merged = new Set([...explicitTickerFilters, ...classMatchedTickers]);
            derivedTickerFilters = [...merged];
        } else {
            derivedTickerFilters = classMatchedTickers;
        }
    }

    const {
        order: filteredOrder,
        filteredOthers,
        filteredReference,
    } = buildCompositionDisplayOrder(
        baseTickerOrder,
        chartData,
        derivedTickerFilters,
        dates.length,
        valueMode === 'absolute' ? percentSeriesMap : null
    );
    const percentOthersSeries = valueMode === 'absolute' ? filteredReference : filteredOthers;
    const activeTickerOrder = filteredOrder.length > 0 ? filteredOrder : baseTickerOrder;
    const usingFilteredOthers = Boolean(filteredOthers);

    // 5. Setup Canvas and Scales
    const canvas = ctx.canvas;
    const canvasWidth = canvas.offsetWidth;
    const canvasHeight = canvas.offsetHeight;
    const isMobile = window.innerWidth <= 768;
    const padding = isMobile
        ? { top: 15, right: 18, bottom: 36, left: 48 }
        : { top: 22, right: 26, bottom: 48, left: 68 };
    const plotWidth = canvasWidth - padding.left - padding.right;
    const plotHeight = canvasHeight - padding.top - padding.bottom;
    if (plotWidth <= 0 || plotHeight <= 0) {
        if (valueMode === 'absolute') {
            chartLayouts.compositionAbs = null;
        } else {
            chartLayouts.composition = null;
        }
        updateCrosshairUI(null, null);
        return;
    }

    const colors = COLOR_PALETTES.COMPOSITION_CHART_COLORS;
    // Local resolveTickerColor logic to match original chart.js exactly
    const resolveTickerColor = (ticker) => {
        let colorIndex = baseTickerOrder.indexOf(ticker);
        if (colorIndex === -1 && ticker === 'Others') {
            colorIndex = baseTickerOrder.indexOf('Others');
        }
        if (colorIndex === -1) {
            colorIndex = baseTickerOrder.length;
        }
        return colors[colorIndex % colors.length];
    };

    const dateTimes = new Array(dates.length);
    let minTime = Infinity;
    let maxTime = -Infinity;
    for (let i = 0; i < dates.length; i++) {
        const time = parseLocalDate(dates[i]).getTime();
        dateTimes[i] = time;
        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
    }

    // Ensure minTime aligns with filter start for correct x-axis labels
    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }

    const xScale = (time) =>
        padding.left +
        (maxTime === minTime
            ? plotWidth / 2
            : ((time - minTime) / (maxTime - minTime)) * plotWidth);

    const yMin = 0;
    let maxTotalValue = 0;
    for (let i = 0; i < totalValuesConverted.length; i++) {
        if (Number.isFinite(totalValuesConverted[i]) && totalValuesConverted[i] > maxTotalValue) {
            maxTotalValue = totalValuesConverted[i];
        }
    }
    const yMax = valueMode === 'absolute' ? Math.max(maxTotalValue, 1) : 100;
    const yScale = (value) =>
        padding.top + plotHeight - ((value - yMin) / (yMax - yMin || 1)) * plotHeight;

    // 6. Draw Axes
    const axisFormatter =
        valueMode === 'absolute'
            ? (val) => formatCurrencyCompact(val, { currency: selectedCurrency })
            : (val) => `${val}%`;
    const chartBounds = {
        top: padding.top,
        bottom: padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        axisFormatter,
        valueMode !== 'absolute'
    );

    // 7. Render Stacked Areas
    const cumulativeValues = new Array(dates.length).fill(0);

    // Bolt: Use standard for loop instead of .forEach to avoid closure allocation inside rendering loop
    for (let tickerIndex = 0; tickerIndex < activeTickerOrder.length; tickerIndex += 1) {
        const ticker = activeTickerOrder[tickerIndex];
        const values =
            ticker === 'Others' && usingFilteredOthers ? filteredOthers : chartData[ticker] || [];
        if (!Array.isArray(values) || values.length !== dates.length) {
            continue;
        }
        const color = resolveTickerColor(ticker) || colors[tickerIndex % colors.length];
        ctx.beginPath();
        ctx.fillStyle = `${color}80`;
        ctx.strokeStyle = 'rgba(128, 128, 128, 0.5)';
        ctx.lineWidth = 1;

        // Bolt: Use standard for loop instead of .forEach to avoid closure allocation
        for (let index = 0; index < dates.length; index += 1) {
            const dateStr = dates[index];
            const x = xScale(parseLocalDate(dateStr).getTime());
            const y = yScale(cumulativeValues[index] + values[index]);
            if (index === 0) {
                ctx.moveTo(x, y);
            } else {
                ctx.lineTo(x, y);
            }
        }

        for (let i = dates.length - 1; i >= 0; i -= 1) {
            const x = xScale(parseLocalDate(dates[i]).getTime());
            const y = yScale(cumulativeValues[i]);
            ctx.lineTo(x, y);
        }
        ctx.closePath();
        ctx.fill();
        ctx.stroke();

        // Bolt: Optimize array allocation by mutating cumulativeValues in place instead of map
        for (let i = 0; i < cumulativeValues.length; i += 1) {
            cumulativeValues[i] += values[i];
        }
    }

    // 8. Prepare Legend and Crosshair Data
    const latestIndex = dates.length - 1;
    const percentSeriesForTicker = (ticker) => {
        if (ticker === 'Others' && percentOthersSeries) {
            return percentOthersSeries;
        }
        return percentSeriesMap[ticker] || [];
    };
    const othersPercentSeries = percentSeriesForTicker('Others');
    const othersPercentage =
        othersPercentSeries.length > 0 ? (othersPercentSeries[latestIndex] ?? 0) : 0;
    const shouldIncludeOthers = othersPercentage > 50 || usingFilteredOthers;

    const buildHoldingInfo = (ticker) => {
        const percentSeries = percentSeriesForTicker(ticker);
        const percent = percentSeries[latestIndex] ?? 0;
        const absoluteSeries =
            ticker === 'Others' && usingFilteredOthers ? filteredOthers : chartData[ticker] || [];
        const latestTotal = totalValuesConverted[latestIndex] ?? 0;
        const absoluteValue =
            valueMode === 'absolute'
                ? (absoluteSeries[latestIndex] ?? 0)
                : (latestTotal * percent) / 100;
        return {
            ticker,
            percent,
            absolute: absoluteValue,
        };
    };

    const latestHoldings = activeTickerOrder
        .filter((ticker) => shouldIncludeOthers || ticker !== 'Others')
        .map(buildHoldingInfo)
        .filter((holding) => holding.percent > 0.1)
        .sort((a, b) => b.percent - a.percent)
        .slice(0, 6);

    const holdingsForLegend =
        latestHoldings.length > 0
            ? latestHoldings
            : activeTickerOrder
                  .filter((ticker) => shouldIncludeOthers || ticker !== 'Others')
                  .map(buildHoldingInfo)
                  .sort((a, b) => b.percent - a.percent)
                  .slice(0, 6);

    const legendSeries = holdingsForLegend.map((holding) => {
        const displayName = holding.ticker === 'BRKB' ? 'BRK-B' : holding.ticker;
        return {
            key: holding.ticker,
            name: displayName,
            color: resolveTickerColor(holding.ticker),
        };
    });

    const seriesForCrosshair = [];
    for (let i = 0; i < activeTickerOrder.length; i += 1) {
        const ticker = activeTickerOrder[i];
        const values =
            ticker === 'Others' && usingFilteredOthers ? filteredOthers : chartData[ticker];
        if (!Array.isArray(values) || values.length !== dates.length) {
            continue;
        }
        const points = new Array(dateTimes.length);
        for (let j = 0; j < dateTimes.length; j += 1) {
            points[j] = { time: dateTimes[j], value: values[j] };
        }
        const label = ticker === 'BRKB' ? 'BRK-B' : ticker;
        const color = resolveTickerColor(ticker);
        seriesForCrosshair.push({
            key: ticker,
            label,
            color,
            getValueAtTime: createTimeInterpolator(points),
            formatValue: (value) =>
                valueMode === 'absolute'
                    ? formatCurrencyInlineValue(value, selectedCurrency)
                    : `${value.toFixed(2)}%`,
            formatDelta: (delta) =>
                valueMode === 'absolute'
                    ? formatCurrencyInlineValue(delta, selectedCurrency)
                    : formatPercentInline(delta),
            originalIndex: i,
        });
    }

    const sortedSeriesForCrosshair = seriesForCrosshair.sort((a, b) => {
        const indexA = activeTickerOrder.indexOf(a.key);
        const indexB = activeTickerOrder.indexOf(b.key);
        return indexA - indexB;
    });

    const totalValuePoints = dateTimes.map((time, idx) => ({
        time,
        value: Number(totalValuesConverted[idx] ?? 0),
    }));

    const layoutKey = valueMode === 'absolute' ? 'compositionAbs' : 'composition';
    if (valueMode === 'absolute') {
        chartLayouts.composition = null;
    } else {
        chartLayouts.compositionAbs = null;
    }
    chartLayouts[layoutKey] = {
        key: layoutKey,
        minTime,
        maxTime,
        valueType: valueMode === 'absolute' ? 'currency' : 'percent',
        valueMode,
        currency: selectedCurrency,
        stackMaxValue: yMax,
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            if (!Number.isFinite(pixelX)) {
                return minTime;
            }
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: sortedSeriesForCrosshair,
        dates,
        percentSeriesMap,
        percentOthersSeries,
        getTotalValueAtTime: createTimeInterpolator(totalValuePoints),
    };

    drawCrosshairOverlay(ctx, chartLayouts[layoutKey]);

    updateLegend(legendSeries, chartManager);
}

function drawCompositionChartLoader(ctx, chartManager, valueMode) {
    stopPerformanceAnimation();
    stopContributionAnimation();
    stopFxAnimation();
    const emptyState = document.getElementById('runningAmountEmpty');

    if (!compositionDataCache && compositionDataLoading) {
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    if (compositionDataCache) {
        renderCompositionChartWithMode(ctx, chartManager, compositionDataCache, { valueMode });
        return;
    }

    compositionDataLoading = true;
    loadCompositionSnapshotData()
        .then((data) => {
            if (!data) {
                throw new Error('Failed to load composition data');
            }
            compositionDataCache = data;
            renderCompositionChartWithMode(ctx, chartManager, data, { valueMode });
        })
        .catch((error) => {
            logger.warn('Composition chart rendering failed:', error);
            if (valueMode === 'absolute') {
                chartLayouts.compositionAbs = null;
            } else {
                chartLayouts.composition = null;
            }
            updateCrosshairUI(null, null);
            if (emptyState) {
                emptyState.style.display = 'block';
            }
        })
        .finally(() => {
            compositionDataLoading = false;
        });
}

function drawCompositionChart(ctx, chartManager) {
