export async function drawContributionChart(ctx, chartManager, timestamp, options = {}) {
    const { drawdownMode = false } = options;
    stopPerformanceAnimation();
    stopFxAnimation();

    const runningAmountSeries = Array.isArray(transactionState.runningAmountSeries)
        ? transactionState.runningAmountSeries
        : [];
    const portfolioSeries = Array.isArray(transactionState.portfolioSeries)
        ? transactionState.portfolioSeries
        : [];
    const filteredTransactions = Array.isArray(transactionState.filteredTransactions)
        ? transactionState.filteredTransactions
        : [];
    const allTransactions = Array.isArray(transactionState.allTransactions)
        ? transactionState.allTransactions
        : [];

    const filtersActive =
        hasActiveTransactionFilters() &&
        transactionState.activeFilterTerm &&
        transactionState.activeFilterTerm.trim().length > 0;
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const contributionTransactions = filtersActive ? filteredTransactions : allTransactions;
    let contributionSource = [];
    let contributionFromTransactions = false;

    if (contributionTransactions.length > 0) {
        const today = parseLocalDate(new Date());
        const rangeTo = transactionState.chartDateRange?.to
            ? parseLocalDate(transactionState.chartDateRange.to)
            : null;
        let padToDate;
        if (rangeTo && today) {
            padToDate = Math.min(rangeTo.getTime(), today.getTime());
        } else if (today) {
            padToDate = today.getTime();
        } else {
            padToDate = rangeTo?.getTime() ?? Date.now();
        }
        contributionSource = getContributionSeriesForTransactions(contributionTransactions, {
            includeSyntheticStart: true,
            padToDate,
            currency: null,
        });
        contributionFromTransactions =
            filtersActive && Array.isArray(contributionSource) && contributionSource.length > 0;
        if (!filtersActive && contributionSource !== runningAmountSeries) {
            setRunningAmountSeries(contributionSource);
        }
    } else {
        const mappedSeries =
            transactionState.runningAmountSeriesByCurrency?.[selectedCurrency] || null;

        if (mappedSeries && mappedSeries === runningAmountSeries) {
            contributionSource = runningAmountSeries;
        } else if (mappedSeries) {
            contributionSource = mappedSeries;
            setRunningAmountSeries(mappedSeries);
        } else {
            contributionSource = runningAmountSeries;
        }
    }

    // Load yield data and merge dividends into contribution series
    let yieldData = getCachedYieldData();
    if (!yieldData) {
        yieldData = await loadYieldData();
    }
    if (yieldData && contributionSource.length > 0) {
        let activeTickers = null;
        if (filtersActive && Array.isArray(filteredTransactions)) {
            const tickerSet = new Set();
            for (let i = 0; i < filteredTransactions.length; i++) {
                const t = filteredTransactions[i];
                if (t.security) {
                    tickerSet.add(t.security);
                }
            }
            activeTickers = Array.from(tickerSet);
        }

        contributionSource = mergeDividendsIntoContribution(
            contributionSource,
            yieldData,
            selectedCurrency,
            activeTickers
        );
    }

    let historicalPrices = transactionState.historicalPrices;
    if (filtersActive && (!historicalPrices || Object.keys(historicalPrices).length === 0)) {
        try {
            const response = await fetch('../data/historical_prices.json');
            if (response.ok) {
                historicalPrices = await response.json();
                // Cache the fetched data to prevent repeated async fetches
                setHistoricalPrices(historicalPrices);
            } else {
                historicalPrices = {};
            }
        } catch (error) {
            logger.warn('Contribution chart rendering failed:', error);
            historicalPrices = {};
        }
    } else {
        historicalPrices = historicalPrices || {};
    }
    // For non-filter mode, use currency-specific portfolio series if available
    const currencyPortfolioSeries =
        transactionState.portfolioSeriesByCurrency?.[selectedCurrency] || portfolioSeries;

    let balanceSource = filtersActive
        ? buildFilteredBalanceSeries(
              filteredTransactions,
              historicalPrices,
              transactionState.splitHistory
          )
        : currencyPortfolioSeries;

    // For filtered data, convert to target currency before any other transformations
    // (including drawdown which should calculate HWM in the target currency)
    if (selectedCurrency !== 'USD' && Array.isArray(balanceSource) && filtersActive) {
        balanceSource = [...balanceSource]
            .sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0))
            .map((entry) => ({
                ...entry,
                value: convertValueToCurrency(entry.value, entry.date, selectedCurrency),
            }));
    }
    const hasBalanceSeries = Array.isArray(balanceSource) && balanceSource.length > 0;

    const { chartVisibility } = transactionState;
    const visibility = chartVisibility || {};
    const showContribution = visibility.contribution !== false;
    const showBalance = visibility.balance !== false && hasBalanceSeries;
    const showAppreciation = visibility.appreciation !== false && hasBalanceSeries;
    const showBuy = visibility.buy !== false;
    const showSell = visibility.sell !== false;

    const canvas = ctx.canvas;
    const emptyState = document.getElementById('runningAmountEmpty');

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;
    const filterFromTime =
        filterFrom && Number.isFinite(filterFrom.getTime()) ? filterFrom.getTime() : null;
    const filterToTime =
        filterTo && Number.isFinite(filterTo.getTime()) ? filterTo.getTime() : null;

    const filterDataByDateRange = (data) => {
        return data.filter((item) => {
            const itemDate = parseLocalDate(item.date);
            if (!itemDate) {
                return false;
            }

            // Normalize dates to date-only strings for comparison (YYYY-MM-DD)
            const itemDateStr = itemDate.toISOString().split('T')[0];
            const filterFromStr = filterFrom ? filterFrom.toISOString().split('T')[0] : null;
            const filterToStr = filterTo ? filterTo.toISOString().split('T')[0] : null;

            // Check if item is within the filter range
            const withinStart = !filterFromStr || itemDateStr >= filterFromStr;
            const withinEnd = !filterToStr || itemDateStr <= filterToStr;

            // Preserve padding points that extend the series to the filter endpoint
            const isPadding = item.orderType && item.orderType.toLowerCase() === 'padding';
            if (isPadding && filterToStr) {
                // If it's a padding point, allow it if it matches the filter end
                // or if it's within the valid range (which is covered by withinStart && withinEnd)
                if (itemDateStr === filterToStr) {
                    return withinStart;
                }
            }

            return withinStart && withinEnd;
        });
    };

    const shouldCalculateBalance = showBalance || showAppreciation;

    const mappedBalanceSource = shouldCalculateBalance
        ? (balanceSource || [])
              .map((item) => ({ ...item, date: parseLocalDate(item.date) }))
              .filter((item) => item.date && !Number.isNaN(item.date.getTime()))
        : [];

    const rawBalanceData = shouldCalculateBalance
        ? injectSyntheticStartPoint(
              filterDataByDateRange(mappedBalanceSource),
              balanceSource,
              filterFrom
          )
        : [];

    // Map contribution data to use 'value' key for compatibility with helper functions
    const mappedContributionSource = (contributionSource || []).map((item) => ({
        ...item,
        date: item.tradeDate || item.date,
        value: item.amount,
    }));

    // Use injectCarryForwardStartPoint to carry forward cumulative contribution value at filter start
    const filteredContributionData = filterDataByDateRange(mappedContributionSource);
    const rawContributionData = injectCarryForwardStartPoint(
        filteredContributionData,
        mappedContributionSource,
        filterFrom,
        'value'
    ).map((item) => ({ ...item, date: parseLocalDate(item.date), amount: item.value }));

    const balanceDataWithinRange =
        (filterFrom || filterTo) && rawBalanceData.length > 0
            ? constrainSeriesToRange(rawBalanceData, filterFrom, filterTo)
            : rawBalanceData;

    // Apply smoothing to contribution and balance data
    const contributionSmoothingConfig = getSmoothingConfig('contribution');
    const balanceSmoothingConfig = getSmoothingConfig('balance') || contributionSmoothingConfig;
    const rangeActive = Boolean(filterFrom || filterTo);
    const shouldSmoothContribution =
        !rangeActive &&
        !contributionFromTransactions &&
        rawContributionData.length > 2 &&
        contributionSmoothingConfig;
    const contributionData = shouldSmoothContribution
        ? smoothFinancialData(
              rawContributionData.map((item) => ({ x: item.date.getTime(), y: item.amount })),
              contributionSmoothingConfig,
              true // preserveEnd - keep the last point unchanged
          ).map((p) => ({ date: new Date(p.x), amount: p.y }))
        : rawContributionData;

    const shouldSmoothBalance =
        !filtersActive && balanceDataWithinRange.length > 2 && balanceSmoothingConfig;
    const balanceData = shouldSmoothBalance
        ? smoothFinancialData(
              balanceDataWithinRange.map((item) => ({ x: item.date.getTime(), y: item.value })),
              balanceSmoothingConfig,
              true // preserveEnd - keep the last point unchanged
          ).map((p) => ({ date: new Date(p.x), value: p.y }))
        : balanceDataWithinRange;

    if (contributionData.length === 0 && balanceData.length === 0) {
        stopContributionAnimation();
        if (emptyState) {
            emptyState.style.display = '';
        }
        return;
    }

    const allTimes = new Array(contributionData.length + balanceData.length);
    let allTimesIndex = 0;
    let allTimesMin = Infinity;
    let allTimesMax = -Infinity;
    for (let i = 0; i < contributionData.length; i++) {
        const t = contributionData[i].date.getTime();
        allTimes[allTimesIndex++] = t;
        if (t < allTimesMin) {
            allTimesMin = t;
        }
        if (t > allTimesMax) {
            allTimesMax = t;
        }
    }
    for (let i = 0; i < balanceData.length; i++) {
        const t = balanceData[i].date.getTime();
        allTimes[allTimesIndex++] = t;
        if (t < allTimesMin) {
            allTimesMin = t;
        }
        if (t > allTimesMax) {
            allTimesMax = t;
        }
    }

    // Calculate effective min times based on actual data within filter range
    let minEffectiveTime = Infinity;
    let hasEffectiveTime = false;
    if (rawContributionData.length > 0) {
        // Use the first point (including synthetic start point) for consistency with balance data
        const t = rawContributionData[0].date.getTime();
        if (t < minEffectiveTime) {
            minEffectiveTime = t;
        }
        hasEffectiveTime = true;
    }

    if (showBalance && rawBalanceData.length > 0) {
        const t = rawBalanceData[0].date.getTime();
        if (t < minEffectiveTime) {
            minEffectiveTime = t;
        }
        hasEffectiveTime = true;
    }

    const fallbackMinTime = allTimes.length > 0 ? allTimesMin : Date.now();
    let minTime = hasEffectiveTime ? minEffectiveTime : fallbackMinTime;

    if (Number.isFinite(filterFromTime)) {
        // Ensure minTime is at least the filter start time, but don't extend before actual data
        minTime = Math.max(minTime, filterFromTime);
    }
    // Calculate maxTime - use filter end if specified (clamped to today), otherwise use data max
    let maxTime;
    if (Number.isFinite(filterToTime)) {
        // When filter is active, extend to min(filterEnd, today)
        // This handles both past periods (stops at filter end) and current periods (stops at today)
        maxTime = Math.min(filterToTime, Date.now());
    } else if (allTimes.length > 0) {
        // No filter: use the maximum time from the data (including padding points)
        maxTime = allTimesMax;
    } else {
        maxTime = Date.now();
    }

    // Force-extend series to maxTime to ensure the line reaches the right edge of the chart
    // This fixes issues where the line stops at the last transaction date instead of the filter end/today
    if (contributionData.length > 0) {
        const lastPoint = contributionData[contributionData.length - 1];
        if (lastPoint.date.getTime() < maxTime) {
            contributionData.push({
                date: new Date(maxTime),
                amount: lastPoint.amount,
            });
        }
    }

    if (balanceData.length > 0) {
        const lastPoint = balanceData[balanceData.length - 1];
        if (lastPoint.date.getTime() < maxTime) {
            balanceData.push({
                date: new Date(maxTime),
                value: lastPoint.value,
            });
        }
    }

    // Apply drawdown transformation if in drawdown mode
    let finalContributionData = contributionData;
    let finalBalanceData = balanceData;

    if (drawdownMode) {
        // Calculate historical peak from full series (before filter) for accurate drawdown
        let contributionHistoricalPeak = -Infinity;
        let balanceHistoricalPeak = -Infinity;

        if (filterFrom) {
            const filterFromTime = filterFrom.getTime();
            // Find peak in contribution data before filter start
            const cSrc = mappedContributionSource || [];
            for (let i = 0; i < cSrc.length; i++) {
                const item = cSrc[i];
                const itemDate = new Date(item.date);
                if (itemDate.getTime() < filterFromTime && Number.isFinite(item.value)) {
                    contributionHistoricalPeak = Math.max(contributionHistoricalPeak, item.value);
                }
            }
            // Find peak in balance data before filter start
            const bSrc = mappedBalanceSource || [];
            for (let i = 0; i < bSrc.length; i++) {
                const item = bSrc[i];
                const itemDate = item.date instanceof Date ? item.date : new Date(item.date);
                if (itemDate.getTime() < filterFromTime && Number.isFinite(item.value)) {
                    balanceHistoricalPeak = Math.max(balanceHistoricalPeak, item.value);
                }
            }
        }

        finalContributionData = applyDrawdownToSeries(
            contributionData,
            'amount',
            contributionHistoricalPeak
        );
        finalBalanceData = applyDrawdownToSeries(balanceData, 'value', balanceHistoricalPeak);
    }

    if (emptyState) {
        emptyState.style.display = 'none';
    }

    const isMobile = window.innerWidth <= 768;
    const padding = isMobile
        ? { top: 15, right: 20, bottom: 35, left: 50 }
        : { top: 20, right: 30, bottom: 48, left: 70 };
    const plotWidth = canvas.offsetWidth - padding.left - padding.right;
    const totalPlotHeight = canvas.offsetHeight - padding.top - padding.bottom;
    const volumeGap = isMobile ? 10 : 16;
    const minMainHeight = isMobile ? 120 : 180;
    const minVolumeHeight = isMobile ? 50 : 80;
    const availableHeight = Math.max(totalPlotHeight - volumeGap, 0);

    let mainPlotHeight = 0;
    let volumeHeight = 0;

    if (availableHeight <= 0) {
        mainPlotHeight = Math.max(totalPlotHeight, 0);
    } else if (availableHeight < minMainHeight + minVolumeHeight) {
        const scale = availableHeight / (minMainHeight + minVolumeHeight);
        mainPlotHeight = minMainHeight * scale;
        volumeHeight = minVolumeHeight * scale;
    } else {
        mainPlotHeight = Math.max(minMainHeight, availableHeight * 0.7);
        volumeHeight = availableHeight - mainPlotHeight;
        if (volumeHeight < minVolumeHeight) {
            volumeHeight = minVolumeHeight;
            mainPlotHeight = availableHeight - volumeHeight;
        }
    }

    const plotHeight = mainPlotHeight;
    const volumeTop = padding.top + plotHeight + (volumeHeight > 0 ? volumeGap : 0);

    // Remove debug object
    if (window.DEBUG_CHART) {
        delete window.DEBUG_CHART;
    }

    // Compute appreciation data: balance − contribution at aligned timestamps
    const appreciationData =
        !drawdownMode && showAppreciation
            ? computeAppreciationSeries(finalBalanceData, finalContributionData)
            : [];

    // Bolt: Use explicit O(N) loop instead of chained .map() and Math.max(...spread) to eliminate GC overhead and avoid call stack limits
    const combinedValues = [];
    let rawMin = Infinity;
    let rawMax = -Infinity;

    for (let i = 0; i < finalContributionData.length; i++) {
        const val = finalContributionData[i].amount;
        if (Number.isFinite(val)) {
            combinedValues.push(val);
            if (val < rawMin) {
                rawMin = val;
            }
            if (val > rawMax) {
                rawMax = val;
            }
        }
    }
    for (let i = 0; i < finalBalanceData.length; i++) {
        const val = finalBalanceData[i].value;
        if (Number.isFinite(val)) {
            combinedValues.push(val);
            if (val < rawMin) {
                rawMin = val;
            }
            if (val > rawMax) {
                rawMax = val;
            }
        }
    }
    for (let i = 0; i < appreciationData.length; i++) {
        const val = appreciationData[i].value;
        if (Number.isFinite(val)) {
            combinedValues.push(val);
            if (val < rawMin) {
                rawMin = val;
            }
            if (val > rawMax) {
                rawMax = val;
            }
        }
    }

    const hasValues = combinedValues.length > 0;
    if (!hasValues) {
        rawMin = 0;
        rawMax = 0;
    }

    const {
        startYAxisAtZero = true,
        paddingRatio: configuredPaddingRatio = 0.05,
        minPaddingValue: configuredMinPadding = 0,
    } = CONTRIBUTION_CHART_SETTINGS || {};

    const paddingRatio = Number.isFinite(configuredPaddingRatio)
        ? Math.max(configuredPaddingRatio, 0)
        : 0.05;
    const minPaddingValue = Number.isFinite(configuredMinPadding)
        ? Math.max(configuredMinPadding, 0)
        : 0;

    let yMin = startYAxisAtZero ? Math.min(0, rawMin) : rawMin;
    let yMax = startYAxisAtZero ? Math.max(rawMax, 0) : rawMax;

    // In drawdown mode, force yMax to 0 and yMin to include all negative values
    if (drawdownMode) {
        yMax = 0;
        yMin = Math.min(rawMin, 0);
    }

    if (!hasValues) {
        yMin = startYAxisAtZero || drawdownMode ? 0 : 0;
        yMax = drawdownMode ? 0 : 1;
        if (drawdownMode) {
            yMin = -1;
        }
    }

    const range = yMax - yMin;
    const paddingDelta =
        range > 0
            ? Math.max(range * paddingRatio, minPaddingValue)
            : Math.max(Math.abs(yMax || yMin) * paddingRatio, minPaddingValue || 1);

    if (startYAxisAtZero) {
        yMax += paddingDelta;
    } else {
        yMin -= paddingDelta;
        yMax += paddingDelta;
    }

    if (yMax <= yMin) {
        const fallbackSpan = paddingDelta || 1;
        yMax = yMin + fallbackSpan;
    }

    const xScale = (t) =>
        padding.left +
        (maxTime === minTime ? plotWidth / 2 : ((t - minTime) / (maxTime - minTime)) * plotWidth);
    const yScale = (v) => padding.top + plotHeight - ((v - yMin) / (yMax - yMin)) * plotHeight;

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        formatCurrencyCompact,
        false, // isPerformanceChart
        volumeHeight > 0 ? { drawXAxis: false } : {},
        transactionState.selectedCurrency || 'USD'
    );

    const rootStyles = window.getComputedStyle(document.documentElement);
    const colors = getChartColors(rootStyles);
    const contributionAnimationEnabled = isAnimationEnabled('contribution');
    const animationPhase = advanceContributionAnimation(timestamp);

    const animatedSeries = [];
    const filterStartTime = Number.isFinite(filterFromTime) ? filterFromTime : null;

    const formatBalanceValue = (value) =>
        formatCurrencyCompact(value, { currency: transactionState.selectedCurrency || 'USD' });

    const formatContributionAnnotationValue = (value) => {
        const amount = Number.isFinite(Number(value)) ? Number(value) : 0;
        if (Math.abs(amount) < 1) {
            return formatBalanceValue(amount);
        }
        const currency = transactionState.selectedCurrency || 'USD';
        return formatCurrencyCompact(amount, { currency });
    };

    const showChartLabels = getShowChartLabels();

    if (showContribution && finalContributionData.length > 0) {
        // Bolt: Replaced chained .filter().map() with a single loop to eliminate intermediate array and closure allocations
        const contribData = [];
        for (let i = 0; i < finalContributionData.length; i++) {
            const item = finalContributionData[i];
            const time = item.date.getTime();
            if (!filterStartTime || time >= filterStartTime) {
                contribData.push({ time, value: item.amount });
            }
        }
        animatedSeries.push({
            key: 'contribution',
            color: colors.contribution,
            lineWidth: CHART_LINE_WIDTHS.contribution ?? 2,
            order: 1,
            data: contribData,
        });
    }

    if (showBalance && finalBalanceData.length > 0) {
        // Bolt: Replaced chained .filter().map() with a single loop to eliminate intermediate array and closure allocations
        const balData = [];
        for (let i = 0; i < finalBalanceData.length; i++) {
            const item = finalBalanceData[i];
            const time = item.date.getTime();
            if (!filterStartTime || time >= filterStartTime) {
                balData.push({ time, value: item.value });
            }
        }
        animatedSeries.push({
            key: 'balance',
            color: colors.portfolio,
            lineWidth: CHART_LINE_WIDTHS.balance ?? 2,
            order: 2,
            data: balData,
        });
    }

    if (showAppreciation && appreciationData.length > 0) {
        const appreciationGradient = BALANCE_GRADIENTS['appreciation'];
        // Bolt: Replaced chained .filter().map() with a single loop to eliminate intermediate array and closure allocations
        const apprecData = [];
        for (let i = 0; i < appreciationData.length; i++) {
            const item = appreciationData[i];
            const time = item.date.getTime();
            if (!filterStartTime || time >= filterStartTime) {
                apprecData.push({ time, value: item.value });
            }
        }
        animatedSeries.push({
            key: 'appreciation',
            color: appreciationGradient ? appreciationGradient[1] : '#FF8E53',
            lineWidth: CHART_LINE_WIDTHS.appreciation ?? 1,
            order: 1.5,
            data: apprecData,
        });
    }

    for (let sIdx = 0; sIdx < animatedSeries.length; sIdx++) {
        const series = animatedSeries[sIdx];
        const coords = new Array(series.data.length);
        if (series.data.length > 0) {
            // Ensure visual continuity by adding a synthetic start point if filtering
            if (filterStartTime && series.data[0].time > filterStartTime) {
                // ... same logic as injectSyntheticStartPoint but for drawing coordinates ...
                // actually injectSyntheticStartPoint was applied to raw data, so series.data should already cover it
                // except if clamping cut it off?
                // The data passed here is finalBalanceData/finalContributionData which went through helpers
            }
        }

        for (let i = 0; i < series.data.length; i++) {
            const point = series.data[i];
            coords[i] = {
                x: xScale(point.time),
                y: yScale(point.value),
                time: point.time,
                value: point.value,
            };
        }

        series.coords = coords;
    }

    // Draw divider line between line chart and volume chart
    if (volumeHeight > 0) {
        const dividerY = padding.top + plotHeight + volumeGap / 2;
        ctx.save();
        ctx.beginPath();
        ctx.moveTo(padding.left, dividerY);
        ctx.lineTo(padding.left + plotWidth, dividerY);
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
        ctx.lineWidth = 1;
        ctx.stroke();
        ctx.restore();
    }

    const { buyVolumeMap, sellVolumeMap } = drawVolumeChart(ctx, rawContributionData, {
        showBuy,
        showSell,
        minTime,
        maxTime,
        volumeHeight,
        volumeTop,
        padding,
        plotWidth,
        xScale,
        formatCurrencyCompact,
        selectedCurrency: transactionState.selectedCurrency || 'USD',
        volumeGap,
    });

    const chartBounds = {
        top: padding.top,
        bottom: volumeHeight > 0 ? volumeTop : padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    drawContributionMarkers(ctx, rawContributionData, {
        showMarkersConfig: CHART_MARKERS?.showContributionMarkers !== false,
        showBuy,
        showSell,
        minTime,
        maxTime,
        xScale,
        yScale,
        bounds: chartBounds,
        colors,
    });

    const sortedSeries = animatedSeries
        .map((series) => ({ ...series }))
        .sort((a, b) => (a.order ?? 0) - (b.order ?? 0));

    let hasAnimatedSeries = false;

    const areaBaselineY = drawdownMode ? yScale(0) : chartBounds.bottom;

    // Line chart clipping is now handled by the global clip above,
    // but we might want to restrict it further to just the plot area (excluding volume)
    // However, since volume is below, and line chart is above, they don't overlap much.
    // But to be safe and consistent with previous logic:

    for (let index = 0; index < sortedSeries.length; index++) {
        const series = sortedSeries[index];
        const coords = series.coords || [];
        if (coords.length === 0) {
            continue;
        }

        // Apply gradient effect for balance chart lines
        const gradientStops = BALANCE_GRADIENTS[series.key];
        if (gradientStops) {
            const gradient = ctx.createLinearGradient(padding.left, 0, padding.left + plotWidth, 0);
            gradient.addColorStop(0, gradientStops[0]);
            gradient.addColorStop(1, gradientStops[1]);
            ctx.strokeStyle = gradient;
        } else {
            ctx.strokeStyle = series.color;
        }

        if (mountainFill.enabled) {
            const gradientStops = BALANCE_GRADIENTS[series.key];
            const colorStops =
                gradientStops && gradientStops.length === 2
                    ? gradientStops
                    : [series.color, series.color];

            drawMountainFill(ctx, coords, areaBaselineY, {
                color: series.color,
                colorStops,
                opacityTop: drawdownMode ? 0 : 0.35,
                opacityBottom: drawdownMode ? 0.35 : 0,
                bounds: chartBounds,
            });
        }

        ctx.beginPath();
        for (let coordIndex = 0; coordIndex < coords.length; coordIndex++) {
            const coord = coords[coordIndex];
            if (coordIndex === 0) {
                ctx.moveTo(coord.x, coord.y);
            } else {
                ctx.lineTo(coord.x, coord.y);
            }
        }
        ctx.lineWidth = series.lineWidth;
        ctx.stroke();

        if (contributionAnimationEnabled) {
            // Use gradient end color for glow effect
            const glowColor = gradientStops ? gradientStops[1] : series.color;
            drawSeriesGlow(
                ctx,
                { coords, color: glowColor, lineWidth: series.lineWidth },
                {
                    basePhase: animationPhase,
                    seriesIndex: index,
                    isMobile,
                    chartKey: 'contribution',
                }
            );
            hasAnimatedSeries = true;
        }
    }

    // ctx.restore(); // Removed inner restore, will restore at the end

    if (contributionAnimationEnabled && hasAnimatedSeries) {
        scheduleContributionAnimation(chartManager);
    } else {
        stopContributionAnimation();
    }

    // Draw start and end values using raw data to ensure accuracy (or transformed data for drawdown)
    // Use separate bounds for start vs end labels so they don't interfere across chart sides
    const startLabelBounds = [];
    const endLabelBounds = [];

    // Collect start labels to draw them in sorted order.
    // This fixed stacking order when multiple lines start near 0.
    const startLabelsToDraw = [];

    const labelContributionData = drawdownMode ? finalContributionData : rawContributionData;
    if (showChartLabels && showContribution && labelContributionData.length > 0) {
        const contributionGradient = BALANCE_GRADIENTS['contribution'];
        const contributionStartColor = contributionGradient
            ? contributionGradient[0]
            : colors.contribution;
        const contributionEndColor = contributionGradient
            ? contributionGradient[1]
            : colors.contribution;

        const firstContribution =
            labelContributionData.find((item) => item.synthetic) ||
            labelContributionData.find((item) => {
                if (typeof item.orderType !== 'string') {
                    return true;
                }
                return item.orderType.toLowerCase() !== 'padding';
            }) ||
            labelContributionData[0];
        if (firstContribution && Math.abs(firstContribution.amount) >= 0.01) {
            const firstContributionX = xScale(firstContribution.date.getTime());
            const firstContributionY = yScale(
                drawdownMode ? firstContribution.amount : firstContribution.amount
            );

            startLabelsToDraw.push({
                y: firstContributionY,
                draw: (existingBounds) =>
                    drawStartValue(
                        ctx,
                        firstContributionX,
                        firstContributionY,
                        firstContribution.amount,
                        contributionStartColor,
                        isMobile,
                        padding,
                        plotWidth,
                        plotHeight,
                        formatContributionAnnotationValue,
                        true,
                        existingBounds
                    ),
            });
        }

        const lastContribution = labelContributionData[labelContributionData.length - 1];
        const lastContributionX = xScale(lastContribution.date.getTime());
        const lastContributionY = yScale(lastContribution.amount);
        const endBounds = drawEndValue(
            ctx,
            lastContributionX,
            lastContributionY,
            lastContribution.amount,
            contributionEndColor,
            isMobile,
            padding,
            plotWidth,
            plotHeight,
            formatContributionAnnotationValue,
            true,
            endLabelBounds
        );
        if (endBounds) {
            endLabelBounds.push(endBounds);
        }
    }

    const labelBalanceData = drawdownMode ? finalBalanceData : rawBalanceData;
    if (showChartLabels && showBalance && labelBalanceData.length > 0) {
        const balanceGradient = BALANCE_GRADIENTS['balance'];
        const balanceStartColor = balanceGradient ? balanceGradient[0] : colors.portfolio;
        const balanceEndColor = balanceGradient ? balanceGradient[1] : colors.portfolio;

        const firstBalance = labelBalanceData[0];
        if (Math.abs(firstBalance.value) >= 0.01) {
            const firstBalanceX = xScale(firstBalance.date.getTime());
            const firstBalanceY = yScale(firstBalance.value);

            startLabelsToDraw.push({
                y: firstBalanceY,
                draw: (existingBounds) =>
                    drawStartValue(
                        ctx,
                        firstBalanceX,
                        firstBalanceY,
                        firstBalance.value,
                        balanceStartColor,
                        isMobile,
                        padding,
                        plotWidth,
                        plotHeight,
                        formatBalanceValue,
                        true,
                        existingBounds
                    ),
            });
        }

        const lastBalance = labelBalanceData[labelBalanceData.length - 1];
        const lastBalanceX = xScale(lastBalance.date.getTime());
        const lastBalanceY = yScale(lastBalance.value);
        const balEndBounds = drawEndValue(
            ctx,
            lastBalanceX,
            lastBalanceY,
            lastBalance.value,
            balanceEndColor,
            isMobile,
            padding,
            plotWidth,
            plotHeight,
            formatBalanceValue,
            true,
            endLabelBounds
        );
        if (balEndBounds) {
            endLabelBounds.push(balEndBounds);
        }
    }

    // Draw appreciation labels (only in non-drawdown mode)
    if (showChartLabels && showAppreciation && !drawdownMode && appreciationData.length > 0) {
        const appreciationGradient = BALANCE_GRADIENTS['appreciation'];
        const appreciationStartColor = appreciationGradient ? appreciationGradient[0] : '#FF8E53';
        const appreciationEndColor = appreciationGradient ? appreciationGradient[1] : '#FF8E53';

        const firstAppreciation = appreciationData[0];
        if (Math.abs(firstAppreciation.value) >= 0.01) {
            const firstAppreciationX = xScale(firstAppreciation.date.getTime());
            const firstAppreciationY = yScale(firstAppreciation.value);

            startLabelsToDraw.push({
                y: firstAppreciationY,
                draw: (existingBounds) =>
                    drawStartValue(
                        ctx,
                        firstAppreciationX,
                        firstAppreciationY,
                        firstAppreciation.value,
                        appreciationStartColor,
                        isMobile,
                        padding,
                        plotWidth,
                        plotHeight,
                        formatBalanceValue,
                        true,
                        existingBounds
                    ),
            });
        }

        const lastAppreciation = appreciationData[appreciationData.length - 1];
        const lastAppreciationX = xScale(lastAppreciation.date.getTime());
        const lastAppreciationY = yScale(lastAppreciation.value);
        const apprEndBounds = drawEndValue(
            ctx,
            lastAppreciationX,
            lastAppreciationY,
            lastAppreciation.value,
            appreciationEndColor,
            isMobile,
            padding,
            plotWidth,
            plotHeight,
            formatBalanceValue,
            true,
            endLabelBounds
        );
        if (apprEndBounds) {
            endLabelBounds.push(apprEndBounds);
        }
    }

    // --- Sort and Draw Starts ---
    drawSortedStartLabels(startLabelsToDraw, startLabelBounds);

    ctx.restore(); // Restore the global clip

    if (legendState.contributionDirty) {
        // Use gradient end colors for legend
        const contributionGradient = BALANCE_GRADIENTS['contribution'];
        const balanceGradient = BALANCE_GRADIENTS['balance'];
        const legendSeries = [
            {
                key: 'contribution',
                name: 'Contribution',
                color: contributionGradient ? contributionGradient[1] : colors.contribution,
            },
        ];
        if (hasBalanceSeries) {
            legendSeries.push({
                key: 'balance',
                name: 'Balance',
                color: balanceGradient ? balanceGradient[1] : colors.portfolio,
            });
        }
        if (hasBalanceSeries && !drawdownMode) {
            const appreciationGradient = BALANCE_GRADIENTS['appreciation'];
            legendSeries.push({
                key: 'appreciation',
                name: 'Appreciation',
                color: appreciationGradient ? appreciationGradient[1] : '#FF8E53',
            });
        }
        legendSeries.push({ key: 'buy', name: 'Buy', color: colors.buy });
        legendSeries.push({ key: 'sell', name: 'Sell', color: colors.sell });
        updateLegend(legendSeries, chartManager);
        legendState.contributionDirty = false;
    }

    const normalizeToDay = (time) => {
        const day = new Date(time);
        day.setHours(0, 0, 0, 0);
        return day.getTime();
    };

    const seriesDisplayLabels = {
        balance: 'Balance',
        contribution: 'Contribution',
        appreciation: 'Appreciation',
    };

    const baseSeries = animatedSeries.map((series) => {
        const displayLabel = seriesDisplayLabels[series.key] || series.key;
        let displayColor = series.color;
        if (series.key === 'balance') {
            displayColor =
                (BALANCE_GRADIENTS.balance && BALANCE_GRADIENTS.balance[1]) || colors.portfolio;
        } else if (series.key === 'contribution') {
            displayColor =
                (BALANCE_GRADIENTS.contribution && BALANCE_GRADIENTS.contribution[1]) ||
                colors.contribution;
        } else if (series.key === 'appreciation') {
            displayColor =
                (BALANCE_GRADIENTS.appreciation && BALANCE_GRADIENTS.appreciation[1]) || '#FF8E53';
        }
        return {
            key: series.key,
            label: displayLabel,
            color: displayColor,
            getValueAtTime: createTimeInterpolator(series.data),
            formatValue: formatBalanceValue,
            formatDelta: (delta) => formatCurrencyInline(delta),
        };
    });

    const volumeSeries = [];
    const makeVolumeGetter = (map) => (time) => {
        const value = map.get(normalizeToDay(time));
        return Number.isFinite(value) ? value : 0;
    };

    volumeSeries.push({
        key: 'buyVolume',
        label: 'Buy',
        color: colors.buy,
        getValueAtTime: makeVolumeGetter(buyVolumeMap),
        formatValue: formatCurrencyInline,
        includeInRangeSummary: false,
        drawMarker: false,
    });

    volumeSeries.push({
        key: 'sellVolume',
        label: 'Sell',
        color: colors.sell,
        getValueAtTime: makeVolumeGetter(sellVolumeMap),
        formatValue: formatCurrencyInline,
        includeInRangeSummary: false,
        drawMarker: false,
    });

    const layoutKey = drawdownMode ? 'drawdownAbs' : 'contribution';
    chartLayouts[layoutKey] = {
        key: layoutKey,
        minTime,
        maxTime,
        valueType: 'currency',
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            if (!Number.isFinite(pixelX)) {
                return minTime;
            }
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: [...baseSeries, ...volumeSeries],
    };

    drawCrosshairOverlay(ctx, chartLayouts[layoutKey]);

    if (contributionAnimationEnabled && hasAnimatedSeries) {
        scheduleContributionAnimation(chartManager);
    } else {
        stopContributionAnimation();
    }
}

/**
 * Sorts start labels by Y-position (descending, i.e., bottom-up) and draws them.
 * This ensures correct visual stacking when labels are constrained at the bottom.
 *
 * @param {Array<{y: number, draw: (existingBounds: Array) => object}>} items
 * @param {Array} startLabelBounds
 */
export function drawSortedStartLabels(items, startLabelBounds) {
    if (!items || items.length === 0) {
        return;
    }

    // Sort by Y descending (largest Y = bottom of screen first)
    items.sort((a, b) => b.y - a.y);

    for (const item of items) {
        const bounds = item.draw(startLabelBounds);
        if (bounds) {
            startLabelBounds.push(bounds);
        }
    }
}

import { drawAxes, drawMarker } from '../core.js';

export function drawContributionMarkers(ctx, rawContributionData, options = {}) {
    const {
        showMarkersConfig,
        showBuy,
        showSell,
        minTime,
        maxTime,
        xScale,
        yScale,
        bounds,
        colors,
    } = options;

    if (showMarkersConfig === false) {
        return;
    }

    const markerGroups = new Map();

    // Bolt: Use explicit loops instead of .forEach to eliminate closure allocations and reduce GC overhead
    for (let i = 0; i < rawContributionData.length; i += 1) {
        const item = rawContributionData[i];
        if (typeof item.orderType !== 'string') {
            continue;
        }
        const type = item.orderType.toLowerCase();
        if (!((type === 'buy' && showBuy) || (type === 'sell' && showSell))) {
            continue;
        }
        const timestamp = item.date.getTime();
        if (!Number.isFinite(timestamp)) {
            continue;
        }

        if (timestamp < minTime || timestamp > maxTime) {
            continue;
        }

        if (!markerGroups.has(timestamp)) {
            markerGroups.set(timestamp, { buys: [], sells: [] });
        }
        const group = markerGroups.get(timestamp);
        const netAmount = Number(item.netAmount) || 0;
        const amount = Number(item.amount) || 0;
        const radius = Math.min(8, Math.max(2, Math.abs(netAmount) / 500));
        if (type === 'buy') {
            group.buys.push({ radius, amount, netAmount });
        } else {
            group.sells.push({ radius, amount, netAmount });
        }
    }

    if (markerGroups.size > 0) {
        // Bolt: Use explicit loop over Map entries
        for (const [timestamp, group] of markerGroups.entries()) {
            const x = xScale(timestamp);

            const sortedBuys = [...group.buys].sort((a, b) => b.radius - a.radius);
            let buyOffset = 8;
            for (let j = 0; j < sortedBuys.length; j += 1) {
                const marker = sortedBuys[j];
                const y = yScale(marker.amount) - buyOffset - marker.radius;
                drawMarker(ctx, x, y, marker.radius, true, colors, bounds);
                buyOffset += marker.radius * 2 + 4;
            }

            const sortedSells = [...group.sells].sort((a, b) => b.radius - a.radius);
            let sellOffset = 8;
            for (let j = 0; j < sortedSells.length; j += 1) {
                const marker = sortedSells[j];
                const y = yScale(marker.amount) + sellOffset + marker.radius;
                drawMarker(ctx, x, y, marker.radius, false, colors, bounds);
                sellOffset += marker.radius * 2 + 4;
            }
        }
    }
}

export function drawVolumeChart(ctx, rawContributionData, options = {}) {
    const {
        showBuy,
        showSell,
        minTime,
        maxTime,
        volumeHeight,
        volumeTop,
        padding,
        plotWidth,
        xScale,
        formatCurrencyCompact,
        selectedCurrency,
    } = options;

    const buyVolumeMap = new Map();
    const sellVolumeMap = new Map();
    const volumeEntries = [];
    let maxVolume = 0;
    const volumeGroups = new Map();

    // Bolt: Use explicit loops instead of .forEach to eliminate closure allocations
    for (let i = 0; i < rawContributionData.length; i += 1) {
        const item = rawContributionData[i];
        if (typeof item.orderType !== 'string') {
            continue;
        }
        const type = item.orderType.toLowerCase();

        // If we have explicit volume data, we can process even if type is 'mixed'
        const hasExplicitVolume = Number(item.buyVolume) > 0 || Number(item.sellVolume) > 0;

        if (!hasExplicitVolume && !((type === 'buy' && showBuy) || (type === 'sell' && showSell))) {
            continue;
        }
        const normalizedDate = new Date(item.date.getTime());
        normalizedDate.setHours(0, 0, 0, 0);
        const timestamp = normalizedDate.getTime();
        if (!Number.isFinite(timestamp)) {
            continue;
        }
        // Ensure volume bars are strictly within the visible chart range
        if (timestamp < minTime || timestamp > maxTime) {
            continue;
        }
        const netAmount = Math.abs(Number(item.netAmount) || 0);
        if (!hasExplicitVolume && netAmount <= 0) {
            continue;
        }

        if (!volumeGroups.has(timestamp)) {
            volumeGroups.set(timestamp, { totalBuy: 0, totalSell: 0 });
        }
        const totals = volumeGroups.get(timestamp);

        // Use pre-consolidated volumes if available
        if (Number.isFinite(item.buyVolume) || Number.isFinite(item.sellVolume)) {
            if (showBuy) {
                totals.totalBuy += Number(item.buyVolume) || 0;
            }
            if (showSell) {
                totals.totalSell += Number(item.sellVolume) || 0;
            }
        } else if (type === 'buy') {
            // Fallback for non-consolidated items
            totals.totalBuy += netAmount;
        } else {
            totals.totalSell += netAmount;
        }
    }

    for (const [timestamp, totals] of volumeGroups.entries()) {
        const { totalBuy, totalSell } = totals;
        const totalBuyVolume = totalBuy;
        const totalSellVolume = totalSell;
        if (totalBuyVolume === 0 && totalSellVolume === 0) {
            continue;
        }

        maxVolume = Math.max(maxVolume, totalBuyVolume, totalSellVolume);
        volumeEntries.push({
            timestamp,
            totalBuyVolume,
            totalSellVolume,
        });
    }

    for (let i = 0; i < volumeEntries.length; i += 1) {
        const { timestamp, totalBuyVolume, totalSellVolume } = volumeEntries[i];
        if (totalBuyVolume > 0) {
            buyVolumeMap.set(timestamp, totalBuyVolume);
        }
        if (totalSellVolume > 0) {
            sellVolumeMap.set(timestamp, totalSellVolume);
        }
    }

    const volumePadding = {
        top: volumeTop,
        right: padding.right,
        bottom: padding.bottom,
        left: padding.left,
    };

    let volumeYScale = null;
    if (volumeHeight > 0) {
        const volumeYMin = 0;
        const volumeYMax = maxVolume > 0 ? maxVolume * 1.1 : 1;
        const volumeRange = volumeYMax - volumeYMin || 1;
        volumeYScale = (value) =>
            volumePadding.top + volumeHeight - ((value - volumeYMin) / volumeRange) * volumeHeight;

        drawAxes(
            ctx,
            volumePadding,
            plotWidth,
            volumeHeight,
            minTime,
            maxTime,
            volumeYMin,
            volumeYMax,
            xScale,
            volumeYScale,
            formatCurrencyCompact,
            false,
            { drawYAxis: maxVolume > 0 },
            selectedCurrency || 'USD'
        );
    }

    if (volumeHeight > 0 && volumeEntries.length > 0 && typeof volumeYScale === 'function') {
        volumeEntries.sort((a, b) => a.timestamp - b.timestamp);
        const barWidth = 4;
        const baselineY = volumePadding.top + volumeHeight;

        const allVolumeRects = [];

        for (let i = 0; i < volumeEntries.length; i += 1) {
            const entry = volumeEntries[i];
            const { timestamp, totalBuyVolume, totalSellVolume } = entry;
            const x = xScale(timestamp);

            const bars = [];
            if (totalBuyVolume > 0) {
                bars.push({
                    type: 'buy',
                    volume: totalBuyVolume,
                    fill: 'rgba(76, 175, 80, 0.6)',
                    stroke: 'rgba(76, 175, 80, 0.8)',
                });
            }
            if (totalSellVolume > 0) {
                bars.push({
                    type: 'sell',
                    volume: totalSellVolume,
                    fill: 'rgba(244, 67, 54, 0.6)',
                    stroke: 'rgba(244, 67, 54, 0.8)',
                });
            }
            if (bars.length === 0) {
                continue;
            }

            const dayMaxVolume = Math.max(totalBuyVolume, totalSellVolume);

            for (let j = 0; j < bars.length; j += 1) {
                const bar = bars[j];
                const topY = volumeYScale(bar.volume);
                const height = baselineY - topY;

                let actualWidth = barWidth;
                if (bars.length === 2) {
                    if (bar.volume < dayMaxVolume) {
                        actualWidth = barWidth;
                    } else if (totalBuyVolume === totalSellVolume && bar.type === 'sell') {
                        actualWidth = barWidth;
                    } else {
                        actualWidth = barWidth * 2;
                    }
                }

                const currentX = Math.round(x - actualWidth / 2);

                if (height > 0) {
                    allVolumeRects.push({
                        timestamp,
                        x: currentX,
                        width: actualWidth,
                        topY,
                        height,
                        fill: bar.fill,
                        stroke: bar.stroke,
                        order: actualWidth < barWidth ? 1 : 0,
                    });
                }
            }
        }

        const originalFill = ctx.fillStyle;
        const originalStroke = ctx.strokeStyle;
        const originalLineWidth = ctx.lineWidth;

        allVolumeRects.sort((a, b) => {
            if (a.height !== b.height) {
                return b.height - a.height;
            }
            if (a.timestamp !== b.timestamp) {
                return a.timestamp - b.timestamp;
            }
            return a.order - b.order;
        });

        for (let i = 0; i < allVolumeRects.length; i += 1) {
            const rect = allVolumeRects[i];
            ctx.fillStyle = rect.fill;
            ctx.fillRect(rect.x, rect.topY, rect.width, rect.height);

            ctx.strokeStyle = rect.stroke;
            ctx.lineWidth = 1;
            ctx.strokeRect(rect.x, rect.topY, rect.width, rect.height);
        }

        ctx.fillStyle = originalFill;
        ctx.strokeStyle = originalStroke;
        ctx.lineWidth = originalLineWidth;
    }

    return { buyVolumeMap, sellVolumeMap, volumeYScale };
}

import { transactionState, getShowChartLabels } from '../../state.js';
import { chartLayouts } from '../state.js';
import { mountainFill, CHART_LINE_WIDTHS } from '../../../config.js';
import { BENCHMARK_GRADIENTS, PERFORMANCE_SERIES_CURRENCY } from '../config.js';
import { convertBetweenCurrencies } from '../../utils.js';
import { drawAxes, drawMountainFill, drawEndValue } from '../core.js';
import { getChartColors, createTimeInterpolator, clampTime, parseLocalDate } from '../helpers.js';
import { updateCrosshairUI, updateLegend, drawCrosshairOverlay } from '../interaction.js';
import {
    stopContributionAnimation,
    stopFxAnimation,
    stopPerformanceAnimation,
    isAnimationEnabled,
    advancePerformanceAnimation,
    drawSeriesGlow,
    schedulePerformanceAnimation,
} from '../animation.js';

export function buildDrawdownSeries(series) {
    if (!Array.isArray(series) || series.length === 0) {
        return [];
    }

    // Sort by date/transactionId to ensure correct order
    const sortedSeries = [...series].sort((a, b) => {
        const timeA = parseLocalDate(a.date || a.tradeDate).getTime();
        const timeB = parseLocalDate(b.date || b.tradeDate).getTime();
        if (timeA !== timeB) {
            return timeA - timeB;
        }
        return (a.transactionId ?? 0) - (b.transactionId ?? 0);
    });

    const drawdownSeries = [];
    let highWaterMark = -Infinity;

    for (const point of sortedSeries) {
        const value = Number(point.value ?? point.amount); // Handle both value and amount keys
        if (!Number.isFinite(value)) {
            continue;
        }

        if (value > highWaterMark) {
            highWaterMark = value;
        }

        const date = point.date || point.tradeDate;
        // Avoid division by zero or negative high water marks (logic assumes value >= 0 generally)
        // If highWaterMark is <= 0 (e.g. only losses or shorts?), logic assumes long-only portfolio for standard HWM.
        // Standard drawdown formula: (Value - Peak) / Peak
        const safePeak = highWaterMark > 0 ? highWaterMark : 1;
        const drawdown = ((value - highWaterMark) / safePeak) * 100;

        drawdownSeries.push({
            date: parseLocalDate(date),
            value: drawdown,
            rawValue: value,
            peak: highWaterMark,
        });
    }

    return drawdownSeries;
}

export async function drawDrawdownChart(ctx, chartManager, timestamp) {
    const selectedCurrency = transactionState.selectedCurrency || 'USD';
    // Percentage Drawdown Chart (Benchmarks)
    // Absolute drawdown is now handled by drawContributionChart with drawdownMode=true

    stopContributionAnimation();
    stopFxAnimation();

    const canvas = ctx.canvas;
    const isMobile = window.innerWidth <= 768;
    const padding = isMobile
        ? { top: 15, right: 20, bottom: 35, left: 50 }
        : { top: 20, right: 30, bottom: 48, left: 70 };
    const plotWidth = canvas.offsetWidth - padding.left - padding.right;
    const plotHeight = canvas.offsetHeight - padding.top - padding.bottom;

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    let seriesToDraw = [];
    let orderedKeys = [];

    // ========== PERCENTAGE MODE ==========
    // Use performanceSeries (benchmark data) and calculate percentage drawdown
    const performanceSeries =
        transactionState.performanceSeries && typeof transactionState.performanceSeries === 'object'
            ? transactionState.performanceSeries
            : {};

    if (Object.keys(performanceSeries).length === 0) {
        stopPerformanceAnimation();
        chartLayouts.drawdown = null;
        updateCrosshairUI(null, null);
        return;
    }

    const { chartVisibility } = transactionState;
    orderedKeys = Object.keys(performanceSeries).sort((a, b) => {
        if (a === '^LZ') {
            return -1;
        }
        if (b === '^LZ') {
            return 1;
        }
        return a.localeCompare(b);
    });

    for (let i = 0; i < orderedKeys.length; i++) {
        const key = orderedKeys[i];
        if (transactionState.chartVisibility[key] === undefined) {
            transactionState.chartVisibility[key] = key === '^LZ' || key === '^GSPC';
        }
    }

    const allExpectedSeries = new Array(orderedKeys.length);
    for (let i = 0; i < orderedKeys.length; i++) {
        const key = orderedKeys[i];
        const points = Array.isArray(performanceSeries[key]) ? performanceSeries[key] : [];
        const sourceCurrency = PERFORMANCE_SERIES_CURRENCY[key] || 'USD';

        const convertedPoints = new Array(points.length);
        for (let j = 0; j < points.length; j++) {
            const point = points[j];
            convertedPoints[j] = {
                date: point.date,
                value: convertBetweenCurrencies(
                    Number(point.value),
                    sourceCurrency,
                    point.date,
                    selectedCurrency
                ),
            };
        }

        const drawdownPoints = buildDrawdownSeries(convertedPoints);

        allExpectedSeries[i] = {
            key,
            name: key,
            data: drawdownPoints,
        };
    }

    seriesToDraw = allExpectedSeries.filter((s) => chartVisibility[s.key] !== false);

    if (seriesToDraw.length === 0) {
        stopPerformanceAnimation();
        chartLayouts.drawdown = null;
        updateCrosshairUI(null, null);
        return;
    }

    // Filter by date range
    const filteredSeries = [];
    const allPoints = [];
    for (let i = 0; i < seriesToDraw.length; i++) {
        const s = seriesToDraw[i];
        const validData = [];
        for (let j = 0; j < s.data.length; j++) {
            const d = s.data[j];
            const pointDate = d.date;
            if ((!filterFrom || pointDate >= filterFrom) && (!filterTo || pointDate <= filterTo)) {
                validData.push(d);
                allPoints.push(d);
            }
        }
        if (validData.length > 0) {
            filteredSeries.push({ ...s, data: validData });
        }
    }
    seriesToDraw = filteredSeries;

    if (seriesToDraw.length === 0) {
        stopPerformanceAnimation();
        return;
    }

    // ========== COMMON RENDERING LOGIC ==========

    // Bolt: Use explicit O(N) loop instead of chained .map() and Math.max(...spread) to eliminate GC overhead and avoid call stack limits
    let minTime = Infinity;
    let maxTime = -Infinity;
    let dataMin = Infinity;

    for (let i = 0; i < allPoints.length; i++) {
        const time = parseLocalDate(allPoints[i].date).getTime();
        const value = allPoints[i].value;
        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
        if (value < dataMin) {
            dataMin = value;
        }
    }

    // Ensure minTime aligns with filter start for correct x-axis labels
    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }
    // dataMax not needed since yMax is fixed at 0

    // Y-axis: 0 at top, most negative at bottom
    const yMax = 0; // Hard ceiling at 0
    let yMin = dataMin;

    // Add padding to bottom
    const range = Math.abs(yMax - yMin);
    const paddingVal = Math.max(range * 0.05, 1);
    yMin -= paddingVal;

    const xScale = (t) =>
        padding.left +
        (maxTime === minTime ? plotWidth / 2 : ((t - minTime) / (maxTime - minTime)) * plotWidth);
    const yScale = (v) => padding.top + plotHeight - ((v - yMin) / (yMax - yMin)) * plotHeight;

    // Format Y-axis labels
    const yLabelFormatter = (v) => `${v.toFixed(0)}%`;

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        yLabelFormatter,
        true // isPerformanceChart style for percentage mode
    );

    const performanceAnimationEnabled = isAnimationEnabled('performance');
    const animationPhase = advancePerformanceAnimation(timestamp);

    const rootStyles = window.getComputedStyle(document.documentElement);
    const colors = getChartColors(rootStyles);
    const colorMap = {
        // Benchmark colors for percentage mode
        '^LZ': BENCHMARK_GRADIENTS['^LZ']?.[1] || colors.portfolio,
        '^GSPC': BENCHMARK_GRADIENTS['^GSPC']?.[1] || '#4caf50',
        '^IXIC': BENCHMARK_GRADIENTS['^IXIC']?.[1] || '#ff9800',
        '^DJI': BENCHMARK_GRADIENTS['^DJI']?.[1] || '#2196f3',
        '^SSEC': BENCHMARK_GRADIENTS['^SSEC']?.[1] || '#e91e63',
        '^HSI': BENCHMARK_GRADIENTS['^HSI']?.[1] || '#9c27b0',
        '^N225': BENCHMARK_GRADIENTS['^N225']?.[1] || '#00bcd4',
    };

    const lineThickness = CHART_LINE_WIDTHS.performance ?? 2;
    const renderedSeries = [];
    let glowIndex = 0;

    const chartBounds = {
        top: padding.top,
        bottom: padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    const zeroLineY = yScale(0);

    for (let sIdx = 0; sIdx < seriesToDraw.length; sIdx++) {
        const series = seriesToDraw[sIdx];
        const resolvedColor = colorMap[series.key] || colors.contribution;
        const gradientStops = BENCHMARK_GRADIENTS[series.key];

        if (gradientStops) {
            const gradient = ctx.createLinearGradient(padding.left, 0, padding.left + plotWidth, 0);
            gradient.addColorStop(0, gradientStops[0]);
            gradient.addColorStop(1, gradientStops[1]);
            ctx.strokeStyle = gradient;
        } else {
            ctx.strokeStyle = resolvedColor;
        }

        const coords = new Array(series.data.length);
        for (let i = 0; i < series.data.length; i++) {
            const point = series.data[i];
            const time = parseLocalDate(point.date).getTime();
            coords[i] = {
                x: xScale(time),
                y: yScale(point.value),
                time,
                value: point.value,
            };
        }

        // "Underwater" fill: fill area between line and 0
        if (mountainFill.enabled) {
            drawMountainFill(ctx, coords, zeroLineY, {
                color: resolvedColor,
                colorStops: gradientStops || [resolvedColor, resolvedColor],
                opacityTop: 0.05,
                opacityBottom: 0.35,
                bounds: chartBounds,
            });
        }

        ctx.beginPath();
        for (let idx = 0; idx < coords.length; idx++) {
            const coord = coords[idx];
            if (idx === 0) {
                ctx.moveTo(coord.x, coord.y);
            } else {
                ctx.lineTo(coord.x, coord.y);
            }
        }
        ctx.lineWidth = lineThickness;
        ctx.stroke();

        const renderedPoints = new Array(coords.length);
        for (let j = 0; j < coords.length; j++) {
            renderedPoints[j] = { time: coords[j].time, value: coords[j].value };
        }

        renderedSeries.push({
            key: series.key,
            name: series.name,
            color: resolvedColor,
            points: renderedPoints,
        });

        if (performanceAnimationEnabled) {
            drawSeriesGlow(
                ctx,
                { coords, color: resolvedColor, lineWidth: lineThickness },
                {
                    basePhase: animationPhase,
                    seriesIndex: glowIndex,
                    isMobile,
                    chartKey: 'performance',
                }
            );
            glowIndex++;
        }
    }

    if (renderedSeries.length === 0) {
        stopPerformanceAnimation();
        return;
    }

    if (performanceAnimationEnabled && glowIndex > 0) {
        schedulePerformanceAnimation(chartManager);
    } else if (!performanceAnimationEnabled) {
        stopPerformanceAnimation();
    }

    const showChartLabels = getShowChartLabels();
    const labelBounds = [];
    if (showChartLabels) {
        for (let i = 0; i < seriesToDraw.length; i++) {
            const series = seriesToDraw[i];
            const lastData = series.data[series.data.length - 1];
            if (!lastData) {
                continue;
            }
            const x = xScale(parseLocalDate(lastData.date).getTime());
            const y = yScale(lastData.value);
            const resolvedColor = colorMap[series.key] || colors.contribution;

            const formatter = (v) => `${v.toFixed(2)}%`;

            const bounds = drawEndValue(
                ctx,
                x,
                y,
                lastData.value,
                resolvedColor,
                isMobile,
                padding,
                plotWidth,
                plotHeight,
                formatter,
                true,
                labelBounds
            );
            if (bounds) {
                labelBounds.push(bounds);
            }
        }
    }

    // Store layout for crosshair
    const layoutKey = 'drawdown';
    const valueFormatter = (value) => `${value.toFixed(2)}%`;

    chartLayouts[layoutKey] = {
        key: layoutKey,
        minTime,
        maxTime,
        valueType: 'percent',
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            if (!Number.isFinite(pixelX)) {
                return minTime;
            }
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: (() => {
            const layoutSeries = new Array(renderedSeries.length);
            for (let i = 0; i < renderedSeries.length; i++) {
                const s = renderedSeries[i];
                layoutSeries[i] = {
                    key: s.key,
                    name: s.name,
                    color: s.color,
                    getValueAtTime: createTimeInterpolator(s.points || []),
                    formatValue: valueFormatter,
                    formatDelta: (d) => `${d > 0 ? '+' : ''}${d.toFixed(2)}%`,
                };
            }
            return layoutSeries;
        })(),
    };

    drawCrosshairOverlay(ctx, chartLayouts[layoutKey]);

    const legendEntries = new Array(orderedKeys.length);
    for (let i = 0; i < orderedKeys.length; i++) {
        const key = orderedKeys[i];
        legendEntries[i] = {
            key,
            name: key,
            color: colorMap[key] || colors.contribution,
        };
    }
    updateLegend(legendEntries, chartManager);
}

import { transactionState, getShowChartLabels } from '../../state.js';
import {
    stopPerformanceAnimation,
    stopContributionAnimation,
    stopFxAnimation,
    scheduleFxAnimation,
    advanceFxAnimation,
    isAnimationEnabled,
    drawSeriesGlow,
} from '../animation.js';
import { updateCrosshairUI, drawCrosshairOverlay, updateLegend } from '../interaction.js';
import { FX_CURRENCY_ORDER, FX_LINE_COLORS, FX_GRADIENTS } from '../config.js';
import { CHART_LINE_WIDTHS, mountainFill } from '../../../config.js';
import { convertBetweenCurrencies } from '../../utils.js';
import { drawAxes, drawMountainFill, drawEndValue, computePercentTickInfo } from '../core.js';
import {
    getSmoothingConfig,
    createTimeInterpolator,
    formatPercentInline,
    formatFxValue,
    clampTime,
    lightenColor,
    darkenColor,
    parseLocalDate,
} from '../helpers.js';
import { smoothFinancialData } from '../../../utils/smoothing.js';
import { chartLayouts } from '../state.js';

export function buildFxChartSeries(baseCurrency) {
    const fxRates = transactionState.fxRatesByCurrency || {};
    const normalizedBase = typeof baseCurrency === 'string' ? baseCurrency.toUpperCase() : 'USD';
    const baseEntry = fxRates[normalizedBase];
    const seriesList = [];

    FX_CURRENCY_ORDER.filter((currency) => currency !== normalizedBase).forEach((currency) => {
        const targetEntry = fxRates[currency];
        if (!targetEntry && currency !== 'USD') {
            return;
        }
        const dateSource =
            (currency === 'USD'
                ? baseEntry?.sorted
                : targetEntry?.sorted || baseEntry?.sorted || []) || [];
        if (dateSource.length === 0) {
            return;
        }
        const points = [];
        for (let i = 0; i < dateSource.length; i++) {
            const { date } = dateSource[i];
            const value = convertBetweenCurrencies(1, normalizedBase, date, currency);
            if (Number.isFinite(value)) {
                const parsedDate = parseLocalDate(date);
                if (parsedDate && !Number.isNaN(parsedDate.getTime())) {
                    points.push({ date: parsedDate, value });
                }
            }
        }
        if (!points.length) {
            return;
        }
        const key = `FX_${normalizedBase}_${currency}`;
        if (transactionState.chartVisibility[key] === undefined) {
            transactionState.chartVisibility[key] = true;
        }
        const color = FX_LINE_COLORS[currency] || '#FF8E53';
        seriesList.push({
            key,
            base: normalizedBase,
            quote: currency,
            label: `${currency}`,
            color,
            data: points,
        });
    });

    return seriesList;
}

export function drawFxChart(ctx, chartManager, timestamp) {
    stopPerformanceAnimation();
    stopContributionAnimation();
    const fxAnimationEnabled = isAnimationEnabled('fx');
    const animationPhase = fxAnimationEnabled ? advanceFxAnimation(timestamp) : 0;
    let glowIndex = 0;
    const canvas = ctx.canvas;
    const emptyState = document.getElementById('runningAmountEmpty');
    const baseCurrency = (transactionState.selectedCurrency || 'USD').toUpperCase();
    const seriesData = buildFxChartSeries(baseCurrency);

    if (!seriesData.length) {
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        chartLayouts.fx = null;
        updateCrosshairUI(null, null);
        stopFxAnimation();
        return;
    }
    if (emptyState) {
        emptyState.style.display = 'none';
    }

    const { chartDateRange } = transactionState;
    let filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    if (!filterFrom) {
        // If no explicit filter (like 'all'), clamp to the exact first date of the portfolio.
        // This ensures the 0% baseline and the x-axis start match the other portfolio charts.
        let earliestTime = null;
        if (transactionState.portfolioSeries && transactionState.portfolioSeries.length > 0) {
            const firstDate =
                transactionState.portfolioSeries[0].date ||
                transactionState.portfolioSeries[0].tradeDate;
            const parsed = parseLocalDate(firstDate);
            if (parsed && !Number.isNaN(parsed.getTime())) {
                earliestTime = parsed.getTime();
            }
        }
        if (earliestTime !== null) {
            filterFrom = new Date(earliestTime);
        } else {
            // Safe fallback if portfolio data is inexplicably absent
            filterFrom = new Date(Date.UTC(new Date().getFullYear(), 0, 1));
        }
    }

    const filteredSeries = [];
    for (let i = 0; i < seriesData.length; i++) {
        const series = seriesData[i];
        const filtered = [];
        for (let j = 0; j < series.data.length; j++) {
            const point = series.data[j];
            const date = point.date;
            if ((!filterFrom || date >= filterFrom) && (!filterTo || date <= filterTo)) {
                filtered.push(point);
            }
        }

        if (filtered.length > 0) {
            // Normalize to percent change since first point
            const baseValue = filtered[0].value;
            const safeBase = Number.isFinite(baseValue) && baseValue !== 0 ? baseValue : 1;
            const percentData = new Array(filtered.length);
            for (let j = 0; j < filtered.length; j++) {
                const point = filtered[j];
                percentData[j] = {
                    ...point,
                    percent: ((point.value - safeBase) / safeBase) * 100,
                    rawValue: point.value,
                };
            }
            filteredSeries.push({ ...series, data: percentData });
        }
    }

    if (!filteredSeries.length) {
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        stopFxAnimation();
        chartLayouts.fx = null;
        updateCrosshairUI(null, null);
        return;
    }

    const isMobile = window.innerWidth <= 768;
    const padding = isMobile
        ? { top: 15, right: 20, bottom: 35, left: 60 }
        : { top: 20, right: 30, bottom: 48, left: 80 };
    const plotWidth = canvas.offsetWidth - padding.left - padding.right;
    const plotHeight = canvas.offsetHeight - padding.top - padding.bottom;
    const chartBounds = {
        top: padding.top,
        bottom: padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    let minTime = Infinity;
    let maxTime = -Infinity;
    let dataMin = Infinity;
    let dataMax = -Infinity;

    for (let i = 0; i < filteredSeries.length; i++) {
        const series = filteredSeries[i];
        for (let j = 0; j < series.data.length; j++) {
            const point = series.data[j];
            const time = point.date.getTime();
            if (Number.isFinite(time)) {
                minTime = Math.min(minTime, time);
                maxTime = Math.max(maxTime, time);
            }
            if (Number.isFinite(point.percent)) {
                dataMin = Math.min(dataMin, point.percent);
                dataMax = Math.max(dataMax, point.percent);
            }
        }
    }

    if (!Number.isFinite(minTime) || !Number.isFinite(maxTime) || minTime === maxTime) {
        chartLayouts.fx = null;
        updateCrosshairUI(null, null);
        stopFxAnimation();
        return;
    }

    // Ensure minTime aligns with filter start for correct x-axis labels
    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }

    if (!Number.isFinite(dataMin) || !Number.isFinite(dataMax)) {
        chartLayouts.fx = null;
        updateCrosshairUI(null, null);
        stopFxAnimation();
        return;
    }

    const paddingValue = Math.max((dataMax - dataMin) * 0.05, 0.05);
    let yMin = dataMin - paddingValue;
    let yMax = dataMax + paddingValue;

    const percentTickInfo = computePercentTickInfo(yMin, yMax);
    const displayRange = yMax - yMin;
    if (
        Number.isFinite(displayRange) &&
        displayRange > 0 &&
        percentTickInfo.tickSpacing > 0 &&
        displayRange >= percentTickInfo.tickSpacing * 0.4
    ) {
        yMin = percentTickInfo.startTick;
        yMax = percentTickInfo.endTick;
    }

    const xScale = (t) =>
        padding.left +
        (maxTime === minTime ? plotWidth / 2 : ((t - minTime) / (maxTime - minTime)) * plotWidth);
    const yScale = (v) =>
        padding.top +
        plotHeight -
        (yMax === yMin ? plotHeight / 2 : ((v - yMin) / (yMax - yMin)) * plotHeight);

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        (v) => `${v.toFixed(0)}%`,
        false,
        { drawXAxis: true, drawYAxis: true },
        transactionState.selectedCurrency || 'USD',
        true
    );

    const showChartLabels = getShowChartLabels();
    const renderedSeries = [];
    const labelBounds = [];
    for (let i = 0; i < filteredSeries.length; i++) {
        const series = filteredSeries[i];
        const visibility = transactionState.chartVisibility[series.key];
        if (visibility === false) {
            continue;
        }

        const smoothingConfig = getSmoothingConfig('performance');

        // Bolt: Eliminate chained Array map allocations in render loops
        // Impact: Eliminates O(N) intermediate array allocations per animation frame, reducing GC pauses.
        const nData = series.data.length;
        const rawPoints = new Array(nData);
        for (let i = 0; i < nData; i++) {
            const point = series.data[i];
            rawPoints[i] = {
                x: point.date.getTime(),
                y: point.percent,
                raw: point.rawValue,
            };
        }

        const smoothed = smoothingConfig
            ? smoothFinancialData(rawPoints, smoothingConfig, true)
            : rawPoints;

        const nSmoothed = smoothed.length;
        if (nSmoothed === 0) {
            return;
        }

        const coords = new Array(nSmoothed);
        const seriesPoints = new Array(nSmoothed);
        const rawSeriesPoints = new Array(nSmoothed);
        for (let i = 0; i < nSmoothed; i++) {
            const point = smoothed[i];
            const source = rawPoints[i] || rawPoints[rawPoints.length - 1];

            const rawVal = source?.raw ?? source?.y ?? point.y;

            coords[i] = {
                x: xScale(point.x),
                y: yScale(point.y),
                time: point.x,
                value: point.y,
                rawValue: rawVal,
            };

            seriesPoints[i] = { time: point.x, value: point.y };
            rawSeriesPoints[i] = { time: point.x, value: rawVal };
        }

        const baseColor = series.color;
        const gradientStops = FX_GRADIENTS[series.quote] || FX_GRADIENTS[series.label] || null;
        const darkColor = gradientStops ? gradientStops[0] : darkenColor(baseColor, 0.15);
        const lightColor = gradientStops ? gradientStops[1] : lightenColor(baseColor, 0.2);
        const resolvedColor = lightColor;
        const strokeGradient = ctx.createLinearGradient(
            padding.left,
            0,
            padding.left + plotWidth,
            0
        );
        strokeGradient.addColorStop(0, darkColor);
        strokeGradient.addColorStop(1, lightColor);

        if (mountainFill.enabled) {
            drawMountainFill(ctx, coords, yScale(0), {
                color: baseColor,
                colorStops: [darkColor, lightColor],
                opacityTop: 0.3,
                opacityBottom: 0,
                bounds: chartBounds,
            });
        }

        ctx.beginPath();
        for (let j = 0; j < coords.length; j++) {
            const coord = coords[j];
            if (j === 0) {
                ctx.moveTo(coord.x, coord.y);
            } else {
                ctx.lineTo(coord.x, coord.y);
            }
        }
        ctx.lineWidth = CHART_LINE_WIDTHS.fx ?? 2;
        ctx.strokeStyle = strokeGradient;
        ctx.stroke();

        if (showChartLabels) {
            const lastCoord = coords[coords.length - 1];
            const bounds = drawEndValue(
                ctx,
                lastCoord.x,
                lastCoord.y,
                lastCoord.value,
                resolvedColor,
                isMobile,
                padding,
                plotWidth,
                plotHeight,
                formatPercentInline,
                true,
                labelBounds
            );
            if (bounds) {
                labelBounds.push(bounds);
            }
        }

        renderedSeries.push({
            key: series.key,
            label: series.label,
            color: resolvedColor,
            points: seriesPoints,
            rawPoints: rawSeriesPoints,
        });

        if (fxAnimationEnabled) {
            drawSeriesGlow(
                ctx,
                { coords, color: lightColor, lineWidth: 2 },
                {
                    basePhase: animationPhase,
                    seriesIndex: glowIndex,
                    isMobile,
                    chartKey: 'fx',
                }
            );
            glowIndex += 1;
        }
    }

    if (!renderedSeries.length) {
        stopFxAnimation();
        chartLayouts.fx = null;
        updateCrosshairUI(null, null);
        return;
    }

    chartLayouts.fx = {
        key: 'fx',
        minTime,
        maxTime,
        valueType: 'percent',
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            if (!Number.isFinite(pixelX)) {
                return minTime;
            }
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: (function () {
            const result = new Array(renderedSeries.length);
            for (let i = 0; i < renderedSeries.length; i++) {
                const series = renderedSeries[i];
                const rawInterpolator = createTimeInterpolator(series.rawPoints || []);
                result[i] = {
                    key: series.key,
                    label: series.label,
                    color: series.color,
                    getValueAtTime: createTimeInterpolator(series.points || []),
                    getRawValueAtTime: rawInterpolator,
                    formatValue: (value, time) => {
                        const raw = rawInterpolator(time);
                        const percentText = formatPercentInline(value);
                        if (!Number.isFinite(raw)) {
                            return percentText;
                        }
                        return `${formatFxValue(raw)} (${percentText})`;
                    },
                    formatDelta: (delta, percentChange, startTime, endTime) => {
                        const startRaw = rawInterpolator(startTime);
                        const endRaw = rawInterpolator(endTime);
                        const rawDelta =
                            Number.isFinite(startRaw) && Number.isFinite(endRaw)
                                ? endRaw - startRaw
                                : null;
                        const percentText = Number.isFinite(percentChange)
                            ? formatPercentInline(percentChange)
                            : formatPercentInline(delta);
                        if (Number.isFinite(rawDelta) && Math.abs(rawDelta) > 1e-6) {
                            const rawText = `${rawDelta >= 0 ? '+' : '−'}${formatFxValue(
                                Math.abs(rawDelta)
                            )}`;
                            return `${rawText} (${percentText})`;
                        }
                        return percentText;
                    },
                };
            }
            return result;
        })(),
    };

    if (fxAnimationEnabled && glowIndex > 0) {
        scheduleFxAnimation(chartManager);
    } else {
        stopFxAnimation();
    }

    drawCrosshairOverlay(ctx, chartLayouts.fx);

    const legendEntries = new Array(renderedSeries.length);
    for (let i = 0; i < renderedSeries.length; i++) {
        const series = renderedSeries[i];
        legendEntries[i] = {
            key: series.key,
            name: series.label,
            color: series.color,
        };
    }
    updateLegend(legendEntries, chartManager);
}

import { logger } from '../../../utils/logger.js';
import { transactionState } from '../../state.js';
import { chartLayouts } from '../state.js';
import { loadGeographySnapshotData } from '../../dataLoader.js';
import {
    stopPerformanceAnimation,
    stopContributionAnimation,
    stopFxAnimation,
} from '../animation.js';
import { updateCrosshairUI, updateLegend, drawCrosshairOverlay } from '../interaction.js';
import { drawAxes } from '../core.js';
import {
    createTimeInterpolator,
    clampTime,
    formatPercentInline,
    parseLocalDate,
} from '../helpers.js';
import {
    formatCurrencyInlineValue,
    formatCurrencyCompact,
    convertValueToCurrency,
} from '../../utils.js';
import { COLOR_PALETTES } from '../../../config.js';

let geographyDataCache = null;
let geographyDataLoading = false;

function renderGeographyChartWithMode(ctx, chartManager, data, options = {}) {
    const valueMode = options.valueMode === 'absolute' ? 'absolute' : 'percent';

    if (
        !data ||
        typeof data !== 'object' ||
        !Array.isArray(data.dates) ||
        data.dates.length === 0
    ) {
        chartLayouts.geography = null;
        chartLayouts.geographyAbs = null;
        updateCrosshairUI(null, null);
        const emptyState = document.getElementById('runningAmountEmpty');
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    const emptyState = document.getElementById('runningAmountEmpty');
    if (emptyState) {
        emptyState.style.display = 'none';
    }

    const rawDates = data.dates.slice();
    const rawSeries = data.series || {};
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    // Bolt: Replaced O(N) Array .map().filter().map() with a single inline loop
    const filteredIndices = [];
    for (let i = 0; i < rawDates.length; i += 1) {
        const date = parseLocalDate(rawDates[i]);
        if (!date || Number.isNaN(date.getTime())) {
            continue;
        }
        if (filterFrom && date < filterFrom) {
            continue;
        }
        if (filterTo && date > filterTo) {
            continue;
        }
        filteredIndices.push(i);
    }

    const dates =
        filterFrom || filterTo ? filteredIndices.map((i) => rawDates[i]) : rawDates.slice();

    if (dates.length === 0) {
        if (valueMode === 'absolute') {
            chartLayouts.geographyAbs = null;
        } else {
            chartLayouts.geography = null;
        }
        updateCrosshairUI(null, null);
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    const rawTotalValues = Array.isArray(data.total_values) ? data.total_values : [];
    const mappedTotalValues =
        filterFrom || filterTo
            ? filteredIndices.map((index) => Number(rawTotalValues[index] ?? 0))
            : rawTotalValues.map((value) => Number(value ?? 0));

    const totalValuesUsd = mappedTotalValues;
    const totalValuesConverted = totalValuesUsd.map((value, idx) => {
        const converted = convertValueToCurrency(value, dates[idx], selectedCurrency);
        return Number.isFinite(converted) ? converted : 0;
    });

    const percentSeriesMap = {};
    const chartData = {};
    Object.entries(rawSeries).forEach(([country, values]) => {
        const mappedValues =
            filterFrom || filterTo
                ? filteredIndices.map((index) => values[index] ?? 0)
                : values.map((value) => value ?? 0);

        percentSeriesMap[country] = mappedValues;
        if (valueMode === 'absolute') {
            // Bolt: Optimize absolute value mapping by pre-allocating an array and using a for loop
            const absoluteValues = new Array(mappedValues.length);
            for (let i = 0; i < mappedValues.length; i += 1) {
                absoluteValues[i] = ((totalValuesConverted[i] ?? 0) * mappedValues[i]) / 100;
            }
            chartData[country] = absoluteValues;
        } else {
            chartData[country] = mappedValues;
        }
    });

    const baseCountryOrder = Object.keys(chartData).sort((a, b) => {
        const arrA = chartData[a] || [];
        const arrB = chartData[b] || [];
        const lastA = arrA[arrA.length - 1] ?? 0;
        const lastB = arrB[arrB.length - 1] ?? 0;
        return lastB - lastA;
    });

    const canvas = ctx.canvas;
    const canvasWidth = canvas.offsetWidth;
    const canvasHeight = canvas.offsetHeight;
    const isMobile = window.innerWidth <= 768;
    const padding = isMobile
        ? { top: 15, right: 18, bottom: 36, left: 48 }
        : { top: 22, right: 26, bottom: 48, left: 68 };
    const plotWidth = canvasWidth - padding.left - padding.right;
    const plotHeight = canvasHeight - padding.top - padding.bottom;

    if (plotWidth <= 0 || plotHeight <= 0) {
        return;
    }

    const colors = COLOR_PALETTES.COMPOSITION_CHART_COLORS;
    const resolveCountryColor = (country) => {
        const index = baseCountryOrder.indexOf(country);
        return colors[index % colors.length];
    };

    const dateTimes = new Array(dates.length);
    let minTime = Infinity;
    let maxTime = -Infinity;
    for (let i = 0; i < dates.length; i++) {
        const time = parseLocalDate(dates[i]).getTime();
        dateTimes[i] = time;
        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
    }

    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }

    const xScale = (time) =>
        padding.left +
        (maxTime === minTime
            ? plotWidth / 2
            : ((time - minTime) / (maxTime - minTime)) * plotWidth);

    const yMin = 0;
    let maxTotalValue = 0;
    for (let i = 0; i < totalValuesConverted.length; i++) {
        if (totalValuesConverted[i] > maxTotalValue) {
            maxTotalValue = totalValuesConverted[i];
        }
    }
    const yMax = valueMode === 'absolute' ? Math.max(maxTotalValue, 1) : 100;
    const yScale = (value) =>
        padding.top + plotHeight - ((value - yMin) / (yMax - yMin || 1)) * plotHeight;

    const axisFormatter =
        valueMode === 'absolute'
            ? (val) => formatCurrencyCompact(val, { currency: selectedCurrency })
            : (val) => `${val}%`;

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        axisFormatter,
        valueMode !== 'absolute'
    );

    const cumulativeValues = new Array(dates.length).fill(0);
    // Bolt: Use standard for loop instead of .forEach to avoid closure allocation inside rendering loop
    for (let cIdx = 0; cIdx < baseCountryOrder.length; cIdx += 1) {
        const country = baseCountryOrder[cIdx];
        const values = chartData[country] || [];
        const color = resolveCountryColor(country);
        ctx.beginPath();
        ctx.fillStyle = `${color}80`;
        ctx.strokeStyle = 'rgba(128, 128, 128, 0.5)';
        ctx.lineWidth = 1;

        // Bolt: Use standard for loop instead of .forEach to avoid closure allocation
        for (let index = 0; index < dates.length; index += 1) {
            const dateStr = dates[index];
            const x = xScale(parseLocalDate(dateStr).getTime());
            const y = yScale(cumulativeValues[index] + values[index]);
            if (index === 0) {
                ctx.moveTo(x, y);
            } else {
                ctx.lineTo(x, y);
            }
        }

        for (let i = dates.length - 1; i >= 0; i -= 1) {
            const x = xScale(parseLocalDate(dates[i]).getTime());
            const y = yScale(cumulativeValues[i]);
            ctx.lineTo(x, y);
        }
        ctx.closePath();
        ctx.fill();
        ctx.stroke();

        // Bolt: Optimize array allocation by mutating cumulativeValues in place instead of map
        for (let i = 0; i < cumulativeValues.length; i += 1) {
            cumulativeValues[i] += values[i];
        }
    }

    const latestIndex = dates.length - 1;

    // Build legend series - show top countries by percentage
    const legendSeries = baseCountryOrder
        .map((country) => ({
            country,
            percent: percentSeriesMap[country][latestIndex] ?? 0,
        }))
        .filter((c) => c.percent > 0.1)
        .sort((a, b) => b.percent - a.percent)
        .slice(0, 4)
        .map((c) => ({
            key: c.country,
            name: c.country,
            color: resolveCountryColor(c.country),
        }));

    // Build series for crosshair with proper formatting
    const seriesForCrosshair = baseCountryOrder.map((country) => {
        const values = chartData[country];
        const points = dateTimes.map((time, idx) => ({
            time,
            value: values[idx],
        }));
        return {
            key: country,
            label: country,
            color: resolveCountryColor(country),
            getValueAtTime: createTimeInterpolator(points),
            formatValue: (value) =>
                valueMode === 'absolute'
                    ? formatCurrencyInlineValue(value, selectedCurrency)
                    : `${value.toFixed(2)}%`,
            formatDelta: (delta) =>
                valueMode === 'absolute'
                    ? formatCurrencyInlineValue(delta, selectedCurrency)
                    : formatPercentInline(delta),
            originalIndex: baseCountryOrder.indexOf(country),
        };
    });

    // Sort series by original index for consistent ordering
    const sortedSeriesForCrosshair = seriesForCrosshair.sort((a, b) => {
        const indexA = baseCountryOrder.indexOf(a.key);
        const indexB = baseCountryOrder.indexOf(b.key);
        return indexA - indexB;
    });

    const totalValuePoints = dateTimes.map((time, idx) => ({
        time,
        value: Number(totalValuesConverted[idx] ?? 0),
    }));

    const layoutKey = valueMode === 'absolute' ? 'geographyAbs' : 'geography';

    // Clear the other mode's layout
    if (valueMode === 'absolute') {
        chartLayouts.geography = null;
    } else {
        chartLayouts.geographyAbs = null;
    }

    chartLayouts[layoutKey] = {
        key: layoutKey,
        minTime,
        maxTime,
        valueType: valueMode === 'absolute' ? 'currency' : 'percent',
        valueMode,
        currency: selectedCurrency,
        stackMaxValue: yMax,
        padding,
        chartBounds: {
            top: padding.top,
            bottom: padding.top + plotHeight,
            left: padding.left,
            right: padding.left + plotWidth,
        },
        xScale,
        yScale,
        invertX: (pixelX) => {
            if (!Number.isFinite(pixelX)) {
                return minTime;
            }
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: sortedSeriesForCrosshair,
        percentSeriesMap,
        dates,
        getTotalValueAtTime: createTimeInterpolator(totalValuePoints),
    };

    drawCrosshairOverlay(ctx, chartLayouts[layoutKey]);
    updateLegend(legendSeries, chartManager);
}

