    stopContributionAnimation,
    stopFxAnimation,
    stopPeAnimation,
    stopConcentrationAnimation,
    isAnimationEnabled,
    advancePeAnimation,
    schedulePeAnimation,
    drawSeriesGlow,
} from '../animation.js';
