export async function drawRollingChart(ctx, chartManager, timestamp) {
    const performanceSeries =
        transactionState.performanceSeries && typeof transactionState.performanceSeries === 'object'
            ? transactionState.performanceSeries
            : {};
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const { chartVisibility } = transactionState;
    stopContributionAnimation();
    stopFxAnimation();
    if (Object.keys(performanceSeries).length === 0) {
        stopPerformanceAnimation();
        chartLayouts.rolling = null;
        updateCrosshairUI(null, null);
        return;
    }

    const orderedKeys = Object.keys(performanceSeries).sort((a, b) => {
        if (a === '^LZ') {
            return -1;
        }
        if (b === '^LZ') {
            return 1;
        }
        return a.localeCompare(b);
    });

    for (let i = 0; i < orderedKeys.length; i++) {
        const key = orderedKeys[i];
        if (transactionState.chartVisibility[key] === undefined) {
            transactionState.chartVisibility[key] = key === '^LZ' || key === '^GSPC';
        }
    }

    // Transform cumulative TWRR into rolling 1Y returns
    const allPossibleSeries = new Array(orderedKeys.length);
    for (let sIdx = 0; sIdx < orderedKeys.length; sIdx++) {
        const key = orderedKeys[sIdx];
        const rawPoints = Array.isArray(performanceSeries[key]) ? performanceSeries[key] : [];
        const sourceCurrency = PERFORMANCE_SERIES_CURRENCY[key] || 'USD';

        // Pre-parse dates to avoid repeated Date object creation
        // Bolt: Replaced chained .map().filter() with a single inline loop
        const points = [];
        for (let i = 0; i < rawPoints.length; i++) {
            const p = rawPoints[i];
            const parsedDate = parseLocalDate(p.date);
            if (parsedDate !== null) {
                points.push({
                    ...p,
                    parsedDate,
                });
            }
        }

        const rollingData = [];

        // Use a sliding window approach to find the start point (closest to 1 year ago)
        let j = 0;

        for (let i = 0; i < points.length; i++) {
            const currentPoint = points[i];
            const currentDate = currentPoint.parsedDate;
            const oneYearAgo = new Date(currentDate);
            oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);

            // Advance the start pointer 'j' to find the closest point <= oneYearAgo
            // Since points are chronological, 'j' will never need to go backwards
            while (j < i && points[j + 1].parsedDate <= oneYearAgo) {
                j++;
            }

            const startPoint = points[j] && points[j].parsedDate <= oneYearAgo ? points[j] : null;

            if (startPoint && startPoint.value !== 0) {
                const startVal = convertBetweenCurrencies(
                    Number(startPoint.value),
                    sourceCurrency,
                    startPoint.date,
                    selectedCurrency
                );
                const endVal = convertBetweenCurrencies(
                    Number(currentPoint.value),
                    sourceCurrency,
                    currentPoint.date,
                    selectedCurrency
                );
                const rollingReturn = (endVal / startVal - 1) * 100;
                rollingData.push({
                    date: currentPoint.date,
                    value: rollingReturn,
                });
            }
        }

        allPossibleSeries[sIdx] = {
            key,
            name: key,
            data: rollingData,
        };
    }

    const visibility = chartVisibility || {};
    const seriesToDraw = allPossibleSeries.filter((s) => visibility[s.key] !== false);

    if (seriesToDraw.length === 0) {
        stopPerformanceAnimation();
        chartLayouts.rolling = null;
        updateCrosshairUI(null, null);
        return;
    }

    const canvas = ctx.canvas;
    const isMobile = typeof window !== 'undefined' ? window.innerWidth <= 768 : false;
    const padding = isMobile
        ? { top: 15, right: 20, bottom: 35, left: 50 }
        : { top: 20, right: 30, bottom: 48, left: 70 };
    const plotWidth = canvas.offsetWidth - padding.left - padding.right;
    const plotHeight = canvas.offsetHeight - padding.top - padding.bottom;

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    const filteredSeries = [];
    const allPoints = [];
    for (let i = 0; i < seriesToDraw.length; i++) {
        const s = seriesToDraw[i];
        const validData = [];
        for (let j = 0; j < s.data.length; j++) {
            const d = s.data[j];
            const dt = parseLocalDate(d.date);
            if ((!filterFrom || dt >= filterFrom) && (!filterTo || dt <= filterTo)) {
                validData.push(d);
                allPoints.push(d);
            }
        }
        filteredSeries.push({ ...s, data: validData });
    }
    if (allPoints.length === 0) {
        stopPerformanceAnimation();
        return;
    }

    // Bolt: Replaced O(N) Array.map() + spread operator with a single inline loop for min/max
    let minTime = Infinity;
    let maxTime = -Infinity;
    let dataMin = Infinity;
    let dataMax = -Infinity;

    for (let i = 0; i < allPoints.length; i++) {
        const point = allPoints[i];
        const time = parseLocalDate(point.date).getTime();
        const value = point.value;

        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
        if (value < dataMin) {
            dataMin = value;
        }
        if (value > dataMax) {
            dataMax = value;
        }
    }

    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }

    const valueRange = dataMax - dataMin;
    const yPadding = Math.max(valueRange * 0.1, 5);
    const yMin = dataMin - yPadding;
    const yMax = dataMax + yPadding;

    const xScale = (t) =>
        padding.left +
        (maxTime === minTime ? plotWidth / 2 : ((t - minTime) / (maxTime - minTime)) * plotWidth);
    const yScale = (v) =>
        padding.top +
        plotHeight -
        (yMax === yMin ? plotHeight / 2 : ((v - yMin) / (yMax - yMin)) * plotHeight);

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        (v) => `${v.toFixed(0)}%`,
        true
    );

    const animationPhase = advancePerformanceAnimation(timestamp);
    const rootStyles =
        typeof window !== 'undefined' ? window.getComputedStyle(document.documentElement) : null;
    const colors = getChartColors(rootStyles);
    const colorMap = {
        '^LZ': BENCHMARK_GRADIENTS['^LZ'][1],
        '^GSPC': BENCHMARK_GRADIENTS['^GSPC'][1],
        '^IXIC': BENCHMARK_GRADIENTS['^IXIC'][1],
        '^DJI': BENCHMARK_GRADIENTS['^DJI'][1],
        '^SSEC': BENCHMARK_GRADIENTS['^SSEC'][1],
        '^HSI': BENCHMARK_GRADIENTS['^HSI'][1],
        '^N225': BENCHMARK_GRADIENTS['^N225'][1],
    };

    const lineThickness = CHART_LINE_WIDTHS.performance ?? 2;
    const renderedSeries = [];
    let glowIndex = 0;

    const chartBounds = {
        top: padding.top,
        bottom: padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    const baselineY = yScale(0);
    const seriesForDrawing = filteredSeries.slice().sort((a, b) => {
        const aIsPortfolio = a.key === '^LZ';
        const bIsPortfolio = b.key === '^LZ';
        if (aIsPortfolio && !bIsPortfolio) {
            return 1;
        }
        if (!aIsPortfolio && bIsPortfolio) {
            return -1;
        }
        return 0;
    });

    for (let sIdx = 0; sIdx < seriesForDrawing.length; sIdx++) {
        const series = seriesForDrawing[sIdx];
        if (series.data.length === 0) {
            continue;
        }

        const rawPoints = series.data;
        const smoothingConfig = getSmoothingConfig('performance');

        // Bolt: Optimize array allocation
        const mapRawPoints = new Array(rawPoints.length);
        for (let i = 0; i < rawPoints.length; i++) {
            const p = rawPoints[i];
            mapRawPoints[i] = { x: parseLocalDate(p.date).getTime(), y: p.value };
        }

        let points;
        if (smoothingConfig) {
            const smoothed = smoothFinancialData(mapRawPoints, smoothingConfig, true);
            points = new Array(smoothed.length);
            for (let i = 0; i < smoothed.length; i++) {
                points[i] = { date: parseLocalDate(smoothed[i].x), value: smoothed[i].y };
            }
        } else {
            points = new Array(rawPoints.length);
            for (let i = 0; i < rawPoints.length; i++) {
                const p = rawPoints[i];
                points[i] = { date: parseLocalDate(p.date), value: p.value };
            }
        }

        const gradientStops = BENCHMARK_GRADIENTS[series.key];
        const resolvedColor = gradientStops
            ? gradientStops[1]
            : colorMap[series.key] || colors.contribution;

        const coords = new Array(points.length);
        for (let i = 0; i < points.length; i++) {
            const p = points[i];
            coords[i] = {
                x: xScale(p.date.getTime()),
                y: yScale(p.value),
                time: p.date.getTime(),
                value: p.value,
            };
        }

        if (mountainFill.enabled) {
            drawMountainFill(ctx, coords, baselineY, {
                color: resolvedColor,
                colorStops: gradientStops || [resolvedColor, resolvedColor],
                opacityTop: 0.35,
                opacityBottom: 0,
                bounds: chartBounds,
            });
        }

        ctx.beginPath();
        for (let idx = 0; idx < coords.length; idx++) {
            const c = coords[idx];
            if (idx === 0) {
                ctx.moveTo(c.x, c.y);
            } else {
                ctx.lineTo(c.x, c.y);
            }
        }
        ctx.strokeStyle = resolvedColor;
        if (gradientStops) {
            const grad = ctx.createLinearGradient(padding.left, 0, padding.left + plotWidth, 0);
            grad.addColorStop(0, gradientStops[0]);
            grad.addColorStop(1, gradientStops[1]);
            ctx.strokeStyle = grad;
        }
        ctx.lineWidth = lineThickness;
        ctx.stroke();

        const renderedPoints = new Array(coords.length);
        for (let j = 0; j < coords.length; j++) {
            renderedPoints[j] = { time: coords[j].time, value: coords[j].value };
        }

        renderedSeries.push({
            key: series.key,
            name: series.name,
            color: resolvedColor,
            x: coords[coords.length - 1].x,
            y: coords[coords.length - 1].y,
            value: points[points.length - 1].value,
            coords,
            points: renderedPoints,
        });

        if (isAnimationEnabled('performance')) {
            drawSeriesGlow(
                ctx,
                { coords, color: resolvedColor, lineWidth: lineThickness },
                {
                    basePhase: animationPhase,
                    seriesIndex: glowIndex,
                    isMobile,
                    chartKey: 'performance',
                }
            );
            glowIndex += 1;
        }
    }

    if (isAnimationEnabled('performance') && glowIndex > 0) {
        schedulePerformanceAnimation(chartManager);
    } else {
        stopPerformanceAnimation();
    }

    const showChartLabels = getShowChartLabels();
    const labelBounds = [];
    if (showChartLabels) {
        for (let i = 0; i < renderedSeries.length; i++) {
            const s = renderedSeries[i];
            const bounds = drawEndValue(
                ctx,
                s.x,
                s.y,
                s.value,
                s.color,
                isMobile,
                padding,
                plotWidth,
                plotHeight,
                (v) => `${v.toFixed(1)}%`,
                true,
                labelBounds
            );
            if (bounds) {
                labelBounds.push(bounds);
            }
        }
    }

    chartLayouts.rolling = {
        key: 'rolling',
        minTime,
        maxTime,
        valueType: 'percent',
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: (() => {
            const layoutSeries = new Array(renderedSeries.length);
            for (let i = 0; i < renderedSeries.length; i++) {
                const s = renderedSeries[i];
                layoutSeries[i] = {
                    key: s.key,
                    label: s.name,
                    color: s.color,
                    getValueAtTime: createTimeInterpolator(s.points),
                    formatValue: (v) => `${v >= 0 ? '+' : ''}${v.toFixed(2)}%`,
                    formatDelta: (delta, percent) => formatPercentInline(percent ?? delta),
                };
            }
            return layoutSeries;
        })(),
    };

    drawCrosshairOverlay(ctx, chartLayouts.rolling);

    if (legendState.performanceDirty) {
        const legendSeries = new Array(allPossibleSeries.length);
        for (let i = 0; i < allPossibleSeries.length; i++) {
            const s = allPossibleSeries[i];
            legendSeries[i] = {
                key: s.key,
                name: s.name,
                color: colorMap[s.key] || colors.contribution,
            };
        }
        updateLegend(legendSeries, chartManager);
        legendState.performanceDirty = false;
    }
}

import { logger } from '../../../utils/logger.js';
import { transactionState } from '../../state.js';
import { chartLayouts } from '../state.js';
import { loadSectorsSnapshotData } from '../../dataLoader.js';
import {
    stopPerformanceAnimation,
    stopContributionAnimation,
    stopFxAnimation,
} from '../animation.js';
import { updateCrosshairUI, updateLegend, drawCrosshairOverlay } from '../interaction.js';
import { drawAxes } from '../core.js';
import {
    createTimeInterpolator,
    clampTime,
    formatPercentInline,
    parseLocalDate,
} from '../helpers.js';
import {
    formatCurrencyInlineValue,
    formatCurrencyCompact,
    convertValueToCurrency,
} from '../../utils.js';
import { COLOR_PALETTES } from '../../../config.js';

let sectorsDataCache = null;
let sectorsDataLoading = false;

function renderSectorsChartWithMode(ctx, chartManager, data, options = {}) {
    const valueMode = options.valueMode === 'absolute' ? 'absolute' : 'percent';

    if (
        !data ||
        typeof data !== 'object' ||
        !Array.isArray(data.dates) ||
        data.dates.length === 0
    ) {
        chartLayouts.sectors = null;
        chartLayouts.sectorsAbs = null;
        updateCrosshairUI(null, null);
        const emptyState = document.getElementById('runningAmountEmpty');
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    const emptyState = document.getElementById('runningAmountEmpty');
    if (emptyState) {
        emptyState.style.display = 'none';
    }

    const rawDates = data.dates.slice();
    const rawSeries = data.series || {};
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    // Bolt: Replaced O(N) Array .map().filter().map() with a single inline loop
    const filteredIndices = [];
    for (let i = 0; i < rawDates.length; i += 1) {
        const date = parseLocalDate(rawDates[i]);
        if (!date || Number.isNaN(date.getTime())) {
            continue;
        }
        if (filterFrom && date < filterFrom) {
            continue;
        }
        if (filterTo && date > filterTo) {
            continue;
        }
        filteredIndices.push(i);
    }

    const dates =
        filterFrom || filterTo ? filteredIndices.map((i) => rawDates[i]) : rawDates.slice();

    if (dates.length === 0) {
        if (valueMode === 'absolute') {
            chartLayouts.sectorsAbs = null;
        } else {
            chartLayouts.sectors = null;
        }
        updateCrosshairUI(null, null);
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    const rawTotalValues = Array.isArray(data.total_values) ? data.total_values : [];
    const mappedTotalValues =
        filterFrom || filterTo
            ? filteredIndices.map((index) => Number(rawTotalValues[index] ?? 0))
            : rawTotalValues.map((value) => Number(value ?? 0));

    const totalValuesUsd = mappedTotalValues;
    const totalValuesConverted = totalValuesUsd.map((value, idx) => {
        const converted = convertValueToCurrency(value, dates[idx], selectedCurrency);
        return Number.isFinite(converted) ? converted : 0;
    });

    const percentSeriesMap = {};
    const chartData = {};
    Object.entries(rawSeries).forEach(([sector, values]) => {
        const mappedValues =
            filterFrom || filterTo
                ? filteredIndices.map((index) => values[index] ?? 0)
                : values.map((value) => value ?? 0);

        percentSeriesMap[sector] = mappedValues;
        if (valueMode === 'absolute') {
            // Bolt: Optimize absolute value mapping by pre-allocating an array and using a for loop
            const absoluteValues = new Array(mappedValues.length);
            for (let i = 0; i < mappedValues.length; i += 1) {
                absoluteValues[i] = ((totalValuesConverted[i] ?? 0) * mappedValues[i]) / 100;
            }
            chartData[sector] = absoluteValues;
        } else {
            chartData[sector] = mappedValues;
        }
    });

    const baseSectorOrder = Object.keys(chartData).sort((a, b) => {
        const arrA = chartData[a] || [];
        const arrB = chartData[b] || [];
        const lastA = arrA[arrA.length - 1] ?? 0;
        const lastB = arrB[arrB.length - 1] ?? 0;
        return lastB - lastA;
    });

    const canvas = ctx.canvas;
    const canvasWidth = canvas.offsetWidth;
    const canvasHeight = canvas.offsetHeight;
    const isMobile = window.innerWidth <= 768;
    const padding = isMobile
        ? { top: 15, right: 18, bottom: 36, left: 48 }
        : { top: 22, right: 26, bottom: 48, left: 68 };
    const plotWidth = canvasWidth - padding.left - padding.right;
    const plotHeight = canvasHeight - padding.top - padding.bottom;

    if (plotWidth <= 0 || plotHeight <= 0) {
        return;
    }

    const colors = COLOR_PALETTES.COMPOSITION_CHART_COLORS;
    const resolveSectorColor = (sector) => {
        const index = baseSectorOrder.indexOf(sector);
        return colors[index % colors.length];
    };

    const dateTimes = new Array(dates.length);
    let minTime = Infinity;
    let maxTime = -Infinity;
    for (let i = 0; i < dates.length; i++) {
        const time = parseLocalDate(dates[i]).getTime();
        dateTimes[i] = time;
        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
    }

    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }

    const xScale = (time) =>
        padding.left +
        (maxTime === minTime
            ? plotWidth / 2
            : ((time - minTime) / (maxTime - minTime)) * plotWidth);

    const yMin = 0;
    let maxTotalValue = 0;
    for (let i = 0; i < totalValuesConverted.length; i++) {
        if (totalValuesConverted[i] > maxTotalValue) {
            maxTotalValue = totalValuesConverted[i];
        }
    }
    const yMax = valueMode === 'absolute' ? Math.max(maxTotalValue, 1) : 100;
    const yScale = (value) =>
        padding.top + plotHeight - ((value - yMin) / (yMax - yMin || 1)) * plotHeight;

    const axisFormatter =
        valueMode === 'absolute'
            ? (val) => formatCurrencyCompact(val, { currency: selectedCurrency })
            : (val) => `${val}%`;

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        axisFormatter,
        valueMode !== 'absolute'
    );

    const cumulativeValues = new Array(dates.length).fill(0);
    // Bolt: Use standard for loop instead of .forEach to avoid closure allocation inside rendering loop
    for (let sIdx = 0; sIdx < baseSectorOrder.length; sIdx += 1) {
        const sector = baseSectorOrder[sIdx];
        const values = chartData[sector] || [];
        const color = resolveSectorColor(sector);
        ctx.beginPath();
        ctx.fillStyle = `${color}80`;
        ctx.strokeStyle = 'rgba(128, 128, 128, 0.5)';
        ctx.lineWidth = 1;

        // Bolt: Use standard for loop instead of .forEach to avoid closure allocation
        for (let index = 0; index < dates.length; index += 1) {
            const dateStr = dates[index];
            const x = xScale(parseLocalDate(dateStr).getTime());
            const y = yScale(cumulativeValues[index] + values[index]);
            if (index === 0) {
                ctx.moveTo(x, y);
            } else {
                ctx.lineTo(x, y);
            }
        }

        for (let i = dates.length - 1; i >= 0; i -= 1) {
            const x = xScale(parseLocalDate(dates[i]).getTime());
            const y = yScale(cumulativeValues[i]);
            ctx.lineTo(x, y);
        }
        ctx.closePath();
        ctx.fill();
        ctx.stroke();

        // Bolt: Optimize array allocation by mutating cumulativeValues in place instead of map
        for (let i = 0; i < cumulativeValues.length; i += 1) {
            cumulativeValues[i] += values[i];
        }
    }

    const latestIndex = dates.length - 1;
    const legendSeries = baseSectorOrder
        .map((sector) => ({
            sector,
            percent: percentSeriesMap[sector][latestIndex] ?? 0,
        }))
        .filter((s) => s.percent > 0.1)
        .sort((a, b) => b.percent - a.percent)
        .slice(0, 4)
        .map((s) => ({
            key: s.sector,
            name: s.sector,
            color: resolveSectorColor(s.sector),
        }));

    const seriesForCrosshair = baseSectorOrder.map((sector) => {
        const values = chartData[sector];
        const points = dateTimes.map((time, idx) => ({
            time,
            value: values[idx],
        }));
        return {
            key: sector,
            label: sector,
            color: resolveSectorColor(sector),
            getValueAtTime: createTimeInterpolator(points),
            formatValue: (value) =>
                valueMode === 'absolute'
                    ? formatCurrencyInlineValue(value, selectedCurrency)
                    : `${value.toFixed(2)}%`,
            formatDelta: (delta) =>
                valueMode === 'absolute'
                    ? formatCurrencyInlineValue(delta, selectedCurrency)
                    : formatPercentInline(delta),
        };
    });

    const totalValuePoints = dateTimes.map((time, idx) => ({
        time,
        value: Number(totalValuesConverted[idx] ?? 0),
    }));

    const layoutKey = valueMode === 'absolute' ? 'sectorsAbs' : 'sectors';
    chartLayouts[layoutKey] = {
        key: layoutKey,
        minTime,
        maxTime,
        valueType: valueMode === 'absolute' ? 'currency' : 'percent',
        valueMode,
        currency: selectedCurrency,
        stackMaxValue: yMax,
        padding,
        chartBounds: {
            top: padding.top,
            bottom: padding.top + plotHeight,
            left: padding.left,
            right: padding.left + plotWidth,
        },
        xScale,
        yScale,
        invertX: (pixelX) => {
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: seriesForCrosshair,
        percentSeriesMap,
        dates,
        getTotalValueAtTime: createTimeInterpolator(totalValuePoints),
    };

    drawCrosshairOverlay(ctx, chartLayouts[layoutKey]);
    updateLegend(legendSeries, chartManager);
}

function drawSectorsChartLoader(ctx, chartManager, valueMode) {
    stopPerformanceAnimation();
    stopContributionAnimation();
    stopFxAnimation();
    const emptyState = document.getElementById('runningAmountEmpty');

    if (!sectorsDataCache && sectorsDataLoading) {
        if (emptyState) {
            emptyState.style.display = 'block';
        }
        return;
    }

    if (sectorsDataCache) {
        renderSectorsChartWithMode(ctx, chartManager, sectorsDataCache, { valueMode });
        return;
    }

    sectorsDataLoading = true;
    loadSectorsSnapshotData()
        .then((data) => {
            if (!data) {
                throw new Error('Failed to load sectors data');
            }
            sectorsDataCache = data;
            renderSectorsChartWithMode(ctx, chartManager, data, { valueMode });
        })
        .catch((error) => {
            logger.warn('Sectors chart rendering failed:', error);
            updateCrosshairUI(null, null);
            if (emptyState) {
                emptyState.style.display = 'block';
            }
        })
        .finally(() => {
            sectorsDataLoading = false;
        });
}

export function drawSectorsChart(ctx, chartManager) {
    drawSectorsChartLoader(ctx, chartManager, 'percent');
}

export function drawSectorsAbsoluteChart(ctx, chartManager) {
    drawSectorsChartLoader(ctx, chartManager, 'absolute');
}

import { transactionState, getShowChartLabels } from '../../state.js';
import {
    stopPerformanceAnimation,
    stopContributionAnimation,
    stopFxAnimation,
    isAnimationEnabled,
    advancePerformanceAnimation,
    schedulePerformanceAnimation,
} from '../animation.js';
import {
    updateCrosshairUI,
    drawCrosshairOverlay,
    updateLegend,
    legendState,
} from '../interaction.js';
import { PERFORMANCE_SERIES_CURRENCY, BENCHMARK_GRADIENTS } from '../config.js';
import { CHART_LINE_WIDTHS, mountainFill } from '../../../config.js';
import { convertBetweenCurrencies } from '../../utils.js';
import { drawAxes, drawMountainFill, drawEndValue } from '../core.js';
import {
    getChartColors,
    getSmoothingConfig,
    createTimeInterpolator,
    formatPercentInline,
    clampTime,
    parseLocalDate,
} from '../helpers.js';
import { smoothFinancialData } from '../../../utils/smoothing.js';
import { chartLayouts } from '../state.js';
import { drawSeriesGlow } from '../animation.js';

export async function drawVolatilityChart(ctx, chartManager, timestamp) {
    const performanceSeries =
        transactionState.performanceSeries && typeof transactionState.performanceSeries === 'object'
            ? transactionState.performanceSeries
            : {};
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const { chartVisibility } = transactionState;
    stopContributionAnimation();
    stopFxAnimation();
    if (Object.keys(performanceSeries).length === 0) {
        stopPerformanceAnimation();
        chartLayouts.volatility = null;
        updateCrosshairUI(null, null);
        return;
    }

    const orderedKeys = Object.keys(performanceSeries).sort((a, b) => {
        if (a === '^LZ') {
            return -1;
        }
        if (b === '^LZ') {
            return 1;
        }
        return a.localeCompare(b);
    });

    orderedKeys.forEach((key) => {
        if (transactionState.chartVisibility[key] === undefined) {
            transactionState.chartVisibility[key] = key === '^LZ' || key === '^GSPC';
        }
    });

    // Transform cumulative TWRR into 90-day annualized rolling volatility
    const allPossibleSeries = orderedKeys.map((key) => {
        const points = Array.isArray(performanceSeries[key]) ? performanceSeries[key] : [];
        const sourceCurrency = PERFORMANCE_SERIES_CURRENCY[key] || 'USD';

        // 1. Convert cumulative values and calculate daily returns
        const dailyReturns = [];
        for (let i = 1; i < points.length; i++) {
            const startVal = convertBetweenCurrencies(
                Number(points[i - 1].value),
                sourceCurrency,
                points[i - 1].date,
                selectedCurrency
            );
            const endVal = convertBetweenCurrencies(
                Number(points[i].value),
                sourceCurrency,
                points[i].date,
                selectedCurrency
            );

            if (startVal !== 0) {
                const ret = endVal / startVal - 1;
                dailyReturns.push({
                    date: points[i].date,
                    value: ret,
                });
            }
        }

        // 2. Calculate rolling standard deviation of daily returns (90-day window)
        const volatilityData = [];
        const windowSize = 90;

        // Bolt: Optimize O(N * W) slice allocations by iterating indices directly over dailyReturns array
        for (let i = windowSize - 1; i < dailyReturns.length; i++) {
            let sum = 0;
            const startIdx = i - windowSize + 1;

            for (let j = startIdx; j <= i; j++) {
                sum += dailyReturns[j].value;
            }
            const mean = sum / windowSize;

            let varianceSum = 0;
            for (let j = startIdx; j <= i; j++) {
                varianceSum += Math.pow(dailyReturns[j].value - mean, 2);
            }
            const variance = varianceSum / (windowSize - 1);

            const dailyStdDev = Math.sqrt(variance);

            // Annualize (multiply by sqrt(252))
            const annualizedVolatility = dailyStdDev * Math.sqrt(252) * 100; // in percentage

            volatilityData.push({
                date: dailyReturns[i].date,
                value: annualizedVolatility,
            });
        }

        return {
            key,
            name: key,
            data: volatilityData,
        };
    });

    const visibility = chartVisibility || {};
    const seriesToDraw = allPossibleSeries.filter((s) => visibility[s.key] !== false);

    if (seriesToDraw.length === 0) {
        stopPerformanceAnimation();
        chartLayouts.volatility = null;
        updateCrosshairUI(null, null);
        return;
    }

    const canvas = ctx.canvas;
    const isMobile = typeof window !== 'undefined' ? window.innerWidth <= 768 : false;
    const padding = isMobile
        ? { top: 15, right: 20, bottom: 35, left: 50 }
        : { top: 20, right: 30, bottom: 48, left: 70 };
    const plotWidth = canvas.offsetWidth - padding.left - padding.right;
    const plotHeight = canvas.offsetHeight - padding.top - padding.bottom;

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    const filteredSeries = [];
    const allPoints = [];
    for (let i = 0; i < seriesToDraw.length; i++) {
        const s = seriesToDraw[i];
        const validData = [];
        for (let j = 0; j < s.data.length; j++) {
            const d = s.data[j];
            const dt = parseLocalDate(d.date);
            if ((!filterFrom || dt >= filterFrom) && (!filterTo || dt <= filterTo)) {
                validData.push(d);
                allPoints.push(d);
            }
        }
        filteredSeries.push({ ...s, data: validData });
    }
    if (allPoints.length === 0) {
        stopPerformanceAnimation();
        return;
    }

    // Bolt: Use explicit O(N) loop instead of chained .map() and Math.max(...spread) to eliminate GC overhead and avoid call stack limits
    let minTime = Infinity;
    let maxTime = -Infinity;
    let dataMin = Infinity;
    let dataMax = -Infinity;

    for (let i = 0; i < allPoints.length; i++) {
        const time = parseLocalDate(allPoints[i].date).getTime();
        const value = allPoints[i].value;
        if (time < minTime) {
            minTime = time;
        }
        if (time > maxTime) {
            maxTime = time;
        }
        if (value < dataMin) {
            dataMin = value;
        }
        if (value > dataMax) {
            dataMax = value;
        }
    }

    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }
    const valueRange = dataMax - dataMin;
    const yPaddingTop = Math.max(valueRange * 0.1, 5);
    // Add small buffer to bottom so 0 is not on the axis
    const yMin = -0.5;
    const yMax = dataMax + yPaddingTop;

    const xScale = (t) =>
        padding.left +
        (maxTime === minTime ? plotWidth / 2 : ((t - minTime) / (maxTime - minTime)) * plotWidth);
    const yScale = (v) =>
        padding.top +
        plotHeight -
        (yMax === yMin ? plotHeight / 2 : ((v - yMin) / (yMax - yMin)) * plotHeight);

    drawAxes(
        ctx,
        padding,
        plotWidth,
        plotHeight,
        minTime,
        maxTime,
        yMin,
        yMax,
        xScale,
        yScale,
        (v) => `${v.toFixed(0)}%`,
        true
    );

    const animationPhase = advancePerformanceAnimation(timestamp);
    const rootStyles =
        typeof window !== 'undefined' ? window.getComputedStyle(document.documentElement) : null;
    const colors = getChartColors(rootStyles);
    const colorMap = {
        '^LZ': BENCHMARK_GRADIENTS['^LZ'][1],
        '^GSPC': BENCHMARK_GRADIENTS['^GSPC'][1],
        '^IXIC': BENCHMARK_GRADIENTS['^IXIC'][1],
        '^DJI': BENCHMARK_GRADIENTS['^DJI'][1],
        '^SSEC': BENCHMARK_GRADIENTS['^SSEC'][1],
        '^HSI': BENCHMARK_GRADIENTS['^HSI'][1],
        '^N225': BENCHMARK_GRADIENTS['^N225'][1],
    };

    const lineThickness = CHART_LINE_WIDTHS.performance ?? 2;
    const renderedSeries = [];
    let glowIndex = 0;

    const chartBounds = {
        top: padding.top,
        bottom: padding.top + plotHeight,
        left: padding.left,
        right: padding.left + plotWidth,
    };

    const seriesForDrawing = filteredSeries.slice().sort((a, b) => {
        const aIsPortfolio = a.key === '^LZ';
        const bIsPortfolio = b.key === '^LZ';
        if (aIsPortfolio && !bIsPortfolio) {
            return 1;
        }
        if (!aIsPortfolio && bIsPortfolio) {
            return -1;
        }
        return 0;
    });

    seriesForDrawing.forEach((series) => {
        if (series.data.length === 0) {
            return;
        }

        const rawPoints = series.data;
        const smoothingConfig = getSmoothingConfig('performance');
        const points = smoothingConfig
            ? smoothFinancialData(
                  rawPoints.map((p) => ({ x: parseLocalDate(p.date).getTime(), y: p.value })),
                  smoothingConfig,
                  true
              ).map((p) => ({ date: parseLocalDate(p.x), value: p.y }))
            : rawPoints.map((p) => ({ date: parseLocalDate(p.date), value: p.value }));

        const gradientStops = BENCHMARK_GRADIENTS[series.key];
        const resolvedColor = gradientStops
            ? gradientStops[1]
            : colorMap[series.key] || colors.contribution;

        const coords = points.map((p) => ({
            x: xScale(p.date.getTime()),
            y: yScale(p.value),
            time: p.date.getTime(),
            value: p.value,
        }));

        if (mountainFill.enabled) {
            drawMountainFill(ctx, coords, yScale(yMin), {
                color: resolvedColor,
                colorStops: gradientStops || [resolvedColor, resolvedColor],
                opacityTop: 0.35,
                opacityBottom: 0,
                bounds: chartBounds,
            });
        }

        ctx.beginPath();
        for (let idx = 0; idx < coords.length; idx++) {
            const c = coords[idx];
            if (idx === 0) {
                ctx.moveTo(c.x, c.y);
            } else {
                ctx.lineTo(c.x, c.y);
            }
        }
        ctx.strokeStyle = resolvedColor;
        if (gradientStops) {
            const grad = ctx.createLinearGradient(padding.left, 0, padding.left + plotWidth, 0);
            grad.addColorStop(0, gradientStops[0]);
            grad.addColorStop(1, gradientStops[1]);
            ctx.strokeStyle = grad;
        }
        ctx.lineWidth = lineThickness;
        ctx.stroke();

        renderedSeries.push({
            key: series.key,
            name: series.name,
            color: resolvedColor,
            x: coords[coords.length - 1].x,
            y: coords[coords.length - 1].y,
            value: points[points.length - 1].value,
            coords,
            points: coords.map((c) => ({ time: c.time, value: c.value })),
        });

        if (isAnimationEnabled('performance')) {
            drawSeriesGlow(
                ctx,
                { coords, color: resolvedColor, lineWidth: lineThickness },
                {
                    basePhase: animationPhase,
                    seriesIndex: glowIndex,
                    isMobile,
                    chartKey: 'performance',
                }
            );
            glowIndex += 1;
        }
    });

    if (isAnimationEnabled('performance') && glowIndex > 0) {
        schedulePerformanceAnimation(chartManager);
    } else {
        stopPerformanceAnimation();
    }

    const showChartLabels = getShowChartLabels();
    const labelBounds = [];
    if (showChartLabels) {
        renderedSeries.forEach((s) => {
            const bounds = drawEndValue(
                ctx,
                s.x,
                s.y,
                s.value,
                s.color,
                isMobile,
                padding,
                plotWidth,
                plotHeight,
                (v) => `${v.toFixed(1)}%`,
                true,
                labelBounds
            );
            if (bounds) {
                labelBounds.push(bounds);
            }
        });
    }

    chartLayouts.volatility = {
        key: 'volatility',
        minTime,
        maxTime,
        valueType: 'percent',
        padding,
        chartBounds,
        xScale,
        yScale,
        invertX: (pixelX) => {
            const clampedX = Math.max(padding.left, Math.min(padding.left + plotWidth, pixelX));
            if (plotWidth <= 0 || maxTime === minTime) {
                return minTime;
            }
            const ratio = (clampedX - padding.left) / plotWidth;
            return clampTime(minTime + ratio * (maxTime - minTime), minTime, maxTime);
        },
        series: renderedSeries.map((s) => ({
            key: s.key,
            label: s.name,
            color: s.color,
            getValueAtTime: createTimeInterpolator(s.points),
            formatValue: (v) => `${v.toFixed(2)}%`,
            formatDelta: (delta, percent) => formatPercentInline(percent ?? delta),
        })),
    };

    drawCrosshairOverlay(ctx, chartLayouts.volatility);

    if (legendState.performanceDirty) {
        const legendSeries = allPossibleSeries.map((s) => ({
            key: s.key,
            name: s.name,
            color: colorMap[s.key] || colors.contribution,
        }));
        updateLegend(legendSeries, chartManager);
        legendState.performanceDirty = false;
    }
}

import { logger } from '../../../utils/logger.js';
import { transactionState, getShowChartLabels } from '../../state.js';
import { chartLayouts } from '../state.js';
import { CHART_LINE_WIDTHS, mountainFill } from '../../../config.js';
import { BENCHMARK_GRADIENTS } from '../config.js';
import {
    stopPerformanceAnimation,
    stopContributionAnimation,
    stopFxAnimation,
    stopPeAnimation,
    stopConcentrationAnimation,
    stopYieldAnimation,
    isAnimationEnabled,
    advanceYieldAnimation,
    scheduleYieldAnimation,
    drawSeriesGlow,
} from '../animation.js';
import { updateLegend, drawCrosshairOverlay } from '../interaction.js';
import { drawAxes, drawEndValue, generateConcreteTicks, drawMountainFill } from '../core.js';
import { getChartColors, createTimeInterpolator, parseLocalDate } from '../helpers.js';
import {
    formatCurrencyCompact,
    formatCurrencyInline,
    convertValueToCurrency,
} from '../../utils.js';

// Data cache
let yieldDataCache = null;
let yieldDataPromise = null;
let yieldDataLoading = false; // still used locally by drawYieldChart if we don't refactor it

/**
 * Get synchronously cached yield data
 */
export function getCachedYieldData() {
    return yieldDataCache;
}

/**
 * Load yield data from the backend JSON with caching.
 */
export async function loadYieldData() {
    if (yieldDataCache) {
        return yieldDataCache;
    }
    if (yieldDataPromise) {
        return yieldDataPromise;
    }
    yieldDataPromise = (async () => {
        try {
            const response = await fetch('../data/yield_data.json');
            if (!response.ok) {
                yieldDataPromise = null;
                return null;
            }
            yieldDataCache = await response.json();
            return yieldDataCache;
        } catch (error) {
            logger.warn('Yield chart rendering failed:', error);
            yieldDataPromise = null;
            return null;
        }
    })();
    return yieldDataPromise;
}

/**
 * Main draw function for the yield chart.
 */
export async function drawYieldChart(ctx, chartManager, timestamp) {
    const { canvas } = ctx;
    const width = canvas.offsetWidth;
    const height = canvas.offsetHeight;
    const { chartDateRange } = transactionState;

    // Load data if not cached
    if (!yieldDataCache && !yieldDataLoading) {
        yieldDataLoading = true;
        yieldDataCache = await loadYieldData();
        yieldDataLoading = false;
        chartManager.update();
        return;
    }

    if (!yieldDataCache) {
        return;
    }

    // Filter data by date range
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    // Bolt: Replaced Array .filter() and .map() with a single inline loop
    const filteredData = [];
    for (let i = 0; i < yieldDataCache.length; i++) {
        const d = yieldDataCache[i];
        const date = parseLocalDate(d.date);
        if ((!filterFrom || date >= filterFrom) && (!filterTo || date <= filterTo)) {
            filteredData.push(d);
        }
    }

    if (filteredData.length === 0) {
        stopYieldAnimation();
        return;
    }

    const margin = { top: 40, right: 60, bottom: 40, left: 60 };
    const chartWidth = width - margin.left - margin.right;
    const chartHeight = height - margin.top - margin.bottom;

    const times = new Array(filteredData.length);
    for (let i = 0; i < filteredData.length; i++) {
        times[i] = parseLocalDate(filteredData[i].date).getTime();
    }
    let minTime = times[0];
    const maxTime = times[times.length - 1];

    // Ensure minTime aligns with filter start for correct x-axis labels
    const filterFromTime = filterFrom ? filterFrom.getTime() : null;
    if (Number.isFinite(filterFromTime)) {
        minTime = Math.max(minTime, filterFromTime);
    }

    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    // Y-Axis 1: Forward Yield (%)
    // Bolt: Use explicit O(N) loop instead of chained .map() and Math.max(...spread) to eliminate GC overhead and avoid call stack limits
    const yields = [];
    const incomes = [];
    let rawMaxY = 1;
    let rawMaxIncome = 100;

    for (let i = 0; i < filteredData.length; i += 1) {
        const d = filteredData[i];

        const yieldVal = d.forward_yield;
        yields.push(yieldVal);
        if (yieldVal > rawMaxY) {
            rawMaxY = yieldVal;
        }

        const incomeVal = convertValueToCurrency(d.ttm_income, d.date, selectedCurrency);
        incomes.push(incomeVal);
        if (incomeVal > rawMaxIncome) {
            rawMaxIncome = incomeVal;
        }
    }

    const minY = 0;
    const maxY = rawMaxY * 1.1;

    const minIncome = 0;
    const maxIncome = rawMaxIncome * 1.1;

    const xScale = (t) => margin.left + ((t - minTime) / (maxTime - minTime || 1)) * chartWidth;
    const yScale = (y) => margin.top + chartHeight - ((y - minY) / (maxY - minY)) * chartHeight;
    const y2Scale = (i) =>
        margin.top + chartHeight - ((i - minIncome) / (maxIncome - minIncome)) * chartHeight;

    // Stop other animations
    stopPerformanceAnimation();
    stopContributionAnimation();
    stopFxAnimation();
    stopPeAnimation();
    stopConcentrationAnimation();

    // Clear canvas
    ctx.clearRect(0, 0, width, height);

    // Generate ticks for the left y-axis (yield) to use for both axes alignment
    const yieldTicks = generateConcreteTicks(minY, maxY, false, selectedCurrency);

    // Explicitly set text style for axes before calling drawAxes
    ctx.fillStyle = '#8b949e';

    // Draw axes
    drawAxes(
        ctx,
        margin,
        chartWidth,
        chartHeight,
        minTime,
        maxTime,
        minY,
        maxY,
        xScale,
        yScale,
        (v) => `${v.toFixed(1)}%`,
        false, // isPerformanceChart
        {}, // axisOptions
        selectedCurrency, // currency
        false // forcePercent
    );

    const rootStyles = window.getComputedStyle(document.documentElement);
    const colors = getChartColors(rootStyles);
    const isMobile = window.innerWidth <= 768;
    const monoFont =
        'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace';

    // 1. Draw Secondary Y-Axis (Right) for TTM Income
    // Use the same vertical positions as the left axis for alignment
    ctx.save();
    ctx.fillStyle = '#8b949e';
    ctx.font = isMobile ? `9px ${monoFont}` : `11px ${monoFont}`;
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';

    // Map yield tick positions to income values for aligned labels
    // Bolt: Use standard for loop instead of .forEach to avoid closure allocation inside rendering loop
    for (let i = 0; i < yieldTicks.length; i++) {
        const yieldTick = yieldTicks[i];
        // Convert yield tick to a position (0-1 ratio)
        const ratio = (yieldTick - minY) / (maxY - minY);
        // Map that ratio to income scale
        const incomeValue = minIncome + ratio * (maxIncome - minIncome);

        // Always draw the tick at the mapped position, even if slightly outside
        // This ensures alignment with left axis grid lines
        const y = y2Scale(incomeValue);

        // Only skip if the y position is completely outside the chart area
        // Use generous padding to ensure edge ticks (top/bottom) are always visible
        const chartTop = margin.top;
        const chartBottom = margin.top + chartHeight;
        const labelPadding = 20;

        if (y >= chartTop - labelPadding && y <= chartBottom + labelPadding) {
            ctx.fillText(
                formatCurrencyCompact(Math.round(incomeValue), { currency: selectedCurrency }),
                margin.left + chartWidth + 10,
                y
            );
        }
    }
    ctx.restore();

    // 2. Draw TTM Income Bars (Background)
    ctx.save();
    const barWidth = Math.max(2, (chartWidth / filteredData.length) * 0.8);
    // Use portfolio color for Income bars
    ctx.fillStyle = (colors.portfolio || '#7a7a7a') + '44'; // Semi-transparent

    ctx.beginPath();
    // Bolt: Use standard for loop instead of .forEach to avoid closure allocation inside rendering loop
    for (let i = 0; i < filteredData.length; i++) {
        const d = filteredData[i];
        const t = parseLocalDate(d.date).getTime();
        const x = xScale(t) - barWidth / 2;
        const y = y2Scale(incomes[i]);
        const h = Math.max(0, margin.top + chartHeight - y);
        if (h > 0) {
            ctx.rect(x, y, barWidth, h);
        }
    }
    ctx.fill();
    ctx.restore();

    // 3. Draw Forward Yield Line
    const yieldColor = colors.contribution || '#b3b3b3';
    const gradientStops = BENCHMARK_GRADIENTS['^LZ'] || [yieldColor, yieldColor];

    // Map data to coordinates
    const yieldCoords = new Array(filteredData.length);
    for (let i = 0; i < filteredData.length; i++) {
        const d = filteredData[i];
        const t = parseLocalDate(d.date).getTime();
        yieldCoords[i] = {
            x: xScale(t),
            y: yScale(d.forward_yield),
            time: t,
            value: d.forward_yield,
        };
    }

    const chartBounds = {
        top: margin.top,
        bottom: margin.top + chartHeight,
        left: margin.left,
        right: margin.left + chartWidth,
    };

    if (mountainFill.enabled) {
        drawMountainFill(ctx, yieldCoords, yScale(minY), {
            color: yieldColor,
            colorStops: gradientStops,
            opacityTop: 0.35,
            opacityBottom: 0,
            bounds: chartBounds,
        });
    }

    ctx.beginPath();

    const grad = ctx.createLinearGradient(margin.left, 0, margin.left + chartWidth, 0);
    grad.addColorStop(0, gradientStops[0]);
    grad.addColorStop(1, gradientStops[1]);
    ctx.strokeStyle = grad;

    ctx.lineWidth = CHART_LINE_WIDTHS.yield || 1;
    // Bolt: Use standard for loop instead of .forEach to avoid closure allocation inside rendering loop
    for (let i = 0; i < yieldCoords.length; i++) {
        const c = yieldCoords[i];
        if (i === 0) {
            ctx.moveTo(c.x, c.y);
        } else {
            ctx.lineTo(c.x, c.y);
        }
    }
    ctx.stroke();

    const incomePoints = new Array(filteredData.length);
    for (let i = 0; i < filteredData.length; i++) {
        const d = filteredData[i];
        incomePoints[i] = {
            time: parseLocalDate(d.date).getTime(),
            value: incomes[i],
        };
    }

    // Series for interaction and legend
    const yieldSeries = {
        key: 'Yield',
        name: 'Yield',
        label: 'Forward Yield',
        color: gradientStops[1],
        points: yieldCoords,
        yScale,
        getValueAtTime: createTimeInterpolator(yieldCoords),
        formatValue: (v) => `${v.toFixed(2)}%`,
    };

    const incomeSeries = {
        key: 'Income',
        name: 'Income',
        label: 'TTM Income',
        color: colors.portfolio || '#7a7a7a',
        points: incomePoints,
        yScale: y2Scale,
        getValueAtTime: createTimeInterpolator(incomePoints),
        formatValue: (v) => formatCurrencyInline(v, { currency: selectedCurrency }),
    };

    const series = [yieldSeries, incomeSeries];

    // Initialize chart layout for interaction system
    chartLayouts.yield = {
        key: 'yield',
        margin,
        chartBounds: {
            top: margin.top,
            bottom: margin.top + chartHeight,
            left: margin.left,
            right: margin.left + chartWidth,
        },
        chartWidth,
        chartHeight,
        minTime,
        maxTime,
        minY,
        maxY,
        xScale,
        yScale, // Main y-axis is yield
        invertX: (x) => minTime + ((x - margin.left) / chartWidth) * (maxTime - minTime),
        series,
    };

    // Ensure visibility state exists
    if (transactionState.chartVisibility['Yield'] === undefined) {
        transactionState.chartVisibility['Yield'] = true;
    }
    if (transactionState.chartVisibility['Income'] === undefined) {
        transactionState.chartVisibility['Income'] = true;
    }

    // Draw current value annotation
    const lastYield = yieldSeries.points[yieldSeries.points.length - 1].value;
    const lastIncome = incomeSeries.points[incomeSeries.points.length - 1].value;

    const showChartLabels = getShowChartLabels();
    let yieldBounds = null;
    if (showChartLabels) {
        yieldBounds = drawEndValue(
            ctx,
            margin.left + chartWidth + 5,
            yScale(lastYield),
            lastYield,
            gradientStops[1],
            isMobile,
            margin,
            chartWidth,
            chartHeight,
            yieldSeries.formatValue,
            true
        );

        drawEndValue(
            ctx,
            margin.left + chartWidth + 5,
            y2Scale(lastIncome),
            lastIncome,
            incomeSeries.color,
            isMobile,
            margin,
            chartWidth,
            chartHeight,
            incomeSeries.formatValue,
            true,
            yieldBounds
        );
    }

    const yieldAnimationEnabled = isAnimationEnabled('yield');
    const animationPhase = advanceYieldAnimation(timestamp);

    // Add glowing effect to the line
    if (yieldAnimationEnabled) {
        const lastCoord = yieldSeries.points[yieldSeries.points.length - 1];
        const coords = [lastCoord];

        drawSeriesGlow(
            ctx,
            { coords, color: yieldSeries.color, lineWidth: CHART_LINE_WIDTHS.yield || 1 },
            {
                basePhase: animationPhase,
                seriesIndex: 0,
                isMobile,
                chartKey: 'yield',
            }
        );

        scheduleYieldAnimation(chartManager);
    }

    // Update UI components
    updateLegend(series, chartManager);
    drawCrosshairOverlay(ctx, chartLayouts.yield);
}

