export async function loadCompositionSnapshotData() {
    try {
        const [response, realtime] = await Promise.all([
            fetch('../data/output/figures/composition.json'),
            fetchRealTimeData().catch((error) => {
                logger.warn('Data loading failed:', error);
                return null;
            }),
        ]);

        if (!response.ok) {
            logger.warn('figures/composition.json not found');
            return null;
        }

        const data = await response.json();

        // Merge real-time composition
        if (realtime && realtime.composition && realtime.date) {
            // Append date
            if (data.dates) {
                const lastDate = data.dates[data.dates.length - 1];
                // Update if dates match (intraday) or append if new date
                if (lastDate === realtime.date || lastDate < realtime.date) {
                    // If dates match, remove the stale point first so we can append the fresh one
                    // OR overwrite. Appending logic is simpler if we just pop the key arrays.
                    // But data.composition is object of arrays.
                    // Let's use an overwrite index strategy.
                    let targetIndex = data.dates.length;
                    if (lastDate === realtime.date) {
                        targetIndex = data.dates.length - 1;
                    } else {
                        data.dates.push(realtime.date);
                    }

                    // Update/Append total balance
                    if (Array.isArray(data.total_values) && Number.isFinite(realtime.balance)) {
                        data.total_values[targetIndex] = realtime.balance;
                    }

                    // Merge composition values
                    const composition = data.composition || data.series; // Support flexibility
                    if (composition) {
                        // Pre-compute real-time map for O(1) lookups
                        const rtMap = new Map();
                        const rtLen = realtime.composition.length;
                        for (let i = 0; i < rtLen; i++) {
                            const rtItem = realtime.composition[i];
                            rtMap.set(normalizeTicker(rtItem.ticker), rtItem.percent);
                        }

                        // For each ticker in historical composition, update/add point
                        const compKeys = Object.keys(composition);
                        const compLen = compKeys.length;
                        for (let i = 0; i < compLen; i++) {
                            const ticker = compKeys[i];
                            if (!Array.isArray(composition[ticker])) {
                                continue;
                            }
                            // Find real-time percent for this ticker
                            const rtPercent = rtMap.has(ticker) ? rtMap.get(ticker) : 0;
                            composition[ticker][targetIndex] = rtPercent;
                        }

                        // Add new tickers found in real-time but not history
                        for (let i = 0; i < rtLen; i++) {
                            const rtItem = realtime.composition[i];
                            const normalizedTicker = normalizeTicker(rtItem.ticker);
                            if (Math.abs(rtItem.percent) > 0.001) {
                                // Only if significant
                                if (!composition[normalizedTicker]) {
                                    // Backfill with 0s up to targetIndex
                                    composition[normalizedTicker] = new Array(targetIndex).fill(0);
                                    composition[normalizedTicker][targetIndex] = rtItem.percent;
                                } else {
                                    // Ensure it has value at targetIndex (handled in loop above if key existed)
                                    // If key didn't exist in composition before loop, it enters this block.
                                    // If it partially existed but loop missed it? No, Object.keys covers existing.
                                    // So this block is strictly for NEW keys.
                                    composition[normalizedTicker][targetIndex] = rtItem.percent;
                                }
                            }
                        }
                    }
                }
            }
        }

        return data;
    } catch (error) {
        logger.warn('Failed to load composition snapshot:', error);
        return null;
    }
}

import { logger } from '@utils/logger.js';
import { getNyDate, isTradingDay } from '@utils/date.js';
import {
    fetchPortfolioData,
    fetchMarketRatiosForTickers,
    _calculateDynamicPeValues,
} from '@services/dataService.js';

const FX_DATA_URL = '../data/fx_data.json';

async function fetchJSON(url) {
    const response = await fetch(`${url}?t=${new Date().getTime()}`);
    if (!response.ok) {
        throw new Error(`Failed to fetch ${url}: ${response.status} ${response.statusText}`);
    }
    return response.json();
}

/**
 * Fetches real-time data and calculates the current portfolio state.
 * @returns {Promise<{
 *   date: string,
 *   balance: number,
 *   composition: Array<{ticker: string, value: number, percent: number}>,
 *   fxRates: Object,
 *   pe: number | null,
 *   forwardPe: number | null,
 *   tickerPEs: Object,
 *   tickerWeights: Object
 * } | null>}
 */
export async function fetchRealTimeData() {
    try {
        const today = getNyDate();
        if (!isTradingDay(today)) {
            // Optional: You might still want to return data if you want to show
            // the "latest" closed price even on weekends, but usually charts
            // stick to trading days. For now, let's respect the trading day check.
            // But if the user wants "real time", they might expect to see it updates
            // even if the market is closed but data was updated?
            // "data updated every 30min" implies it might change.
            // Let's allow it for now, as isTradingDay might strict check weekends.
        }

        const [{ holdingsDetails: holdings, prices }, fx] = await Promise.all([
            fetchPortfolioData(),
            fetchJSON(FX_DATA_URL),
        ]);

        if (!holdings || !prices) {
            return null;
        }

        let totalBalanceUSD = 0;
        const composition = [];
        const tickers = Object.keys(holdings);

        const marketRatiosByTicker = await fetchMarketRatiosForTickers(tickers);

        let weightSum = 0;
        let weightedYieldSum = 0;
        let weightedFwdYieldSum = 0;
        const tickerPEs = {};
        const tickerWeights = {};

        // 1. Calculate Balance and Composition
        tickers.forEach((ticker) => {
            const details = holdings[ticker];
            const shares = parseFloat(details.shares) || 0;
            const price = parseFloat(prices[ticker]) || 0;
            if (shares > 0 && price > 0) {
                const value = shares * price;
                totalBalanceUSD += value;
                composition.push({
                    ticker,
                    value,
                    // percent calculated later
                });

                const ratioSnapshot = marketRatiosByTicker.get(ticker);
                if (ratioSnapshot) {
                    const { trailingValue, forwardValue } = _calculateDynamicPeValues(
                        ratioSnapshot,
                        price
                    );

                    if (Number.isFinite(trailingValue) && trailingValue > 0) {
                        tickerPEs[ticker] = trailingValue;
                        weightedYieldSum += value / trailingValue;
                    }
                    if (Number.isFinite(forwardValue) && forwardValue > 0) {
                        weightedFwdYieldSum += value / forwardValue;
                    }
                }
                tickerWeights[ticker] = value;
                weightSum += value;
            }
        });

        const portfolioPE =
            weightSum > 0 && weightedYieldSum > 0 ? weightSum / weightedYieldSum : null;
        const portfolioFwdPE =
            weightSum > 0 && weightedFwdYieldSum > 0 ? weightSum / weightedFwdYieldSum : null;

        // 2. Add Composition Percentages
        if (totalBalanceUSD > 0) {
            composition.forEach((item) => {
                item.percent = (item.value / totalBalanceUSD) * 100;
            });
        }

        // Sort composition by value desc for consistency
        composition.sort((a, b) => b.value - a.value);

        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        const dateStr = `${year}-${month}-${day}`;

        return {
            date: dateStr,
            balance: totalBalanceUSD,
            composition,
            fxRates: fx.rates || { USD: 1.0 },
            pe: portfolioPE,
            forwardPe: portfolioFwdPE,
            tickerPEs,
            tickerWeights,
        };
    } catch (error) {
        logger.warn('Failed to fetch real-time data:', error);
        return null;
    }
}

import {
    transactionState,
    pushCommandHistory,
    resetHistoryIndex,
    setHistoryIndex,
} from './state.js';

// Bolt: Cache Intl.DateTimeFormat instance to prevent expensive recreation
const getCrosshairDateFormatter = (() => {
    let formatter = null;
    return () => {
        if (!formatter && typeof Intl !== 'undefined') {
            formatter = new Intl.DateTimeFormat('en-US', {
                year: 'numeric',
                month: 'short',
                day: '2-digit',
            });
        }
        return formatter;
    };
})();

import { executeCommand } from './terminal/commands.js';
import { autocompleteCommand, resetAutocompleteState } from './terminal/autocomplete.js';

import { initFade, requestFadeUpdate } from './fade.js';
import { cycleCurrency } from '@ui/currencyToggleManager.js';

let crosshairOverlay = null;
let crosshairDetails = null;
let crosshairTimeout = null;

let lastEmptyFilterTerm = null;

function formatCrosshairDateLabel(time) {
    if (!Number.isFinite(time)) {
        return '';
    }
    const date = new Date(time);
    if (Number.isNaN(date.getTime())) {
        return '';
    }
    const formatter = getCrosshairDateFormatter();
    if (formatter) {
        return formatter.format(date);
    }
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${date.getFullYear()}-${month}-${day}`;
}

function ensureCrosshairOverlay() {
    if (crosshairOverlay && crosshairDetails) {
        return { overlay: crosshairOverlay, details: crosshairDetails };
    }

    const terminalElement = document.getElementById('terminal');
    if (!terminalElement) {
        return { overlay: null, details: null };
    }

    let overlay = document.getElementById('terminalCrosshairOverlay');
    if (!overlay) {
        overlay = document.createElement('div');
        overlay.id = 'terminalCrosshairOverlay';
        overlay.className = 'terminal-crosshair-overlay';
        overlay.style.visibility = 'hidden';
        overlay.classList.remove('terminal-crosshair-active');
        const panel = document.createElement('div');
        panel.className = 'terminal-crosshair-panel';

        const header = document.createElement('div');
        header.className = 'terminal-crosshair-header';

        const dateSpan = document.createElement('span');
        dateSpan.className = 'terminal-crosshair-date';
        dateSpan.id = 'terminalCrosshairDate';
        header.appendChild(dateSpan);

        const body = document.createElement('div');
        body.className = 'terminal-crosshair-body';

        const listDiv = document.createElement('div');
        listDiv.id = 'terminalCrosshairList';
        listDiv.className = 'terminal-crosshair-list';
        body.appendChild(listDiv);

        const rangeDiv = document.createElement('div');
        rangeDiv.id = 'terminalCrosshairRange';
        rangeDiv.className = 'terminal-crosshair-range';
        rangeDiv.hidden = true;
        body.appendChild(rangeDiv);

        panel.appendChild(header);
        panel.appendChild(body);

        overlay.appendChild(panel);
        terminalElement.appendChild(overlay);
    }

    const details = {
        date: overlay.querySelector('#terminalCrosshairDate'),
        list: overlay.querySelector('#terminalCrosshairList'),
        range: overlay.querySelector('#terminalCrosshairRange'),
    };

    crosshairOverlay = overlay;
    crosshairDetails = details;

    overlay.addEventListener('transitionend', () => {
        if (!overlay.classList.contains('terminal-crosshair-active')) {
            overlay.style.visibility = 'hidden';
        }
    });

    return { overlay, details };
}

function updateCrosshairDetailsList(detailsList, snapshot) {
    if (typeof detailsList.replaceChildren === 'function') {
        detailsList.replaceChildren();
    } else {
        detailsList.textContent = '';
    }

    if (snapshot.header) {
        const headerDiv = document.createElement('div');
        headerDiv.className = 'terminal-crosshair-header';
        headerDiv.textContent = snapshot.header;
        detailsList.appendChild(headerDiv);
    }

    if (Array.isArray(snapshot.series)) {
        snapshot.series.forEach((series) => {
            const formattedLines = series.formatted.split('\n');
            const mainVal = formattedLines[0];

            const rowDiv = document.createElement('div');
            rowDiv.className = 'terminal-crosshair-row';

            const keySpan = document.createElement('span');
            keySpan.className = 'terminal-crosshair-key';

            const dotSpan = document.createElement('span');
            dotSpan.className = 'terminal-crosshair-dot';
            dotSpan.style.background = series.color;

            keySpan.appendChild(dotSpan);
            keySpan.appendChild(document.createTextNode(' ' + (series.label || series.key)));

            const valSpan = document.createElement('span');
            valSpan.className = 'terminal-crosshair-value';
            valSpan.textContent = mainVal;

            rowDiv.appendChild(keySpan);
            rowDiv.appendChild(valSpan);

            if (formattedLines[1]) {
                const breakdownDiv = document.createElement('div');
                breakdownDiv.className = 'terminal-crosshair-breakdown';
                breakdownDiv.textContent = formattedLines[1];
                rowDiv.appendChild(breakdownDiv);
            }

            detailsList.appendChild(rowDiv);
        });
    }
}

function updateCrosshairRangeDetails(rangeContainer, rangeSummary) {
    if (!rangeSummary) {
        rangeContainer.hidden = true;
        if (typeof rangeContainer.replaceChildren === 'function') {
            rangeContainer.replaceChildren();
        } else {
            rangeContainer.textContent = '';
        }
        return;
    }

    if (typeof rangeContainer.replaceChildren === 'function') {
        rangeContainer.replaceChildren();
    } else {
        rangeContainer.textContent = '';
    }

    const durationLabel =
        rangeSummary.durationDays >= 1
            ? `${Math.round(rangeSummary.durationDays)} day${
                  Math.round(rangeSummary.durationDays) === 1 ? '' : 's'
              }`
            : `${Math.max(1, Math.round(rangeSummary.durationMs / (1000 * 60 * 60)))} hrs`;

    const startLabel = formatCrosshairDateLabel(rangeSummary.start);
    const endLabel = formatCrosshairDateLabel(rangeSummary.end);

    const headerDiv = document.createElement('div');
    headerDiv.className = 'terminal-crosshair-range-header';
    headerDiv.textContent = `${startLabel} → ${endLabel} · ${durationLabel}`;
    rangeContainer.appendChild(headerDiv);

    if (rangeSummary.entries && rangeSummary.entries.length > 0) {
        const bodyDiv = document.createElement('div');
        bodyDiv.className = 'terminal-crosshair-range-body';

        rangeSummary.entries.forEach((entry) => {
            const rowDiv = document.createElement('div');
            rowDiv.className = 'terminal-crosshair-range-row';

            const keySpan = document.createElement('span');
            keySpan.className = 'terminal-crosshair-key';

            const dotSpan = document.createElement('span');
            dotSpan.className = 'terminal-crosshair-dot';
            dotSpan.style.background = entry.color;

            keySpan.appendChild(dotSpan);
            keySpan.appendChild(document.createTextNode(' ' + entry.label));

            const valSpan = document.createElement('span');
            valSpan.className = 'terminal-crosshair-value';
            valSpan.textContent =
                entry.deltaFormatted +
                (entry.percentFormatted ? ` (${entry.percentFormatted})` : '');

            rowDiv.appendChild(keySpan);
            rowDiv.appendChild(valSpan);
            bodyDiv.appendChild(rowDiv);
        });

        rangeContainer.appendChild(bodyDiv);
    }

    rangeContainer.hidden = false;
}

export function updateTerminalCrosshair(snapshot, rangeSummary) {
    const { overlay, details } = ensureCrosshairOverlay();
    if (!overlay || !details) {
        return;
    }

    if (!snapshot) {
        overlay.classList.remove('terminal-crosshair-active');
        if (crosshairTimeout) {
            clearTimeout(crosshairTimeout);
        }
        crosshairTimeout = setTimeout(() => {
            overlay.style.visibility = 'hidden';
        }, 160);
        return;
    }

    if (crosshairTimeout) {
        clearTimeout(crosshairTimeout);
        crosshairTimeout = null;
    }

    overlay.style.visibility = 'visible';
    requestAnimationFrame(() => overlay.classList.add('terminal-crosshair-active'));

    if (details.date) {
        details.date.textContent = snapshot.dateLabel || '';
    }

    if (details.list && snapshot) {
        updateCrosshairDetailsList(details.list, snapshot);
    }

    if (details.range) {
        updateCrosshairRangeDetails(details.range, rangeSummary);
    }
}

export function initTerminal({
    filterAndSort,
    toggleTable,
    closeAllFilterDropdowns,
    resetSortState,
    chartManager,
    onCommandExecuted,
}) {
    const terminalInput = document.getElementById('terminalInput');
    const terminal = document.getElementById('terminal');
    const outputContainer = document.getElementById('terminalOutput');

    function appendMessage(message) {
        if (!outputContainer) {
            return;
        }
        const pre = document.createElement('pre');
        pre.textContent = message;
        outputContainer.appendChild(pre);
        outputContainer.scrollTop = outputContainer.scrollHeight;
        requestFadeUpdate(outputContainer);
    }
    async function processCommand(command) {
        if (!outputContainer) {
            return;
        }
        const promptDiv = document.createElement('div');
        const promptSpan = document.createElement('span');
        promptSpan.className = 'prompt-user';
        promptSpan.textContent = 'lz@fund:~$ ';
        promptDiv.appendChild(promptSpan);
        promptDiv.appendChild(document.createTextNode(command));
        outputContainer.appendChild(promptDiv);
        requestFadeUpdate();

        await executeCommand(command, {
            appendMessage,
            terminalInput,
            chartManager,
            filterAndSort,
            toggleTable,
            closeAllFilterDropdowns,
            resetSortState,
            onCommandExecuted,
        });

        outputContainer.scrollTop = outputContainer.scrollHeight;
    }

    async function processEnterKey(input) {
        if (input.value.trim()) {
            const command = input.value.trim();
            pushCommandHistory(command);
            resetHistoryIndex();
            await processCommand(command);
            input.value = '';
        }
        resetAutocompleteState();
        requestFadeUpdate();
    }

    function processArrowUp(e, input) {
        e.preventDefault();
        if (transactionState.historyIndex < transactionState.commandHistory.length - 1) {
            setHistoryIndex(transactionState.historyIndex + 1);
            input.value = transactionState.commandHistory[transactionState.historyIndex];
        }
        resetAutocompleteState();
        requestFadeUpdate();
    }

    function processArrowDown(e, input) {
        e.preventDefault();
        if (transactionState.historyIndex > 0) {
            setHistoryIndex(transactionState.historyIndex - 1);
            input.value = transactionState.commandHistory[transactionState.historyIndex];
        } else {
            resetHistoryIndex();
            input.value = '';
        }
        resetAutocompleteState();
        requestFadeUpdate();
    }

    function processArrowLeftRight(e, input, direction) {
        if (input.value.trim() === '' && !e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            cycleCurrency(direction);
        } else if (e.ctrlKey || e.metaKey) {
            e.preventDefault();
            cycleCurrency(direction);
        }
        resetAutocompleteState();
        requestFadeUpdate();
    }

    async function handleTerminalInput(e) {
        const input = e.target;
        switch (e.key) {
            case 'Enter':
                await processEnterKey(input);
                break;
            case 'ArrowUp':
                processArrowUp(e, input);
                break;
            case 'ArrowDown':
                processArrowDown(e, input);
                break;
            case 'ArrowLeft':
                processArrowLeftRight(e, input, -1);
                break;
            case 'ArrowRight':
                processArrowLeftRight(e, input, 1);
                break;
            case 'Tab':
                e.preventDefault();
                autocompleteCommand(input);
                break;
            default:
                resetAutocompleteState();
                break;
        }
    }

    if (terminalInput) {
        terminalInput.focus();
        terminalInput.addEventListener('keydown', handleTerminalInput);
    }

    if (terminal) {
        terminal.addEventListener('click', (e) => {
            if (terminalInput && e.target !== terminalInput) {
                terminalInput.focus();
            }
        });
    }

    document.addEventListener('transactionFilterResult', (event) => {
        if (!outputContainer) {
            return;
        }
        const detail = event.detail || {};
        const { count } = detail;
        const searchTerm = typeof detail.searchTerm === 'string' ? detail.searchTerm.trim() : '';
        if (count === 0 && searchTerm) {
            if (lastEmptyFilterTerm !== searchTerm) {
                appendMessage("No transactions match the current filter. Type 'clear' to reset.");
                lastEmptyFilterTerm = searchTerm;
            }
        } else if (count > 0) {
            lastEmptyFilterTerm = null;
        }
        outputContainer.scrollTop = outputContainer.scrollHeight;
        requestFadeUpdate(outputContainer);
    });

    if (outputContainer) {
        // Initialize scroll fading
        initFade(outputContainer);
    }

    return {
        processCommand,
    };
}

import {
    COMMAND_ALIASES,
    STATS_SUBCOMMANDS,
    PLOT_SUBCOMMANDS,
    HELP_SUBCOMMANDS,
} from './constants.js';

export const autocompleteState = {
    prefix: '',
    matches: [],
    index: -1,
};

export function resetAutocompleteState() {
    autocompleteState.prefix = '';
    autocompleteState.matches = [];
    autocompleteState.index = -1;
}

export function autocompleteCommand(input) {
    if (!input) {
        return;
    }
    const val = input.value;
    const trimmedValue = val.trim();
    const searchPrefix = trimmedValue.toLowerCase();

    if (!searchPrefix) {
        resetAutocompleteState();
        return;
    }

    const hasSpace = searchPrefix.includes(' ');
    const parts = searchPrefix.split(' ');
    let matches = [];

    if (hasSpace) {
        if (parts.length >= 2 && (parts[0] === 'stats' || parts[0] === 's')) {
            const subPrefix = parts[1] ? parts[1].toLowerCase() : '';
            matches = subPrefix
                ? STATS_SUBCOMMANDS.filter((cmd) => cmd.startsWith(subPrefix))
                : STATS_SUBCOMMANDS;
        } else if (parts.length >= 2 && (parts[0] === 'plot' || parts[0] === 'p')) {
            const subPrefixRaw = parts.slice(1).join(' ').toLowerCase();
            const normalizedSubPrefix = subPrefixRaw.replace(/\s+/g, '-');
            matches = normalizedSubPrefix
                ? PLOT_SUBCOMMANDS.filter((cmd) => cmd.startsWith(normalizedSubPrefix))
                : PLOT_SUBCOMMANDS;
        } else if (parts.length >= 2 && (parts[0] === 'help' || parts[0] === 'h')) {
            const subPrefix = parts[1] ? parts[1].toLowerCase() : '';
            matches = subPrefix
                ? HELP_SUBCOMMANDS.filter((cmd) => cmd.startsWith(subPrefix))
                : HELP_SUBCOMMANDS;
        } else {
            resetAutocompleteState();
            return;
        }
    } else {
        matches = (
            searchPrefix
                ? COMMAND_ALIASES.filter((cmd) => cmd.startsWith(searchPrefix))
                : COMMAND_ALIASES
        ).filter((cmd, index, arr) => arr.indexOf(cmd) === index);
    }

    if (matches.length === 0) {
        resetAutocompleteState();
        return;
    }

    const currentPrefixKey = searchPrefix;

    if (
        autocompleteState.prefix === currentPrefixKey &&
        autocompleteState.matches.length > 0 &&
        trimmedValue.endsWith(autocompleteState.matches[autocompleteState.index])
    ) {
        autocompleteState.index = (autocompleteState.index + 1) % autocompleteState.matches.length;
    } else {
        autocompleteState.prefix = currentPrefixKey;
        autocompleteState.matches = matches;
        autocompleteState.index = 0;
    }

    const completed = autocompleteState.matches[autocompleteState.index];
    const suffix = matches.length === 1 ? ' ' : '';

    if (hasSpace && ['stats', 's', 'plot', 'p', 'help', 'h'].includes(parts[0])) {
        input.value = `${parts[0]} ${completed}${suffix}`;
    } else {
        input.value = `${completed}${suffix}`;
    }

    const newLength = input.value.length;
    input.setSelectionRange(newLength, newLength);
}

