export async function getYieldSnapshotLine() {
    const data = await loadYieldData();
    if (!data || !Array.isArray(data) || data.length === 0) {
        return null;
    }

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    const filtered = data.filter((d) => {
        const date = parseLocalDate(d.date);
        return (!filterFrom || date >= filterFrom) && (!filterTo || date <= filterTo);
    });

    if (filtered.length === 0) {
        return 'No dividend data in range';
    }

    const last = filtered[filtered.length - 1];
    let minYield = Infinity;
    let maxYield = -Infinity;
    for (let i = 0; i < filtered.length; i++) {
        const y = filtered[i].forward_yield;
        if (y < minYield) {
            minYield = y;
        }
        if (y > maxYield) {
            maxYield = y;
        }
    }

    const selectedCurrency = transactionState.selectedCurrency || 'USD';
    const convertedIncome = convertValueToCurrency(last.ttm_income, last.date, selectedCurrency);

    const earlyPeriodNote =
        '\nNote: Early period yields may appear inflated due to the smaller portfolio base and TTM dividend proxy.';

    return (
        `Forward Yield: ${last.forward_yield.toFixed(2)}% (Range: ${minYield.toFixed(2)}% - ${maxYield.toFixed(2)}%)` +
        `\nTTM Dividend Income: ${formatValueWithCurrency(convertedIncome, { currency: selectedCurrency })}` +
        earlyPeriodNote
    );
}
export function getVolatilitySnapshotLine({ includeHidden = false } = {}) {
    const performanceSeries = transactionState.performanceSeries || {};
    const seriesKeys = Object.keys(performanceSeries);
    if (seriesKeys.length === 0) {
        return null;
    }

    const visibility = transactionState.chartVisibility || {};
    const { chartDateRange } = transactionState;
    const filterFrom = parseDateSafe(chartDateRange?.from);
    const filterTo = parseDateSafe(chartDateRange?.to);
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const orderedKeys = [...seriesKeys].sort((a, b) => {
        if (a === '^LZ') {
            return -1;
        }
        if (b === '^LZ') {
            return 1;
        }
        return a.localeCompare(b);
    });

    const snapshots = [];
    const filterApplied = Boolean(filterFrom || filterTo);
    const showAllSeries = includeHidden || filterApplied;

    orderedKeys.forEach((key) => {
        if (!showAllSeries && visibility[key] === false) {
            return;
        }

        const rawPoints = Array.isArray(performanceSeries[key]) ? performanceSeries[key] : [];
        if (rawPoints.length < 91) {
            return;
        }

        const sourceCurrency = PERFORMANCE_SERIES_CURRENCY[key] || 'USD';
        const latestPoint = rawPoints[rawPoints.length - 1];
        const latestDate = new Date(latestPoint.date);

        // Respect date filters if applied
        const targetDate = filterTo && filterTo < latestDate ? filterTo : latestDate;

        // Find relevant data for volatility calculation (90 day window)
        // We need 90 daily returns, so 91 price points.
        let startIndex = -1;
        let endIndex = -1;

        for (let i = rawPoints.length - 1; i >= 0; i--) {
            const d = new Date(rawPoints[i].date);
            if (endIndex === -1 && d <= targetDate) {
                endIndex = i;
            }
            if (endIndex !== -1 && i <= endIndex - 90) {
                startIndex = i;
                break;
            }
        }

        if (startIndex !== -1 && endIndex !== -1) {
            const windowPoints = rawPoints.slice(startIndex, endIndex + 1);

            // Bolt: Replaced O(N) array allocation and double array reduction with Welford's online variance calculation algorithm.
            // Impact: Computes variance in a single O(1) space, O(N) time pass, significantly reducing GC pressure.
            let count = 0;
            let mean = 0;
            let m2 = 0;

            for (let i = 1; i < windowPoints.length; i++) {
                const startVal = convertBetweenCurrencies(
                    Number(windowPoints[i - 1].value),
                    sourceCurrency,
                    windowPoints[i - 1].date,
                    selectedCurrency
                );
                const endVal = convertBetweenCurrencies(
                    Number(windowPoints[i].value),
                    sourceCurrency,
                    windowPoints[i].date,
                    selectedCurrency
                );

                if (startVal !== 0) {
                    const ret = endVal / startVal - 1;
                    count += 1;
                    const delta = ret - mean;
                    mean += delta / count;
                    const delta2 = ret - mean;
                    m2 += delta * delta2;
                }
            }

            if (count >= 2) {
                const variance = m2 / (count - 1);
                const dailyStdDev = Math.sqrt(variance);
                const annualizedVol = dailyStdDev * Math.sqrt(252) * 100;

                snapshots.push(`${key} ${annualizedVol.toFixed(1)}%`);
            }
        }
    });

    if (snapshots.length === 0) {
        return null;
    }
    const header = `90D Annualized Volatility (base ${selectedCurrency}):`;
    const lines = [];
    for (let i = 0; i < snapshots.length; i += 4) {
        lines.push(snapshots.slice(i, i + 4).join('   '));
    }
    return `${header}\n${lines.join('\n')}`;
}

export async function getCompositionSnapshotLine({ labelPrefix = 'Composition' } = {}) {
    if (
        transactionState.activeChart !== 'composition' &&
        transactionState.activeChart !== 'compositionAbs'
    ) {
        return null;
    }
    const data = await loadCompositionSnapshotData();
    if (
        !data ||
        typeof data !== 'object' ||
        !Array.isArray(data.dates) ||
        data.dates.length === 0
    ) {
        return null;
    }

    const dates = data.dates;
    const { chartDateRange } = transactionState;
    const filterFrom = parseDateSafe(chartDateRange?.from);
    const filterTo = parseDateSafe(chartDateRange?.to);

    const filteredIndices = [];
    for (let i = 0; i < dates.length; i++) {
        const date = parseDateSafe(dates[i]);
        if (date && (!filterFrom || date >= filterFrom) && (!filterTo || date <= filterTo)) {
            filteredIndices.push(i);
        }
    }

    let targetIndex =
        filteredIndices.length > 0 ? filteredIndices[filteredIndices.length - 1] : dates.length - 1;
    if (!Number.isFinite(targetIndex) || targetIndex < 0) {
        targetIndex = dates.length - 1;
    }

    const totalValues = Array.isArray(data.total_values) ? data.total_values : [];
    const totalValueRaw = Number(totalValues[targetIndex] ?? 0) || 0;
    const dateLabel = dates[targetIndex];
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const compositionSeries = data.composition || data.series || {};
    const holdings = [];
    Object.entries(compositionSeries).forEach(([ticker, values]) => {
        const seriesValues = Array.isArray(values) ? values : [];
        const percentage = Number(seriesValues[targetIndex] ?? 0);
        if (!Number.isFinite(percentage) || percentage <= 0) {
            return;
        }
        const baseValue = (totalValueRaw * percentage) / 100;
        const convertedValue = convertValueToCurrency(baseValue, dateLabel, selectedCurrency);
        holdings.push({
            ticker,
            percent: percentage,
            absolute: convertedValue,
        });
    });

    if (!holdings.length) {
        return null;
    }

    holdings.sort((a, b) => b.percent - a.percent);

    let displayHoldings = holdings;
    const filterTickers = getCompositionFilterTickers();
    const assetClassFilter = getCompositionAssetClassFilter();

    // Build a matcher that combines explicit tickers and asset class with OR logic
    const explicitSet =
        Array.isArray(filterTickers) && filterTickers.length > 0
            ? new Set(
                  filterTickers.map((ticker) =>
                      typeof ticker === 'string' ? ticker.toUpperCase() : ''
                  )
              )
            : null;
    const hasClassFilter = assetClassFilter === 'etf' || assetClassFilter === 'stock';
    const shouldMatchEtf = assetClassFilter === 'etf';

    if (explicitSet || hasClassFilter) {
        const selected = holdings.filter((holding) => {
            const upperTicker = holding.ticker.toUpperCase();
            if (explicitSet && explicitSet.has(upperTicker)) {
                return true;
            }
            if (hasClassFilter) {
                if (upperTicker === 'OTHERS') {
                    return false;
                }
                const ac = getHoldingAssetClass(holding.ticker);
                return shouldMatchEtf ? ac === 'etf' : ac !== 'etf';
            }
            return false;
        });
        if (selected.length > 0) {
            const selectedSet = new Set(selected.map((h) => h.ticker.toUpperCase()));
            const remainder = holdings.filter(
                (holding) => !selectedSet.has(holding.ticker.toUpperCase())
            );
            if (remainder.length > 0) {
                const totalPercent = remainder.reduce((sum, item) => sum + item.percent, 0);
                const totalAbsolute = remainder.reduce((sum, item) => sum + item.absolute, 0);
                selected.push({
                    ticker: 'Others',
                    percent: totalPercent,
                    absolute: totalAbsolute,
                });
            }
            displayHoldings = selected;
        }
    }

    const formatted = displayHoldings
        .filter((holding) => Number.isFinite(holding.percent) && holding.percent > 0.1)
        .map((holding) => {
            const label = holding.ticker === 'BRKB' ? 'BRK-B' : holding.ticker;
            const valueText = formatWithSelectedCurrency(holding.absolute);
            const percentText = `${holding.percent.toFixed(2)}%`;
            return `${label} ${valueText} (${percentText})`;
        });

    if (!formatted.length) {
        return null;
    }

    const lines = [];
    for (let i = 0; i < formatted.length; i += 3) {
        lines.push(formatted.slice(i, i + 3).join('   '));
    }

    let hint = '';
    if (labelPrefix === 'Composition') {
        hint =
            "\n(Hint: use 'abs' for absolute values, 'per' for percentages, or 'sectors/geography/marketcap' to switch charts)";
    } else if (labelPrefix === 'Composition Abs') {
        hint =
            "\n(Hint: use 'per' for percentages, 'abs' for absolute values, or 'sectors/geography/marketcap' to switch charts)";
    }

    return `${labelPrefix} (${dateLabel}):\n${lines.join('\n')}${hint}`;
}

