export async function getPESnapshotLine() {
    const data = await loadPEData();
    if (
        !data ||
        typeof data !== 'object' ||
        !Array.isArray(data.dates) ||
        data.dates.length === 0
    ) {
        return null;
    }

    const { chartDateRange } = transactionState;
    const filterFrom = chartDateRange.from ? parseLocalDate(chartDateRange.from) : null;
    const filterTo = chartDateRange.to ? parseLocalDate(chartDateRange.to) : null;

    const series = buildPESeries(
        data.dates,
        data.portfolio_pe,
        data.ticker_pe,
        data.ticker_weights,
        filterFrom,
        filterTo
    );

    if (series.length === 0) {
        return 'No PE data in range';
    }

    const lastPoint = series[series.length - 1];
    const current = lastPoint.pe;

    let min = Infinity;
    let max = -Infinity;
    for (let i = 0; i < series.length; i++) {
        const v = series[i].pe;
        if (v < min) {
            min = v;
        }
        if (v > max) {
            max = v;
        }
    }

    let text = `Current: ${current.toFixed(2)}x | Range: ${min.toFixed(2)}x - ${max.toFixed(2)}x | Harmonic Mean (1 / Σ(w/PE))`;

    const fwdPEData = data.forward_pe || {};
    const tickerFwdPE = fwdPEData.ticker_forward_pe || {};
    const msciPeRatio = fwdPEData.msci_pe_ratio || null;

    if (lastPoint.tickerPEs) {
        const entries = Object.entries(lastPoint.tickerPEs)
            .filter(([, pe]) => pe !== null && Number.isFinite(pe))
            .sort((a, b) => {
                const wA = lastPoint.tickerWeights ? lastPoint.tickerWeights[a[0]] : 0;
                const wB = lastPoint.tickerWeights ? lastPoint.tickerWeights[b[0]] : 0;
                return (wB || 0) - (wA || 0);
            })
            .slice(0, 8);
        if (entries.length > 0) {
            const breakdown = entries
                .map(([t, pe]) => {
                    let fwd = tickerFwdPE[t];
                    // For VT: derive forward PE from trailing PE using MSCI ratio
                    if (t === 'VT' && msciPeRatio?.ratio > 0 && Number.isFinite(pe) && pe > 0) {
                        fwd = pe / msciPeRatio.ratio;
                    }
                    const trailingStr = pe.toFixed(0);
                    if (fwd !== null && fwd !== undefined && Number.isFinite(fwd)) {
                        return `${t}:${trailingStr}/${fwd.toFixed(0)}`;
                    }
                    return `${t}:${trailingStr}`;
                })
                .join(' ');
            text += `\nComponents: ${breakdown}`;
        }
    }

    return text;
}
export function getRollingSnapshotLine({ includeHidden = false } = {}) {
    const performanceSeries = transactionState.performanceSeries || {};
    const seriesKeys = Object.keys(performanceSeries);
    if (seriesKeys.length === 0) {
        return null;
    }

    const visibility = transactionState.chartVisibility || {};
    const { chartDateRange } = transactionState;
    const filterFrom = parseDateSafe(chartDateRange?.from);
    const filterTo = parseDateSafe(chartDateRange?.to);
    const selectedCurrency = transactionState.selectedCurrency || 'USD';

    const orderedKeys = [...seriesKeys].sort((a, b) => {
        if (a === '^LZ') {
            return -1;
        }
        if (b === '^LZ') {
            return 1;
        }
        return a.localeCompare(b);
    });

    const snapshots = [];
    const filterApplied = Boolean(filterFrom || filterTo);
    const showAllSeries = includeHidden || filterApplied;

    orderedKeys.forEach((key) => {
        if (!showAllSeries && visibility[key] === false) {
            return;
        }

        const rawPoints = Array.isArray(performanceSeries[key]) ? performanceSeries[key] : [];
        if (rawPoints.length === 0) {
            return;
        }

        const sourceCurrency = PERFORMANCE_SERIES_CURRENCY[key] || 'USD';
        const latestPoint = rawPoints[rawPoints.length - 1];
        const latestDate = new Date(latestPoint.date);

        // Respect date filters if applied
        const targetDate = filterTo && filterTo < latestDate ? filterTo : latestDate;

        const oneYearAgo = new Date(targetDate);
        oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);

        // Find the point closest to one year ago and the target point
        let startPoint = null;
        let endPoint = null;

        for (let i = rawPoints.length - 1; i >= 0; i--) {
            const d = new Date(rawPoints[i].date);
            if (!endPoint && d <= targetDate) {
                endPoint = rawPoints[i];
            }
            if (d <= oneYearAgo) {
                startPoint = rawPoints[i];
                break;
            }
        }

        if (startPoint && endPoint && startPoint.value !== 0) {
            const startVal = convertBetweenCurrencies(
                Number(startPoint.value),
                sourceCurrency,
                startPoint.date,
                selectedCurrency
            );
            const endVal = convertBetweenCurrencies(
                Number(endPoint.value),
                sourceCurrency,
                endPoint.date,
                selectedCurrency
            );

            const rollingReturn = (endVal / startVal - 1) * 100;
            snapshots.push(`${key} ${formatPercentInline(rollingReturn)}`);
        }
    });

    if (snapshots.length === 0) {
        return null;
    }
    const header = `1Y Rolling Return (base ${selectedCurrency}):`;
    const lines = [];
    for (let i = 0; i < snapshots.length; i += 4) {
        lines.push(snapshots.slice(i, i + 4).join('   '));
    }
    const hint = "\n(Hint: type 'cumulative' to switch to cumulative performance chart)";
    return `${header}\n${lines.join('\n')}${hint}`;
}

import { getNumberFormatter } from '../../../utils/formatting.js';
